const TransportSystem = {
    registry: null,

    async init() {
        if (!this.registry) {
            try {
                if (typeof window.ensureRuntimeDataLoaded === 'function') {
                    await window.ensureRuntimeDataLoaded();
                }
                this.registry = window.TRANSPORT_REGISTRY || {};
                console.log('[TransportSystem] Registry loaded:', Object.keys(this.registry));
            } catch (error) {
                console.error('[TransportSystem] Failed to load registry:', error);
                // Fallback Р С” Р В¶Р ВөРЎРғРЎвҖҡР С”Р С• Р В·Р В°Р С”Р С•Р Т‘Р С‘РЎРӮР С•Р РҶР В°Р Р…Р Р…Р С•Р СҳРЎС“ РЎРғР С—Р С‘РЎРғР С”РЎС“
                this.registry = {
                    horse: { id: 'horse', speedMultiplier: 2.0, cargoBonus: 5, name: 'Р вҖәР С•РЎвӮ¬Р В°Р Т‘РЎРҠ', basePrice: 500, rarity: 'Р СңР ВөР С•Р ВұРЎвҖ№РЎвҖЎР Р…РЎвҖ№Р в„–' },
                    warhorse: { id: 'warhorse', speedMultiplier: 1.8, cargoBonus: 3, name: 'Р вҖҳР С•Р ВөР РҶР С•Р в„– Р С”Р С•Р Р…РЎРҠ', basePrice: 1200, rarity: 'Р В Р ВөР Т‘Р С”Р С‘Р в„–' },
                    cart: { id: 'cart', speedMultiplier: 1.3, cargoBonus: 15, name: 'Р СһР ВөР В»Р ВөР В¶Р С”Р В°', basePrice: 300, rarity: 'Р СӣР ВұРЎвҖ№РЎвҖЎР Р…РЎвҖ№Р в„–' },
                    wagon: { id: 'wagon', speedMultiplier: 1.5, cargoBonus: 30, name: 'Р СһР С•РЎРӮР С–Р С•Р РҶР В°РЎРҸ Р С—Р С•Р РҶР С•Р В·Р С”Р В°', basePrice: 500, rarity: 'Р СңР ВөР С•Р ВұРЎвҖ№РЎвҖЎР Р…РЎвҖ№Р в„–' },
                    ship_deed: { id: 'ship_deed', speedMultiplier: 2.5, cargoBonus: 50, name: 'Р вҖқР С•Р С”РЎС“Р СҳР ВөР Р…РЎвҖҡ Р Р…Р В° Р С”Р С•РЎРӮР В°Р ВұР В»РЎРҠ', basePrice: 2000, rarity: 'Р В Р ВөР Т‘Р С”Р С‘Р в„–' }
                };
            }
        }
        return this.registry;
    },

    isTransportId(id) {
        if (!this.registry) return false;
        return id && this.registry.hasOwnProperty(id.toLowerCase());
    },

    getTransportData(id) {
        if (!this.registry) return null;
        return this.registry[id.toLowerCase()] || null;
    },

    getAllTransportIds() {
        if (!this.registry) return [];
        return Object.keys(this.registry);
    },

    validateTransportItem(item) {
        if (!item) return { valid: false, error: 'Item is null or undefined' };

        const transportData = this.getTransportData(item.prototype_id || item.custom_props?.aiIdentifier);

        if (!transportData) {
            return {
                valid: false,
                error: `Item "${item.custom_props?.name || item.prototype_id}" is not a valid transport. Valid IDs: ${this.getAllTransportIds().join(', ')}`,
                suggestion: `Use addItem with aiIdentifier from: ${this.getAllTransportIds().join(', ')}`
            };
        }

        if (!item.custom_props?.isTransport) {
            return {
                valid: false,
                error: `Item "${item.custom_props?.name}" was not created as transport (missing isTransport flag)`,
                suggestion: `Recreate item using addItem with aiIdentifier="${transportData.id}"`
            };
        }

        return { valid: true, data: transportData };
    },

    // Р вҖңР ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘РЎРҸ Р Т‘Р С•Р С”РЎС“Р СҳР ВөР Р…РЎвҖҡР В°РЎвҖ Р С‘Р С‘ Р Т‘Р В»РЎРҸ Р вҖңР Сҡ
    generateGMDocumentation() {
        if (!this.registry) return '';

        let doc = '=== [Р РҺР вҖәР РҲР вҖ“Р вҖўР вҖҳР СңР С’Р РҮ Р ВҳР СңР ВӨР СӣР В Р СҡР С’Р ВҰР ВҳР РҮ Р вҖқР вҖәР РҮ Р вҖңР Сҡ - Р СңР вҖў Р вҖҷР В«Р вҖҷР СӣР вҖқР ВҳР СһР В¬ Р ВҳР вҖңР В Р СӣР СҷР РҲ] ===\n';
        doc += 'Р СһР В Р С’Р СңР РҺР СҹР СӣР В Р Сһ: Р вҖқР СӣР СҹР РҲР РҺР СһР ВҳР СҡР В«Р вҖў ID (Р РҺР СһР В Р СӣР вҖңР Сӣ!)\n';
        doc += 'Р СҹРЎРӮР С‘ РЎРғР С•Р В·Р Т‘Р В°Р Р…Р С‘Р С‘ РЎвҖҡРЎРӮР В°Р Р…РЎРғР С—Р С•РЎРӮРЎвҖҡР В° РЎвҖЎР ВөРЎРӮР ВөР В· addItem Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р в„– Р СһР СӣР вҖәР В¬Р СҷР Сӣ РЎРҢРЎвҖҡР С‘ aiIdentifier:\n\n';

        for (const [id, data] of Object.entries(this.registry)) {
            doc += `  "${id}" - ${data.name || data.nameEn} (РЎРғР С”Р С•РЎРӮР С•РЎРғРЎвҖҡРЎРҠ Р“вҖ”${data.speedMultiplier}, +${data.cargoBonus} РЎРғР В»Р С•РЎвҖҡР С•Р РҶ)\n`;
        }

        doc += '\nР СҹР В Р С’Р вҖҷР ВҳР вҖәР В¬Р СңР Сӣ:\n';
        doc += '  { "command": "addItem", "args": { "aiIdentifier": "horse", "name": "Р вҖңР Р…Р ВөР Т‘Р В°РЎРҸ Р В»Р С•РЎвӮ¬Р В°Р Т‘РЎРҠ" } }\n';
        doc += '  { "command": "mountTransport", "args": { "itemId": "horse" } }\n';
        doc += '\nР СңР вҖўР СҹР В Р С’Р вҖҷР ВҳР вҖәР В¬Р СңР Сӣ:\n';
        doc += '  { "command": "addItem", "args": { "aiIdentifier": "horse_brown" } } РІСңРҠ\n';
        doc += '  { "command": "addItem", "args": { "aiIdentifier": "Р В»Р С•РЎвӮ¬Р В°Р Т‘РЎРҠ" } } РІСңРҠ\n';
        doc += '=== [Р СҷР СӣР СңР вҖўР ВҰ Р РҺР вҖәР РҲР вҖ“Р вҖўР вҖҳР СңР СӣР в„ў Р ВҳР СңР ВӨР СӣР В Р СҡР С’Р ВҰР ВҳР Вҳ] ===\n';

        return doc;
    }
};

