function getCaravanContents(chestId) {
    if (!chestId || !ContainerRegistry.has(chestId)) return "Р СҹРЎС“РЎРғРЎвҖҡР С•";
    const cont = ContainerRegistry.get(chestId);
    if (!cont.items || cont.items.length === 0) return "Р СҹРЎС“РЎРғРЎвҖҡР С•";
    let contents = [];
    cont.items.forEach(itemId => {
        const item = ItemRegistry.get(itemId);
        if (item) {
            let name = item.custom_props?.name || item.prototype_id;
            contents.push(`${name} (x${item.stack_size})`);
        }
    });
    return contents.join(", ");
}

function formatTrekObjectData(objType, data) {
    if (!data) return "Р СңР ВөРЎвҖҡ Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ";
    if (objType === 'caravan') {
        let goods = getCaravanContents(data.chest_id);
        return `Р СҷР В°РЎРӮР В°Р РҶР В°Р Р… (ID: ${data.id}). Р СҡР В°РЎРӮРЎвӮ¬РЎРӮРЎС“РЎвҖҡ: ${data.origin} -> ${data.destination}. Р СӣРЎвҖҰРЎРӮР В°Р Р…Р В°: ${data.guards} Р Р…Р В°Р ВөР СҳР Р…Р С‘Р С”Р С•Р РҶ. Р вҖңРЎРӮРЎС“Р В· (chest_id: ${data.chest_id}): ${goods}.`;
    } else if (objType === 'army') {
        return `Р С’РЎРӮР СҳР С‘РЎРҸ (ID: ${data.id}). Р ВӨРЎРӮР В°Р С”РЎвҖ Р С‘РЎРҸ: ${data.faction_name || 'Р СңР ВөР С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР Р…Р С•'}. Р В§Р С‘РЎРғР В»Р ВөР Р…Р Р…Р С•РЎРғРЎвҖҡРЎРҠ: ${data.size}. Р СҡР С•РЎРӮР В°Р В»РЎРҠ: ${data.morale}. Р СңР В°Р С—РЎРӮР В°Р РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ Р РҶ: ${data.destination}. Р ВӨР В°Р В·Р В°: ${data.current_phase}. Р РҺРЎС“Р Р…Р Т‘РЎС“Р С” РЎРғР Р…Р В°Р ВұР В¶Р ВөР Р…Р С‘РЎРҸ: ${data.supply_chest_id || 'Р СңР ВөРЎвҖҡ'}.`;
    }
    return JSON.stringify(data);
}


const LivingRoads = {
    timer: null,
    isProcessing: false,
    isGeneratingHour: false,

    calculateDistance: function(x1, y1, x2, y2) {
        return Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
    },

    start: async function(destinationId) {
        if (!player) return { success: false, error: "Р ВҳР С–РЎРӮР С•Р С” Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р…" };
        
        let dest = globalLocations[destinationId] || (player.mapMarkers && player.mapMarkers[destinationId]);
        const allPoints = [
            ...Object.keys(globalLocations || {}).map(k => ({ ...globalLocations[k], id: k })),
            ...Object.values(player.mapMarkers || {})
        ];

        if (!dest) {
            const searchName = String(destinationId).toLowerCase().trim();
            
            // 1. Р СҹР С•Р С‘РЎРғР С” Р С—Р С• Р С‘Р СҳР ВөР Р…Р С‘
            dest = allPoints.find(p => p.name && p.name.toLowerCase().trim().includes(searchName));
            
            // 2. Р СҹР С•Р С‘РЎРғР С” Р С—Р С• РЎвҖЎР В°РЎРғРЎвҖҡРЎРҸР Сҳ ID (РЎС“РЎРғРЎвҖҡР С•Р в„–РЎвҖЎР С‘Р РҶР С•РЎРғРЎвҖҡРЎРҠ Р С” Р С—Р ВөРЎРӮР ВөРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С”Р Вө РЎРғР В»Р С•Р РҶ, Р Р…Р В°Р С—РЎРӮ. aquilon_capital)
            if (!dest) {
                const searchParts = searchName.split(/[_ \-]+/);
                dest = allPoints.find(p => {
                    if (!p.id) return false;
                    const idLower = p.id.toLowerCase();
                    const validParts = searchParts.filter(part => part.length > 2);
                    if (validParts.length === 0) return false;
                    return validParts.every(part => idLower.includes(part));
                });
            }
            
            // 3. Р СҹР С•Р С‘РЎРғР С” Р С—Р С• РЎвҖЎР В°РЎРғРЎвҖҡРЎРҸР Сҳ Р С‘Р СҳР ВөР Р…Р С‘
            if (!dest) {
                const searchParts = searchName.split(/[_ \-]+/);
                dest = allPoints.find(p => {
                    if (!p.name) return false;
                    const nameLower = p.name.toLowerCase();
                    const validParts = searchParts.filter(part => part.length > 2);
                    if (validParts.length === 0) return false;
                    return validParts.some(part => nameLower.includes(part));
                });
            }
        }

        let startLocId = null;
        for (let key in globalLocations) {
            if (globalLocations[key].name === player.location) {
                startLocId = key; break;
            }
        }
        if (!startLocId && player.currentSublocation) {
            let sub = player.subLocations[player.currentSublocation] || (World && World.subLocations && World.subLocations[player.currentSublocation]);
            if (sub && sub.parentId) startLocId = sub.parentId;
        }
        if (!startLocId) startLocId = Object.keys(globalLocations)[0];

        if (!dest) {
            const newName = String(destinationId).replace(/_/g, ' ');
            const capitalizedName = newName.charAt(0).toUpperCase() + newName.slice(1);
            addLogMessage(`[Р вҖҷР СңР ВҳР СҡР С’Р СңР ВҳР вҖў] Р вҖәР С•Р С”Р В°РЎвҖ Р С‘РЎРҸ '${destinationId}' Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р…Р В° Р РҶ Р В°РЎвҖҡР В»Р В°РЎРғР Вө. Р СҡР В°РЎРӮРЎвӮ¬РЎРӮРЎС“РЎвҖҡ Р С—РЎРӮР С•Р В»Р С•Р В¶Р ВөР Р… Р Р…Р В°РЎС“Р С–Р В°Р Т‘, Р В»Р С•Р С”Р В°РЎвҖ Р С‘РЎРҸ Р Т‘Р С•Р ВұР В°Р РҶР В»Р ВөР Р…Р В° Р Р…Р В° Р С”Р В°РЎРӮРЎвҖҡРЎС“.`, "system-message");
            
            let startX = 128, startY = 128;
            if (globalLocations[startLocId]) { startX = globalLocations[startLocId].x; startY = globalLocations[startLocId].y; }
            
            await executeCommand('addMapMarker', {
                id: destinationId,
                name: capitalizedName,
                description: "Р СңР ВөР С‘Р В·Р РҶР ВөР Т‘Р В°Р Р…Р Р…Р С•Р Вө Р СҳР ВөРЎРғРЎвҖҡР С•, РЎС“Р С—Р С•Р СҳРЎРҸР Р…РЎС“РЎвҖҡР С•Р Вө Р РҶ Р С—РЎС“РЎвҖҡР С‘.",
                x: startX + (Math.random() * 20 - 10),
                y: startY + (Math.random() * 20 - 10)
            });
            
            dest = player.mapMarkers[destinationId];
        }

        if (window.electronAPI && window.electronAPI.nexusStartTrek) {
            const res = await window.electronAPI.nexusStartTrek(startLocId, dest.id || destinationId);
            if (res.status === 'ok') {
                player.travel = {
                    active: true, destinationId: dest.id || destinationId, destinationName: dest.name,
                    totalHours: res.total_hours, elapsedHours: 0,
                    paused: false, pauseReason: null
                };
                if (window.Cartographer) window.Cartographer.mapState.isFollowingPlayer = true;
                updateCharacterSheet();
                addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө Р РҶ ${dest.name} Р Р…Р В°РЎвҖЎР В°РЎвҖҡР С•. Р В Р В°РЎРғРЎвҖЎР ВөРЎвҖҡР Р…Р С•Р Вө Р РҶРЎРӮР ВөР СҳРЎРҸ: ${res.total_hours} РЎвҖЎ.`, "system-message");
            }
        }
        this.resume();
        return { success: true };
    },

        tick: async function() {
        if (!player || !player.travel || !player.travel.active || player.travel.paused || this.isProcessing) return;
        this.isProcessing = true;
        this.isGeneratingHour = true;
        updateCharacterSheet(); // Р СҹР С•Р С”Р В°Р В·РЎвҖ№Р РҶР В°Р ВөР Сҳ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”РЎС“

        try {
            // Р вҖ“Р Т‘Р ВөР Сҳ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° Р С•РЎвҖҡ Р Т‘Р РҶР С‘Р В¶Р С”Р В°, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р Р…Р Вө РЎРғР С—Р В°Р СҳР С‘РЎвҖҡРЎРҠ Р В·Р В°Р С—РЎРӮР С•РЎРғР В°Р СҳР С‘
            await new Promise(resolve => {
                const prev = window.isSimulatingTime;
                window.isSimulatingTime = true; // Р СҹР С•Р Т‘Р В°Р РҶР В»РЎРҸР ВөР Сҳ Р ВұР В»Р С•Р С”Р С‘РЎРӮР С•Р РҶР С”РЎС“ Р РҶР РҶР С•Р Т‘Р В° Р Р…Р В° Р РҶРЎРӮР ВөР СҳРЎРҸ РЎвҖҡР С‘Р С”Р В°
                
                            window.electronAPI.nexusSimulate(null, 1, player?.location || "").then(res => {
                this.isGeneratingHour = false;
                if (res.status === 'ok') {
                    if (res.world) setWorld(res.world);
                    if (res.relevant_news) { const w = getWorld(); if (w) w.relevant_news = res.relevant_news; }
                        if (res.items) res.items.forEach(([k, v]) => ItemRegistry.set(k, v));
                        if (res.containers) res.containers.forEach(([k, v]) => setContainer(k, v));
                        if (res.deleted_items) res.deleted_items.forEach(id => ItemRegistry.delete(id));
                        if (res.deleted_containers) res.deleted_containers.forEach(id => ContainerRegistry.delete(id));
                    processMonsterQuests();
                        
                        // Р РҺР С‘Р Р…РЎвҖҰРЎРӮР С•Р Р…Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р С—РЎРӮР С•Р С–РЎРӮР ВөРЎРғРЎРғР В° Р С—РЎС“РЎвҖҡР С‘ Р С‘Р В· C++
                        if (res.world && res.world.player_trek) {
                            player.travel.active = res.world.player_trek.active;
                            // Р вҖ”Р В°РЎвҖ°Р С‘РЎвҖҡР В° Р С•РЎвҖҡ РЎРӮР В°РЎРғРЎРғР С‘Р Р…РЎвҖҰРЎРӮР С•Р Р…Р В°: Р ВөРЎРғР В»Р С‘ Р С‘Р С–РЎРӮР С•Р С” Р Р…Р В°Р В¶Р В°Р В» Р С—Р В°РЎС“Р В·РЎС“, Р Р…Р Вө Р С—Р ВөРЎРӮР ВөР В·Р В°Р С—Р С‘РЎРғРЎвҖ№Р РҶР В°Р ВөР Сҳ РЎРғРЎвҖҡР В°РЎРӮРЎвҖ№Р Сҳ РЎРғРЎвҖҡР ВөР в„–РЎвҖҡР С•Р Сҳ
                            if (!player.travel.paused || res.world.player_trek.paused) {
                                player.travel.paused = res.world.player_trek.paused;
                            }
                            player.travel.elapsedHours = res.world.player_trek.elapsed_hours;
                            player.travel.totalHours = res.world.player_trek.total_hours;
                            player.travel.currentX = res.world.player_trek.current_x;
                            player.travel.currentY = res.world.player_trek.current_y;
                        }
                        
                        // Р вҖқР РҶР С‘Р С–Р В°Р ВөР Сҳ РЎвҖЎР В°РЎРғРЎвҖ№ UI
                        if (player.gameTime) {
                            player.gameTime.totalPulses += 12;
                            player.gameTime.hour += 1;
                            if (player.gameTime.hour >= 24) {
                                player.gameTime.hour = 0;
                                player.gameTime.day += 1;
                            }
                        }

                        if (res.trek_events && res.trek_events.length > 0) {
                            LivingRoads.handleEvents(res.trek_events);
                        }
                        
                        updateTimeDisplay();
                    }
                    window.isSimulatingTime = prev;
                    updateCharacterSheet(); // Р СӣР ВұР Р…Р С•Р РҶР В»РЎРҸР ВөР Сҳ UI Р С—Р С•РЎРғР В»Р Вө Р С—Р С•Р В»РЎС“РЎвҖЎР ВөР Р…Р С‘РЎРҸ Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ
                    if (typeof updateHoldingsDisplay === 'function') updateHoldingsDisplay();
                    resolve();
                }).catch(err => {
                    console.error("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎвҖҡР С‘Р С”Р В° Р С—РЎС“РЎвҖҡР С‘:", err);
                    this.isGeneratingHour = false;
                    window.isSimulatingTime = prev;
                    updateCharacterSheet();
                    resolve();
                });
            });
        } finally {
            this.isProcessing = false;
        }
    },

    pause: async function(reason = "manual") {
        if (!player || !player.travel || !player.travel.active) return;
        player.travel.paused = true;
        player.travel.pauseReason = reason;
        player.travel.isFastForwarding = false;
        if (this.timer) clearInterval(this.timer);
        if (window.electronAPI && window.electronAPI.nexusPauseTrek) await window.electronAPI.nexusPauseTrek();
        updateCharacterSheet();
        addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө Р С—РЎРӮР С‘Р С•РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…Р С•. Р СҹРЎРӮР С‘РЎвҖЎР С‘Р Р…Р В°: ${reason}`, "system-message");
    },

        resume: async function() {
        if (!player || !player.travel || !player.travel.active) return;
        player.travel.paused = false;
        player.travel.pauseReason = null;
        player.travel.currentEvents = null; // Р СӣРЎвҖЎР С‘РЎвҖ°Р В°Р ВөР Сҳ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ Р С—РЎРӮР С‘ Р С—РЎРӮР С•Р Т‘Р С•Р В»Р В¶Р ВөР Р…Р С‘Р С‘ Р С—РЎС“РЎвҖҡР С‘
        player.travel.isFastForwarding = false;
        if (window.electronAPI && window.electronAPI.nexusResumeTrek) await window.electronAPI.nexusResumeTrek();
        if (this.timer) clearInterval(this.timer);
        const interval = requireRuntimeNumber(
            typeof TREK_CONFIG !== 'undefined' ? TREK_CONFIG.tick_interval_ms : NaN,
            'TREK_CONFIG.tick_interval_ms'
        );
        this.timer = setInterval(() => this.tick(), interval);
        updateCharacterSheet();
        addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө Р РҶР С•Р В·Р С•Р ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С•.`, "system-message");
    },

    cancel: async function() {
        if (!player || !player.travel || !player.travel.active) return;
        player.travel.active = false;
        player.travel.isFastForwarding = false;
        if (this.timer) clearInterval(this.timer);
        if (window.electronAPI && window.electronAPI.nexusCancelTrek) await window.electronAPI.nexusCancelTrek();
        addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө Р С•РЎвҖҡР СҳР ВөР Р…Р ВөР Р…Р С•. Р вҖҷРЎвҖ№ Р С•РЎРғРЎвҖҡР В°Р В»Р С‘РЎРғРЎРҠ Р РҶ Р Т‘Р С‘Р С”Р С•Р в„– Р СҳР ВөРЎРғРЎвҖҡР Р…Р С•РЎРғРЎвҖҡР С‘.`, "system-message");
        updateCharacterSheet();
    },

    fastForward: async function() {
        if (!player || !player.travel || !player.travel.active) return;
        player.travel.paused = false;
        player.travel.pauseReason = null;
        player.travel.currentEvents = null;
        player.travel.isFastForwarding = true;
        if (window.electronAPI && window.electronAPI.nexusResumeTrek) await window.electronAPI.nexusResumeTrek();
        if (this.timer) clearInterval(this.timer);
        // Р РҲРЎРғР С”Р С•РЎРӮРЎРҸР ВөР Сҳ Р Т‘Р С• 50Р СҳРЎРғ
        this.timer = setInterval(() => this.tick(), 50);
        addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө РЎС“РЎРғР С”Р С•РЎРӮР ВөР Р…Р С•.`, "system-message");
        updateCharacterSheet();
    },

        handleEvents: function(events) {
        if (!events || events.length === 0) return;
        
        let arrivalEvent = events.find(ev => ev.object_type === 'arrival');
        let otherEvents = events.filter(ev => ev.object_type !== 'arrival');

        if (otherEvents.length > 0) {
            // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ Р Т‘Р В»РЎРҸ Р С•РЎвҖҡР С•Р ВұРЎРӮР В°Р В¶Р ВөР Р…Р С‘РЎРҸ Р РҶ UI
            player.travel.currentEvents = otherEvents;
            player.travel.paused = true;
            player.travel.pauseReason = "event";
            player.travel.isFastForwarding = false;
            if (this.timer) clearInterval(this.timer);
            
            // Р вҖқРЎС“Р ВұР В»Р С‘РЎРӮРЎС“Р ВөР Сҳ Р РҶ Р В»Р С•Р С– Р Т‘Р В»РЎРҸ Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘Р С‘
            otherEvents.forEach(ev => {
                // Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡР С”Р В° Р В»Р С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘Р С‘ Р Т‘Р В»РЎРҸ Р В»Р С•Р С–Р В°
                let description = '';
                let descObj = ev.description;

                // Р вҖўРЎРғР В»Р С‘ description - РЎРҢРЎвҖҡР С• JSON-РЎРғРЎвҖҡРЎРӮР С•Р С”Р В°, Р С—Р В°РЎРӮРЎРғР С‘Р Сҳ Р ВөРЎвҖҳ
                if (typeof descObj === 'string') {
                    try {
                        const parsed = JSON.parse(descObj);
                        if (typeof parsed === 'object' && parsed !== null) {
                            descObj = parsed;
                        } else {
                            description = descObj;
                        }
                    } catch (e) {
                        // Р СңР Вө JSON, Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р ВөР Сҳ Р С”Р В°Р С” Р ВөРЎРғРЎвҖҡРЎРҠ
                        description = descObj;
                    }
                }

                // Р вҖўРЎРғР В»Р С‘ Р ВөРЎвҖ°РЎвҖҳ Р Р…Р Вө РЎС“РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…Р С• Р С‘ РЎРҢРЎвҖҡР С• Р С•Р ВұРЎРүР ВөР С”РЎвҖҡ
                if (!description && typeof descObj === 'object' && descObj !== null) {
                    if (descObj.loc_key) {
                        // Р ВҳРЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р ВөР Сҳ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳРЎС“ Р В»Р С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘Р С‘ РЎРғ Р С”Р В»РЎРӢРЎвҖЎР С•Р Сҳ Р С‘ Р В°РЎРӮР С–РЎС“Р СҳР ВөР Р…РЎвҖҡР В°Р СҳР С‘
                        description = t(descObj.loc_key, descObj.loc_args || {});
                    } else if (descObj[currentLanguage]) {
                        description = descObj[currentLanguage] || descObj['ru'] || descObj['en'];
                    } else {
                        description = JSON.stringify(descObj);
                    }
                }

                if (!description) {
                    description = String(ev.description || 'Р СңР ВөР С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР Р…Р С•Р Вө РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р Вө');
                }

                addLogMessage(`<div style="border-left: 3px solid #f39c12; padding-left: 10px; margin: 5px 0;"><strong style="color:#f39c12;">[Р РҺР СӣР вҖҳР В«Р СһР ВҳР вҖў Р вҖҷ Р СҹР РҲР СһР Вҳ]</strong> ${description}</div>`, "system-message");
            });
        }

        if (arrivalEvent) {
            this.finish();
        }
    },

        interact: async function(objType, simId, description) {
        let formattedData = "";
        if (simId && simId !== "undefined" && simId !== "null" && window.electronAPI && window.electronAPI.nexusInteractTrekObject) {
            const res = await window.electronAPI.nexusInteractTrekObject(objType, simId);
            if (res.status === 'ok') {
                formattedData = formatTrekObjectData(objType, res.object_data);
            }
        }

        if (player && player.travel) {
            player.travel.currentEvents = null;
            player.travel.interactTarget = { type: objType, data: formattedData ? { id: simId } : null };
        }
        updateCharacterSheet();
        
        let prompt = `[SYSTEM: Р СҹР РҲР СһР вҖўР РҒР вҖўР РҺР СһР вҖҷР ВҳР вҖў Р СҹР В Р ВҳР СӣР РҺР СһР С’Р СңР СӣР вҖҷР вҖәР вҖўР СңР Сӣ]\nР РҺР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р Вө Р РҶ Р С—РЎС“РЎвҖҡР С‘: ${description || objType}\n`;
        if (formattedData) {
            prompt += `Р вҖқР В°Р Р…Р Р…РЎвҖ№Р Вө Р С•Р ВұРЎРүР ВөР С”РЎвҖҡР В° Р С•РЎвҖҡ Р Т‘Р РҶР С‘Р В¶Р С”Р В°: ${formattedData}\n`;
        }
        prompt += `Р СӣР С—Р С‘РЎвӮ¬Р С‘ РЎРғРЎвҖ Р ВөР Р…РЎС“ (Р С”Р В°Р С” РЎРҢРЎвҖҡР С• Р РҶРЎвҖ№Р С–Р В»РЎРҸР Т‘Р С‘РЎвҖҡ, Р В·Р РҶРЎС“Р С”Р С‘, Р В·Р В°Р С—Р В°РЎвҖҰР С‘) Р С‘ РЎРғР С—РЎРӮР С•РЎРғР С‘ Р С‘Р С–РЎРӮР С•Р С”Р В°, РЎвҖЎРЎвҖҡР С• Р С•Р Р… Р ВұРЎС“Р Т‘Р ВөРЎвҖҡ Р Т‘Р ВөР В»Р В°РЎвҖҡРЎРҠ. Р вҖ“Р Т‘Р С‘ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° Р С‘Р С–РЎРӮР С•Р С”Р В°.`;
                sendApiRequest(prompt, false, false, [], false);
    },

    finish: function() {
        if (this.timer) clearInterval(this.timer);
        executeCommand('setLocation', { locationName: player.travel.destinationName });
        addLogMessage(`[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’] Р СҹРЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘Р Вө Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…Р С•. Р вҖҷРЎвҖ№ Р С—РЎРӮР С‘Р ВұРЎвҖ№Р В»Р С‘ Р РҶ: ${player.travel.destinationName}.`, "system-message");
        player.travel.active = false;
        updateCharacterSheet();
        updateMapDisplay();
        const prompt = `[SYSTEM: Р СҹР РҲР СһР вҖўР РҒР вҖўР РҺР СһР вҖҷР ВҳР вҖў Р вҖ”Р С’Р вҖҷР вҖўР В Р РҒР вҖўР СңР Сӣ] Р ВҳР С–РЎРӮР С•Р С” РЎС“РЎРғР С—Р ВөРЎвӮ¬Р Р…Р С• Р С—РЎРӮР С‘Р ВұРЎвҖ№Р В» Р РҶ ${player.travel.destinationName}. Р СӣР С—Р С‘РЎвӮ¬Р С‘ Р С—РЎРӮР С‘Р ВұРЎвҖ№РЎвҖҡР С‘Р Вө Р С‘ Р С•Р ВұРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С”РЎС“ Р РҶР С•Р С”РЎРӮРЎС“Р С–.`;
        sendApiRequest(prompt, false, false, [], false);
    }
};

// --- Р ВҳР СңР СһР вҖўР вҖңР В Р С’Р ВҰР ВҳР РҮ WEB WORKER Р вҖқР вҖәР РҮ Р РҺР ВҳР СҡР РҲР вҖәР РҮР ВҰР ВҳР Вҳ Р СҡР ВҳР В Р С’ ---
// ======================================================================
let ECONOMY_ITEMS = {};
let CRAFTING_RECIPES = [];

let FACILITY_NAMES = {};
let TREK_CONFIG = {};
window.DISABLE_LOCALIZATION = false;

function syncRuntimeRegistries() {
    ECONOMY_ITEMS = window.ECONOMY_ITEMS || {};
    CRAFTING_RECIPES = window.CRAFTING_RECIPES || [];
    FACILITY_NAMES = window.FACILITY_NAMES || {};
    TREK_CONFIG = window.TREK_CONFIG;
}

function getLocalizedRuntimeAssetPaths(primaryKey, fallbackKey, replacements = {}) {
    const primary = typeof window.resolveWorldAssetPath === 'function'
        ? window.resolveWorldAssetPath(primaryKey, replacements)
        : '';
    const fallback = typeof window.resolveWorldAssetPath === 'function'
        ? window.resolveWorldAssetPath(fallbackKey, replacements)
        : '';
    return { primary, fallback };
}

function parseLocString(str, disableLoc = window.DISABLE_LOCALIZATION) {
    if (typeof str !== 'string') return str;
    let result = str;

    if (!disableLoc && str.includes('"loc_key"')) {
        const processParsed = (data, originalStr) => {
            if (data.loc_args) {
                for (let k in data.loc_args) {
                    let argStr = data.loc_args[k];
                    if (typeof argStr === 'string') {
                        if (typeof ECONOMY_ITEMS !== 'undefined') {
                            Object.keys(ECONOMY_ITEMS).forEach(itemId => {
                                const r = new RegExp('\\b' + itemId + '\\b', 'g');
                                if (r.test(argStr)) {
                                    argStr = argStr.replace(r, getItemName(itemId, player ? player.era : getRuntimeDefaultEraId()));
                                }
                            });
                        }
                        if (typeof FACILITY_NAMES !== 'undefined') {
                            Object.keys(FACILITY_NAMES).forEach(facId => {
                                const r = new RegExp('\\b' + facId + '\\b', 'g');
                                if (r.test(argStr)) {
                                    argStr = argStr.replace(r, getFacilityName(facId, player ? player.era : getRuntimeDefaultEraId()));
                                }
                            });
                        }
                        if (argStr.includes('"loc_key"')) {
                            argStr = parseLocString(argStr, disableLoc);
                        }
                        data.loc_args[k] = argStr;
                    }
                }
            }
            let trans = t(data.loc_key, data.loc_args, null);
            if (trans === null) {
                let fallbackText = data.loc_key.split('.').pop() + ": ";
                if (data.loc_args) fallbackText += Object.values(data.loc_args).join(', ');
                return fallbackText;
            }
            return trans;
        };

        try {
            let data = JSON.parse(str);
            if (data && data.loc_key) {
                result = processParsed(data, str);
            }
        } catch(e) {
            const regex = /\{"loc_key":"[^"]+"(?:,\s*"loc_args":\{.*?\})?\}/g;
            result = str.replace(regex, (match) => {
                try {
                    let data = JSON.parse(match);
                    if (data && data.loc_key) return processParsed(data, match);
                } catch(err) {
                    console.warn('[i18n] Failed to parse location JSON fragment:', match, err.message);
                }
                return match;
            });
        }
    }

    if (window.ModAPI && window.ModAPI.applyTextFilters) {
        result = window.ModAPI.applyTextFilters(result);
    }
    return result;
}


function getItemName(itemId, eraId) {
    const runtimeEraId = getRuntimeDefaultEraId();
    if (!eraId) eraId = runtimeEraId;
    let locName = t(`economy_items.${itemId}.${eraId}`);
    if (locName !== `economy_items.${itemId}.${eraId}`) return locName;
    return (ECONOMY_ITEMS[itemId] && ECONOMY_ITEMS[itemId].names)
        ? (ECONOMY_ITEMS[itemId].names[eraId] || ECONOMY_ITEMS[itemId].names[runtimeEraId] || ECONOMY_ITEMS[itemId].name || itemId)
        : (ECONOMY_ITEMS[itemId]?.name || itemId);
}
function getFacilityName(facId, eraId) {
    const runtimeEraId = getRuntimeDefaultEraId();
    if (!eraId) eraId = runtimeEraId;
    let locName = t(`facilities.${facId}.${eraId}`);
    if (locName !== `facilities.${facId}.${eraId}`) return locName;
    return (FACILITY_NAMES[facId] && FACILITY_NAMES[facId].names && FACILITY_NAMES[facId].names[eraId]) ? FACILITY_NAMES[facId].names[eraId] : facId;
}

// Р вҖҷРЎРғР С—Р С•Р СҳР С•Р С–Р В°РЎвҖҡР ВөР В»РЎРҠР Р…Р В°РЎРҸ РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРҸ Р Т‘Р В»РЎРҸ Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘ Р Р…Р С•Р РҶР С•РЎРғРЎвҖҡР ВөР в„– Р РҶ Р вҖәР ВөРЎвҖҡР С•Р С—Р С‘РЎРғРЎРҠ Р СҡР С‘РЎРӮР В°
function generateWorldNews(text, location, importance, category) {
    if (typeof World === 'undefined' || !World) return;
    if (!World.news) World.news = [];
    World.news.push({
        id: "news_" + generateUUID(),
        text: text,
        location: location || "global",
        importance: importance || 1,
        category: category || "misc",
        day: (World.current_day !== undefined ? World.current_day : Math.floor((World.tick || 0) / 24))
    });
}

let World = null;
// Defensive getter for World state РІРӮвҖқ prevents null reference errors
function getWorld() {
    return World;
}
function setWorld(newWorld) {
    World = newWorld;
}
function mutateWorld(mutator) {
    if (!World) {
        console.error('[State] Attempted to mutate null World. Call ignored.');
        return false;
    }
    mutator(World);
    return true;
}

// worldWorker РЎС“Р Т‘Р В°Р В»Р ВөР Р…, Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р ВөРЎвҖҡРЎРғРЎРҸ Р Р…Р В°РЎвҖҡР С‘Р РҶР Р…РЎвҖ№Р в„– C++ Nexus Engine

async function initWorldSimulator(initialAgents = 100, startDay = 0, isLoadMode = false) {
    // This function now delegates entirely to the integration script
    // to ensure modded data is loaded correctly.
    return loadDatabaseWithModsAndInitEngine(initialAgents, startDay, isLoadMode);
}
async function preSimulateWorldHistory(yearsToSimulate) {
    IS_PRE_SIMULATING = true;
    
    if (window.electronAPI && window.electronAPI.nexusPreSimulate) {
        const totalTicks = yearsToSimulate * 360 * 24;
        const titleEl = document.getElementById('loading-title');
        if (titleEl) titleEl.textContent = 'Р вҖәР ВөРЎвҖҡР С•Р С—Р С‘РЎРғРЎРҠ Р СҡР С‘РЎРӮР В°';
        const loadingText = document.getElementById('loading-text');
        if (loadingText) loadingText.textContent = `Р РҺР С‘Р Р…РЎвҖҡР ВөР В· Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘Р С‘ Р В·Р В° ${yearsToSimulate} Р В»Р ВөРЎвҖҡ (Р РҶРЎвҖ№РЎвҖЎР С‘РЎРғР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ Р РҶ Nexus Engine)...`;

        console.log(`[Nexus] Р вҖ”Р В°Р С—РЎС“РЎРғР С” Р С—РЎРӮР Вө-РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘ ${totalTicks} РЎвҖҡР С‘Р С”Р С•Р РҶ Р РҶ C++...`);
        const res = await window.electronAPI.nexusPreSimulate(World, totalTicks);
        console.log(`[Nexus] Р СӣРЎвҖҡР РҶР ВөРЎвҖҡ Р С—РЎРӮР Вө-РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘ Р С—Р С•Р В»РЎС“РЎвҖЎР ВөР Р…:`, res ? `status=${res.status}` : 'null');
        if (res.status === 'ok') {
            if (res.world) setWorld(res.world);
            if (res.relevant_news) World.relevant_news = res.relevant_news;
            if (res.items) res.items.forEach(([k, v]) => ItemRegistry.set(k, v));
            if (res.containers) res.containers.forEach(([k, v]) => setContainer(k, v));
            if (res.deleted_items) res.deleted_items.forEach(id => ItemRegistry.delete(id));
            if (res.deleted_containers) res.deleted_containers.forEach(id => ContainerRegistry.delete(id));
                    processMonsterQuests();
            
            IS_PRE_SIMULATING = false;
            if (loadingText) loadingText.textContent = 'Р вҖңР ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘РЎРҸ Р СҳР С‘РЎРӮР В° Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…Р В°...';
            updateWorldChroniclesDisplay();
            updateTradeJournalDisplay();
            updatePortPanel();
            if (typeof updateHoldingsDisplay === 'function') updateHoldingsDisplay();
            document.dispatchEvent(new Event('PreSimulateComplete'));
            return;
        } else {
            console.error("[Nexus] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С—РЎРӮР Вө-РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘:", res);
        }
    } else {
        console.error("[Nexus] Р СңР В°РЎвҖҡР С‘Р РҶР Р…РЎвҖ№Р в„– Р Т‘Р РҶР С‘Р В¶Р С•Р С” Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р ВөР Р… Р Т‘Р В»РЎРҸ Р С—РЎРӮР Вө-РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘!");
    }
    
    IS_PRE_SIMULATING = false;
    document.dispatchEvent(new Event('PreSimulateComplete'));
}

function processMonsterQuests() {
    if (!World || !World.monsters || !player || !player.quests) return;

    let playerRegionId = null;
    if (player.location) {
        const locLower = player.location.toLowerCase().trim();
        for (let rId in World.regions) {
            if (locLower.includes(World.regions[rId].name.toLowerCase().trim())) {
                playerRegionId = rId;
                break;
            }
        }
    }

    let questsUpdated = false;

    World.monsters.forEach(m => {
        if (m.health > 0 && m.state === "ACTIVE") {
            // Р вҖҷРЎвҖ№Р Т‘Р В°Р ВөР Сҳ Р С”Р РҶР ВөРЎРғРЎвҖҡ Р СһР СӣР вҖәР В¬Р СҷР Сӣ Р ВөРЎРғР В»Р С‘ Р СҳР С•Р Р…РЎРғРЎвҖҡРЎРӮ Р Р…Р В°РЎвҖҰР С•Р Т‘Р С‘РЎвҖҡРЎРғРЎРҸ Р РҶ РЎвҖҡР ВөР С”РЎС“РЎвҖ°Р ВөР Сҳ РЎРӮР ВөР С–Р С‘Р С•Р Р…Р Вө Р С‘Р С–РЎРӮР С•Р С”Р В°
            if (m.region_id === playerRegionId) {
                const questId = "hunt_" + m.id;
                if (!player.quests[questId]) {
                    player.quests[questId] = {
                        id: questId,
                        aiIdentifier: questId,
                        title: "Р вҖҷР ВөР В»Р С‘Р С”Р В°РЎРҸ Р СӣРЎвҖҰР С•РЎвҖҡР В°: " + m.name,
                        objective: "Р РҲР Р…Р С‘РЎвҖЎРЎвҖҡР С•Р В¶Р С‘РЎвҖҡРЎРҠ РЎвҖЎРЎС“Р Т‘Р С•Р РҶР С‘РЎвҖ°Р Вө Р РҶ РЎРӮР ВөР С–Р С‘Р С•Р Р…Р Вө " + (World.regions[m.region_id] ? World.regions[m.region_id].name : m.region_id),
                        description: "Р СҡР ВөРЎРғРЎвҖҡР Р…РЎвҖ№Р Вө Р В¶Р С‘РЎвҖҡР ВөР В»Р С‘ Р РҶ РЎС“Р В¶Р В°РЎРғР Вө. Р ВӯР С—Р С‘РЎвҖЎР ВөРЎРғР С”Р С•Р Вө РЎвҖЎРЎС“Р Т‘Р С•Р РҶР С‘РЎвҖ°Р Вө РЎвҖҡР ВөРЎРӮРЎРӮР С•РЎРӮР С‘Р В·Р С‘РЎРӮРЎС“Р ВөРЎвҖҡ РЎРҢРЎвҖҡР С‘ Р В·Р ВөР СҳР В»Р С‘. Р СңР В°Р С–РЎРӮР В°Р Т‘Р В° Р В·Р В° Р ВөР С–Р С• Р С–Р С•Р В»Р С•Р РҶРЎС“ Р ВұРЎС“Р Т‘Р ВөРЎвҖҡ РЎвҖ°Р ВөР Т‘РЎРӮР С•Р в„–.",
                        reward: "Р РҺР С•Р С”РЎРӮР С•Р РҶР С‘РЎвҖ°Р В° Р В»Р С•Р С–Р С•Р РҶР В°, Р РҺР В»Р В°Р РҶР В°",
                        issuer: "Р СҡР ВөРЎРғРЎвҖҡР Р…РЎвҖ№Р Вө РЎРғР В»РЎС“РЎвҖҰР С‘",
                        status: 'active'
                    };
                    // Р вҖҳР В»Р С•Р С”Р С‘РЎРӮРЎС“Р ВөР Сҳ РЎРғР С—Р В°Р Сҳ Р РҶ Р В»Р С•Р С– Р РҶР С• Р РҶРЎРӮР ВөР СҳРЎРҸ Р С—РЎРӮР Вө-РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘ Р С‘ РЎвҖһР С•Р Р…Р С•Р РҶРЎвҖ№РЎвҖҰ РЎРӮР В°РЎРғРЎвҖЎР ВөРЎвҖҡР С•Р РҶ
                    if (!IS_PRE_SIMULATING && !window.isSimulatingTime) {
                        addLogMessage(`[Р С’Р вҖҷР СһР Сӣ-Р СҷР вҖҷР вҖўР РҺР Сһ] Р вҖқР С•Р ВұР В°Р РҶР В»Р ВөР Р…Р С• Р СҳР ВөРЎРғРЎвҖҡР Р…Р С•Р Вө Р В·Р В°Р Т‘Р В°Р Р…Р С‘Р Вө: Р вҖҷР ВөР В»Р С‘Р С”Р В°РЎРҸ Р СӣРЎвҖҰР С•РЎвҖҡР В° Р Р…Р В° ${m.name}!`, "system-message");
                        questsUpdated = true;
                    }
                }
            }
        }
    });

    Object.keys(player.quests).forEach(qId => {
        if (qId.startsWith("hunt_") && player.quests[qId].status === 'active') {
            const mId = qId.replace("hunt_", "");
            const monster = World.monsters.find(m => m.id === mId);
            // Р вҖўРЎРғР В»Р С‘ Р СҳР С•Р Р…РЎРғРЎвҖҡРЎРӮ Р СҳР ВөРЎРӮРЎвҖҡР РҶ Р ВҳР вҖәР Вҳ Р РҶР С•Р С•Р ВұРЎвҖ°Р Вө Р С‘РЎРғРЎвҖЎР ВөР В· Р С‘Р В· Р СҳР В°РЎРғРЎРғР С‘Р РҶР В° (РЎС“Р ВұР С‘РЎвҖҡ Р В°РЎРӮР СҳР С‘Р ВөР в„–)
            if (!monster || monster.health <= 0) {
                player.quests[qId].status = 'completed';
                if (!IS_PRE_SIMULATING && !window.isSimulatingTime) {
                    addLogMessage(`[Р С’Р вҖҷР СһР Сӣ-Р СҷР вҖҷР вҖўР РҺР Сһ] Р вҖ”Р В°Р Т‘Р В°Р Р…Р С‘Р Вө Р РҶРЎвҖ№Р С—Р С•Р В»Р Р…Р ВөР Р…Р С•: ${player.quests[qId].title}!`, "level-up");
                    questsUpdated = true;
                }
            }
        }
    });

    if (questsUpdated && !IS_PRE_SIMULATING && !window.isSimulatingTime) {
        updateQuestList();
    }
}

// Р ВӨР В»Р В°Р С– РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-РЎРӮР ВөР В¶Р С‘Р СҳР В° Р Т‘Р РҶР С‘Р В¶Р С”Р В°
let _realtimeActive = false;

function updateWorldSimulation(pulses) {
    if (!World) return;
    
    if (window.electronAPI && window.electronAPI.nexusStartRealtime) {
        World.time = World.time || { accumulatedMinutes: 0 };
        World.time.accumulatedMinutes += pulses * 5;
        
        let ticks = Math.floor(World.time.accumulatedMinutes / 60);
        if (ticks > 0) {
            World.time.accumulatedMinutes -= ticks * 60;

            // Р В Р ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-РЎРӮР ВөР В¶Р С‘Р Сҳ: Р Т‘Р РҶР С‘Р В¶Р С•Р С” РЎРғР С‘Р СҳРЎС“Р В»Р С‘РЎРӮРЎС“Р ВөРЎвҖҡ Р С‘ РЎРғРЎвҖҡРЎРӮР С‘Р СҳР С‘РЎвҖҡ Р С•Р ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С‘РЎРҸ Р СҳР С‘РЎРӮР В°
            // Р С”Р В°Р В¶Р Т‘РЎвҖ№Р Вө 500Р СҳРЎРғ (Р С—Р С• РЎС“Р СҳР С•Р В»РЎвҖЎР В°Р Р…Р С‘РЎРӢ). JS Р С—Р С•Р В»РЎС“РЎвҖЎР В°Р ВөРЎвҖҡ Р СҳР С‘РЎРӮ Р СҳР С–Р Р…Р С•Р РҶР ВөР Р…Р Р…Р С• РЎвҖЎР ВөРЎРӮР ВөР В· onNexusRealtimeUpdate.
            // Р вҖ”Р В°Р С—РЎС“РЎРғР С”Р В°Р ВөР Сҳ РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ Р ВөРЎРғР В»Р С‘ Р ВөРЎвҖ°РЎвҖҳ Р Р…Р Вө Р В·Р В°Р С—РЎС“РЎвҖ°Р ВөР Р…, Р С‘ Р С•РЎвҖҡР С—РЎРӮР В°Р РҶР В»РЎРҸР ВөР Сҳ РЎвҖҡР С‘Р С”Р С‘.
            const startRealtimeIfNeeded = async () => {
                if (!_realtimeActive) {
                    try {
                        await window.electronAPI.nexusStartRealtime(500);
                        _realtimeActive = true;
                    } catch (e) {
                        console.warn("[Nexus] Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С—РЎС“РЎРғРЎвҖҡР С‘РЎвҖҡРЎРҠ РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-РЎРӮР ВөР В¶Р С‘Р Сҳ, fallback Р Р…Р В° Р ВұР В»Р С•Р С”Р С‘РЎРӮРЎС“РЎРӢРЎвҖ°Р С‘Р в„–:", e);
                    }
                }
                // Р СӣРЎвҖҡР С—РЎРӮР В°Р РҶР В»РЎРҸР ВөР Сҳ РЎвҖҡР С‘Р С”Р С‘ Р Т‘Р В»РЎРҸ РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘
                window.electronAPI.nexusSimulate(World, ticks, player?.location || "").then(res => {
                    if (res.status === 'ok') {
                        // Р В Р ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-Р С•Р ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С‘РЎРҸ Р С—РЎРӮР С‘РЎвҖҰР С•Р Т‘РЎРҸРЎвҖҡ РЎвҖЎР ВөРЎРӮР ВөР В· onNexusRealtimeUpdate,
                        // Р Р…Р С• РЎвҖһР С‘Р Р…Р В°Р В»РЎРҠР Р…РЎвҖ№Р в„– Р С•РЎвҖҡР РҶР ВөРЎвҖҡ РЎвҖҡР С•Р В¶Р Вө Р С•Р ВұРЎРӮР В°Р ВұР В°РЎвҖҡРЎвҖ№Р РҶР В°Р ВөР Сҳ Р Т‘Р В»РЎРҸ trek_events Р С‘ UI
                        if (res.world) setWorld(res.world);
                        if (res.relevant_news) { const w = getWorld(); if (w) w.relevant_news = res.relevant_news; }
                        if (res.items) res.items.forEach(([k, v]) => ItemRegistry.set(k, v));
                        if (res.containers) res.containers.forEach(([k, v]) => setContainer(k, v));
                        if (res.deleted_items) res.deleted_items.forEach(id => ItemRegistry.delete(id));
                        if (res.deleted_containers) res.deleted_containers.forEach(id => ContainerRegistry.delete(id));
                        processMonsterQuests();

                        if (res.world && res.world.player_trek) {
                            if (!player.travel) player.travel = {};
                            player.travel.active = res.world.player_trek.active;
                            player.travel.paused = res.world.player_trek.paused;
                            player.travel.elapsedHours = res.world.player_trek.elapsed_hours;
                            player.travel.totalHours = res.world.player_trek.total_hours;
                            player.travel.currentX = res.world.player_trek.current_x;
                            player.travel.currentY = res.world.player_trek.current_y;
                        }
                        if (res.trek_events && res.trek_events.length > 0) {
                            LivingRoads.handleEvents(res.trek_events);
                        }

                        if (typeof updateEnvironmentPanel === 'function') updateEnvironmentPanel();
                        if (typeof updateHoldingsDisplay === 'function') updateHoldingsDisplay();
                        if (window.isSimulatingTime) {
                            hideLoadingScreen();
                            window.isSimulatingTime = false;
                        }
                        if (World.needsGlobalEvent) {
                            World.needsGlobalEvent = false;
                            runWorldSimulationTick();
                        } else if (!isWaitingForAI && !window.isSimulatingTime) {
                            if (userInput) userInput.disabled = false;
                            if (sendButton) sendButton.disabled = false;
                        }
                    } else {
                        console.error("[Nexus] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘:", res);
                    }
                }).catch(err => {
                    console.error("[Nexus] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р РҶРЎвҖ№Р В·Р С•Р РҶР В° nexusSimulate:", err);
                    if (window.isSimulatingTime) {
                        hideLoadingScreen();
                        window.isSimulatingTime = false;
                    }
                    if (!isWaitingForAI) {
                        if (userInput) userInput.disabled = false;
                        if (sendButton) sendButton.disabled = false;
                    }
                });
            };
            startRealtimeIfNeeded();
        }
    } else {
        console.error("[Nexus] Р СңР В°РЎвҖҡР С‘Р РҶР Р…РЎвҖ№Р в„– Р Т‘Р РҶР С‘Р В¶Р С•Р С” Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р ВөР Р… Р Т‘Р В»РЎРҸ РЎРғР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘Р С‘ Р РҶРЎРӮР ВөР СҳР ВөР Р…Р С‘!");
    }
}

// Р СӣРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С”Р В° РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-РЎРӮР ВөР В¶Р С‘Р СҳР В° Р С—РЎРӮР С‘ Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…Р С‘Р С‘/Р С—Р В°РЎС“Р В·Р Вө
async function stopRealtimeSimulation() {
    if (_realtimeActive && window.electronAPI && window.electronAPI.nexusStopRealtime) {
        try {
            await window.electronAPI.nexusStopRealtime();
            _realtimeActive = false;
        } catch (e) {
            console.warn("[Nexus] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С•РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С”Р С‘ РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ:", e);
        }
    }
}

async function runWorldSimulationTick() {
    if (isSimulatingWorld) return;
    isSimulatingWorld = true;
    isWaitingForAI = true;
    if (userInput) userInput.disabled = true;
    if (sendButton) sendButton.disabled = true;
    
    addCalculationMessage("[Р РҺР ВҳР РҺР СһР вҖўР СҡР С’: Р РҺР ВҳР СҡР РҲР вҖәР РҮР ВҰР ВҳР РҮ] Р СҡР С‘РЎРӮ Р С—РЎРӮР С‘РЎвҖҰР С•Р Т‘Р С‘РЎвҖҡ Р РҶ Р Т‘Р РҶР С‘Р В¶Р ВөР Р…Р С‘Р Вө...");
    const loaderDiv = document.createElement('div');
    loaderDiv.id = 'world-sim-loader';
    loaderDiv.className = 'ether-loader-container';
    loaderDiv.innerHTML = `
        <div class="astrolabe" style="filter: hue-rotate(120deg) brightness(0.8);">
            <div class="astrolabe-ring"></div><div class="astrolabe-ring"></div><div class="astrolabe-ring"></div><div class="astrolabe-core"></div>
        </div>
                    <div class="ether-text-container">
                <span class="ether-text-title" style="color: #e74c3c; text-shadow: 0 0 10px #e74c3c;">Р СҹР вҖўР В Р вҖўР РҺР СһР В Р СӣР в„ўР СҷР С’ Р В Р вҖўР С’Р вҖәР В¬Р СңР СӣР РҺР СһР Вҳ...</span>
                <span class="ether-text-subtitle">Р вҖқР РҶР С‘Р В¶Р С•Р С” Р СҡР С‘РЎРӮР В° Р В°Р Р…Р В°Р В»Р С‘Р В·Р С‘РЎРӮРЎС“Р ВөРЎвҖҡ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ</span>
            </div>
            <button class="ether-cancel-btn" data-action="cancel-api">
                <i class="fas fa-times"></i> Р СҹРЎРӮР ВөРЎРӮР РҶР В°РЎвҖҡРЎРҠ РЎРғР РҶРЎРҸР В·РЎРҠ
            </button>
    `;
    const gameLog = document.getElementById('game-log');
    if (gameLog) {
        gameLog.appendChild(loaderDiv);
        gameLog.scrollTo({ top: gameLog.scrollHeight, behavior: 'smooth' });
    }

    try {
        const currentDay = (World.current_day !== undefined ? World.current_day : Math.floor((World.tick || 0) / 24));
        let daysPassed = currentDay - (player.lastWorldSimDay || 0);
        if (daysPassed <= 0) daysPassed = 1;
        player.lastWorldSimDay = currentDay;

        let worldSummary = "=== Р СһР вҖўР СҷР РҲР В©Р вҖўР вҖў Р РҺР СӣР РҺР СһР СӣР РҮР СңР ВҳР вҖў Р СҡР ВҳР В Р С’ (Р РҺР В«Р В Р В«Р вҖў Р вҖқР С’Р СңР СңР В«Р вҖў) ===\n";
        for (let rId in World.regions) {
            let r = World.regions[rId];
            let ownerName = World.factions[r.factionId] ? World.factions[r.factionId].name : "Р СңР ВөРЎвҖҡ Р РҶР В»Р В°Р Т‘Р ВөР В»РЎРҠРЎвҖ Р В°";
            
            let resArr = [];
            if (r.vault_id && ContainerRegistry.has(r.vault_id)) {
                let vault = ContainerRegistry.get(r.vault_id);
                let counts = {};
                getContainerItems(vault).forEach(itemId => {
                    let item = ItemRegistry.get(itemId);
                    if (item) {
                        counts[item.prototype_id] = (counts[item.prototype_id] || 0) + item.stack_size;
                    }
                });
                for (let k in counts) {
                    if (counts[k] > 0) {
                        let name = getItemName(k, player ? player.era : getRuntimeDefaultEraId());
                        resArr.push(`${name}: ${counts[k]}`);
                    }
                }
            }
            let resStr = resArr.length > 0 ? resArr.slice(0, 6).join(', ') : "Р СҹРЎС“РЎРғРЎвҖҡР С•";

            worldSummary += `Р В Р ВөР С–Р С‘Р С•Р Р…: ${r.name} (Р вҖҷР В»Р В°Р Т‘Р ВөР В»Р ВөРЎвҖ : ${ownerName}). Р СңР В°РЎРғР ВөР В»Р ВөР Р…Р С‘Р Вө: ${r.population}. Р СҹР С•Р С–Р С•Р Т‘Р В°: ${r.weather || "Р СңР С•РЎРӮР СҳР В°Р В»РЎРҠР Р…Р В°РЎРҸ"}. Р В Р ВөРЎРғРЎС“РЎРӮРЎРғРЎвҖ№: ${resStr}.\n`;
        }
        
        let activeWars = [];
        for (let fId in World.factions) {
            let f = World.factions[fId];
            // Р вҖ”Р С•Р В»Р С•РЎвҖҡР С• РЎРғРЎвҖЎР С‘РЎвҖҡР В°Р ВөР Сҳ Р С‘Р В· РЎвҖһР С‘Р В·Р С‘РЎвҖЎР ВөРЎРғР С”Р С‘РЎвҖҰ Р В·Р В°Р С—Р В°РЎРғР С•Р РҶ РЎРғРЎвҖҡР С•Р В»Р С‘РЎвҖЎР Р…Р С•Р С–Р С• РЎРӮР ВөР С–Р С‘Р С•Р Р…Р В°
            const capitalRegionId = Object.keys(World.regions).find(rid => World.regions[rid].factionId === fId);
            let gold = 0;
            if (capitalRegionId && World.regions[capitalRegionId]?.vault_id) {
                gold = countRealItems(World.regions[capitalRegionId].vault_id, getPrimaryCurrencyPrototypeId('gold'));
            }
            const manpower = availableManpower(f);
            worldSummary += `Р ВӨРЎРӮР В°Р С”РЎвҖ Р С‘РЎРҸ: ${f.name}. Р вҖқР С•РЎРғРЎвҖҡРЎС“Р С—Р Р…Р В°РЎРҸ Р В¶Р С‘Р РҶР В°РЎРҸ РЎРғР С‘Р В»Р В°: ${manpower}. Р вҖ”Р С•Р В»Р С•РЎвҖҡР С• Р РҶ РЎРғРЎвҖҡР С•Р В»Р С‘РЎвҖ Р Вө: ${gold}. Р С’РЎРӮР СҳР С‘Р в„– Р РҶ Р С—Р С•РЎвҖҰР С•Р Т‘Р Вө Р РҺР вҖўР в„ўР В§Р С’Р РҺ: ${f.armies.length}.\n`;
            for (let target in f.diplomacy) {
                if (f.diplomacy[target] === "war") activeWars.push(`${f.name} Р РҶР С•РЎРӢР ВөРЎвҖҡ РЎРғ ${World.factions[target].name}`);
            }
        }
        if (activeWars.length > 0) worldSummary += `\nР вҖҷР С•Р в„–Р Р…РЎвҖ№: ${[...new Set(activeWars)].join(", ")}\n`;

        let recentNews = World.news
            .map(n => ({ ...n, daysOld: Math.max(0, currentDay - (n.day || 0)) }))
            .filter(n => n.daysOld <= daysPassed)
            .filter(n => n.importance >= 2)
            .sort((a, b) => b.daysOld - a.daysOld)
            .map(n => `[${n.daysOld} Р Т‘Р Р…. Р Р…Р В°Р В·Р В°Р Т‘, Р вҖәР С•Р С”Р В°РЎвҖ Р С‘РЎРҸ: ${n.location}]: ${parseLocString(n.text)}`)
            .join("\n");
        worldSummary += `\nР ТҗРЎРӮР С•Р Р…Р С•Р В»Р С•Р С–Р С‘РЎРҸ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳР Р…РЎвҖ№РЎвҖҰ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р в„– Р В·Р В° РЎРҢРЎвҖҡР С•РЎвҖҡ Р С—Р ВөРЎРӮР С‘Р С•Р Т‘:\n${recentNews || "Р СңР ВөРЎвҖҡ РЎРғР РҶР ВөР В¶Р С‘РЎвҖҰ Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ"}\n`;

        let mName = "Р СҡР ВөРЎРғРЎРҸРЎвҖ Р В°";
        if (window.WORLD_CONFIG && window.WORLD_CONFIG.months && window.WORLD_CONFIG.months[player.gameTime.month - 1]) {
            const m = window.WORLD_CONFIG.months[player.gameTime.month - 1];
            mName = typeof t === 'function' ? t(m.name_i18n_key, null, m.id) : m.id;
        }
        let currentDateStr = `${player.gameTime.day} ${mName}, ${player.gameTime.year} Р С–Р С•Р Т‘Р В°`;
        
        const prompt = `### Р вҖқР ВҳР В Р вҖўР СҷР СһР ВҳР вҖҷР С’: Р вҖқР вҖҷР ВҳР вҖ“Р СӣР Сҷ Р СҡР ВҳР В Р С’ (WORLD SIMULATOR) v5.0\nР СһРЎвҖ№ РІРӮвҖқ Р В°Р Р…Р В°Р В»Р С‘РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘Р в„– Р СҳР С•Р Т‘РЎС“Р В»РЎРҠ. Р СһР РҶР С•РЎРҸ Р В·Р В°Р Т‘Р В°РЎвҖЎР В°: Р Р…Р В°Р С—Р С‘РЎРғР В°РЎвҖҡРЎРҠ Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘РЎвҖЎР ВөРЎРғР С”РЎС“РЎРӢ РЎРғР РҶР С•Р Т‘Р С”РЎС“ ("Р вҖҷР ВөРЎРғРЎвҖҡР С‘ Р С‘Р В· Р ВӯРЎвҖһР С‘РЎРӮР В°") Р Р…Р В° Р С•РЎРғР Р…Р С•Р РҶР Вө Р РҺР В«Р В Р В«Р Тҗ Р вҖқР С’Р СңР СңР В«Р Тҗ.\n\n[Р РҺР ВҳР РҺР СһР вҖўР СҡР СңР СӣР вҖў Р вҖҷР В Р вҖўР СҡР РҮ]:\n- Р СһР ВөР С”РЎС“РЎвҖ°Р В°РЎРҸ Р Т‘Р В°РЎвҖҡР В°: ${currentDateStr}\n- Р вҖҷРЎРӮР ВөР СҳР ВөР Р…Р С‘ Р С—РЎРӮР С•РЎвӮ¬Р В»Р С• РЎРғ Р С—РЎРӮР С•РЎвӮ¬Р В»Р С•Р в„– РЎРғР РҶР С•Р Т‘Р С”Р С‘: РЎРӮР С•Р РҶР Р…Р С• ${daysPassed} Р Т‘Р Р…Р ВөР в„–.\n\n${worldSummary}\n\nР СҹР В Р ВҳР СҷР С’Р вҖ”Р В« (Р вҖәР СӣР вҖңР ВҳР СҷР С’ Р Вҳ Р ВӨР С’Р СҷР СһР В«):\n1. Р вҖҷР Р…Р С‘Р СҳР В°РЎвҖҡР ВөР В»РЎРҠР Р…Р С• Р С‘Р В·РЎС“РЎвҖЎР С‘ "Р ТҗРЎРӮР С•Р Р…Р С•Р В»Р С•Р С–Р С‘РЎРӢ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳР Р…РЎвҖ№РЎвҖҰ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р в„–". Р СӣР ВұРЎРӮР В°РЎвҖ°Р В°Р в„– Р РҶР Р…Р С‘Р СҳР В°Р Р…Р С‘Р Вө Р Р…Р В° Р С—Р С•Р СҳР ВөРЎвҖҡР С”РЎС“ "[X Р Т‘Р Р…. Р Р…Р В°Р В·Р В°Р Т‘]". Р вҖўРЎРғР В»Р С‘ Р С•РЎРғР В°Р Т‘Р В° Р Р…Р В°РЎвҖЎР В°Р В»Р В°РЎРғРЎРҠ 14 Р Т‘Р Р…Р ВөР в„– Р Р…Р В°Р В·Р В°Р Т‘ Р С‘ Р Т‘Р В»Р С‘Р В»Р В°РЎРғРЎРҠ 4 Р Т‘Р Р…РЎРҸ, Р В·Р Р…Р В°РЎвҖЎР С‘РЎвҖҡ Р СӣР СңР С’ Р РҲР вҖ“Р вҖў Р вҖ”Р С’Р вҖҷР вҖўР В Р РҒР ВҳР вҖәР С’Р РҺР В¬. Р СңР Вө РЎРғР СҳР ВөР в„– Р С—Р С‘РЎРғР В°РЎвҖҡРЎРҠ, РЎвҖЎРЎвҖҡР С• Р С–Р С•РЎРӮР С•Р Т‘ "Р С—РЎРӮР С•Р Т‘Р ВөРЎРӮР В¶Р С‘РЎвҖҡРЎРғРЎРҸ Р ВөРЎвҖ°Р Вө 4 Р Т‘Р Р…РЎРҸ"!\n2. Р РҺР РҶР ВөРЎРӮРЎРҠРЎРғРЎРҸ РЎРғ "Р СһР вҖўР СҷР РҲР В©Р ВҳР Сҡ Р РҺР СӣР РҺР СһР СӣР РҮР СңР ВҳР вҖўР Сҡ Р СҡР ВҳР В Р С’". Р вҖўРЎРғР В»Р С‘ Р РҶ РЎРғР С—Р С‘РЎРғР С”Р Вө "Р С’РЎРӮР СҳР С‘Р в„– Р РҶ Р С—Р С•РЎвҖҰР С•Р Т‘Р Вө Р РҺР вҖўР в„ўР В§Р С’Р РҺ" РЎС“ РЎвҖһРЎРӮР В°Р С”РЎвҖ Р С‘Р С‘ 0 Р В°РЎРӮР СҳР С‘Р в„–, Р В·Р Р…Р В°РЎвҖЎР С‘РЎвҖҡ Р РҶ Р вҖқР С’Р СңР СңР В«Р в„ў Р СҡР СӣР СҡР вҖўР СңР Сһ Р С•Р Р…Р В° Р Р…Р С‘Р С”Р С•Р С–Р С• Р Р…Р Вө Р С•РЎРғР В°Р В¶Р Т‘Р В°Р ВөРЎвҖҡ Р С‘ Р Р…Р С‘Р С”РЎС“Р Т‘Р В° Р Р…Р Вө Р С‘Р Т‘Р ВөРЎвҖҡ. Р вҖҷРЎРғР Вө Р ВөРЎвҖҳ Р С—Р С•РЎвҖҰР С•Р Т‘РЎвҖ№ Р С‘Р В· Р ТҗРЎРӮР С•Р Р…Р С•Р В»Р С•Р С–Р С‘Р С‘ РЎС“Р В¶Р Вө Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…РЎвҖ№, Р С•Р С—Р С‘РЎРғРЎвҖ№Р РҶР В°Р в„– Р С‘РЎвҖҰ Р С”Р В°Р С” Р С—РЎРӮР С•РЎвӮ¬Р В»РЎвҖ№Р Вө РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ.\n3. Р СӣР С—Р С‘РЎвӮ¬Р С‘ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ Р РҶ Р С—РЎРӮР С•РЎвӮ¬Р ВөР Т‘РЎвӮ¬Р ВөР Сҳ Р РҶРЎРӮР ВөР СҳР ВөР Р…Р С‘, Р С”Р В°Р С” Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘Р С”, Р С—Р С•Р Т‘Р РҶР С•Р Т‘РЎРҸРЎвҖ°Р С‘Р в„– Р С‘РЎвҖҡР С•Р С–Р С‘ Р В·Р В° ${daysPassed} Р Т‘Р Р…Р ВөР в„–. Р СӣР С—Р ВөРЎРӮР С‘РЎРӮРЎС“Р в„– РЎвҖҡР С•Р В»РЎРҠР С”Р С• РЎвҖһР В°Р С”РЎвҖҡР В°Р СҳР С‘ Р С‘Р В· РЎРғР РҶР С•Р Т‘Р С”Р С‘, Р СңР вҖў Р вҖҷР В«Р вҖқР РҲР СҡР В«Р вҖҷР С’Р в„ў Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ Р В°РЎРӮР СҳР С‘Р в„–, Р ВөРЎРғР В»Р С‘ Р С‘РЎвҖҰ Р Р…Р ВөРЎвҖҡ Р РҶ Р В»Р С•Р С–Р В°РЎвҖҰ.\n4. Р СңР В°РЎвҖЎР Р…Р С‘ РЎвҖҡР ВөР С”РЎРғРЎвҖҡ РЎРғ РЎвҖЎР ВөРЎвҖҡР С”Р С•Р С–Р С• Р С•Р ВұР С•Р В·Р Р…Р В°РЎвҖЎР ВөР Р…Р С‘РЎРҸ Р С—РЎРӮР С•РЎвӮ¬Р ВөР Т‘РЎвӮ¬Р ВөР С–Р С• Р РҶРЎРӮР ВөР СҳР ВөР Р…Р С‘ (Р СңР В°Р С—РЎРӮР С‘Р СҳР ВөРЎРӮ: "Р вҖ”Р В° Р СҳР С‘Р Р…РЎС“Р РҶРЎвӮ¬Р С‘Р Вө ${daysPassed} Р Т‘Р Р…Р ВөР в„–...", "Р Сҷ ${currentDateStr} РЎРғР С‘РЎвҖҡРЎС“Р В°РЎвҖ Р С‘РЎРҸ...").\n5. Р СһР РҶР С•Р в„– Р С•РЎвҖҡР РҶР ВөРЎвҖҡ Р вҖқР СӣР вҖәР вҖ“Р вҖўР Сң Р вҖҳР В«Р СһР В¬ Р РҺР СһР В Р СӣР вҖңР Сӣ Р вҖҷР С’Р вҖәР ВҳР вҖқР СңР В«Р Сҡ JSON Р СӣР вҖҳР Р„Р вҖўР СҷР СһР СӣР Сҡ. Р СҡР В°РЎРғРЎРғР С‘Р РҶ actions Р С•РЎРғРЎвҖҡР В°Р РҶР В»РЎРҸР в„– Р СҹР РҲР РҺР СһР В«Р Сҡ [].\nР ВӨР С•РЎРӮР СҳР В°РЎвҖҡ:\n{\n  "narrative": "Р СһР РҶР С•РЎРҸ РЎвҖҡР С•РЎвҖЎР Р…Р В°РЎРҸ Р С‘ Р В»Р С•Р С–Р С‘РЎвҖЎР Р…Р В°РЎРҸ РЎвҖҰРЎРӮР С•Р Р…Р С‘Р С”Р В° РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р в„–...",\n  "actions": []\n}`;
        
        let modelId = localModelId;
        if (currentApiProvider === 'gemini') modelId = geminiModelId;
        else if (currentApiProvider === 'llmost') modelId = llmostModelId;
        else if (currentApiProvider === 'openrouter') modelId = openrouterModelId;
        else if (currentApiProvider === 'deepseek') modelId = deepseekModelId;
        else if (currentApiProvider === 'omniroute') modelId = omnirouteModelId;
        
        const raw = await performAiFetch(prompt, [], modelId, `Р С’Р Р…Р В°Р В»Р С‘Р В· Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ Р В·Р В° ${daysPassed} Р Т‘Р Р…Р ВөР в„–.`);
        const res = parseAIResponse(raw);
    if (window.ModAPI) await ModAPI.emit('onAIResponseReceived', {raw, parsed: res, location: player?.location});
        
        if (loaderDiv) loaderDiv.remove();
        
        if (res.ai_reasoning) {
            addCalculationMessage(`[Р СҡР В«Р РҺР вҖәР Вҳ Р ВҳР Вҳ (Р РҺР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘РЎРҸ)]:\n${res.ai_reasoning}`, "calc-info");
        }

        if (res.actions) {
            for (const a of res.actions) await executeCommand(a.command, a.args);
        }

        if (res.narrative) {
            const container = document.querySelector('.game-container');
            if (container) {
                container.classList.remove('heavy-shake');
                void container.offsetWidth; 
                container.classList.add('heavy-shake');
            }
            
            addLogMessage(res.narrative, "world-event");
        }

    } catch (e) { 
        console.error("World Sim Error:", e);
        if (loaderDiv) loaderDiv.remove();
        isSimulatingWorld = false;
        showAiErrorModal(
            e.message || String(e),
            false,
            () => { runWorldSimulationTick(); },
            "Р РҺР ВұР С•Р в„– Р ВӯРЎвҖһР С‘РЎРӮР Р…Р С•Р в„– Р РҺР ВөРЎвҖҡР С‘",
            "Р СҹРЎРӮР С•Р С‘Р В·Р С•РЎвӮ¬Р ВөР В» РЎРғР ВұР С•Р в„– Р С—РЎРӮР С‘ Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘ Р вҖҷР ВөРЎРғРЎвҖҡР ВөР в„– Р С‘Р В· Р ВӯРЎвҖһР С‘РЎРӮР В° (Р РҺР С‘Р СҳРЎС“Р В»РЎРҸРЎвҖ Р С‘РЎРҸ Р СҡР С‘РЎРӮР В°). Р СҹР С•Р РҶРЎвҖҡР С•РЎРӮР С‘РЎвҖҡРЎРҠ Р С—Р С•Р С—РЎвҖ№РЎвҖҡР С”РЎС“?"
        );
    } finally { 
        isSimulatingWorld = false;
        isWaitingForAI = false;
        if (userInput) {
            userInput.disabled = false;
            userInput.focus();
        }
        if (sendButton) sendButton.disabled = false;
        updateWorldChroniclesDisplay();
        updateTradeJournalDisplay();
        updatePortPanel();
        if (typeof updateHoldingsDisplay === 'function') updateHoldingsDisplay();
    }
}
