// --- Р РҺР ВҳР РҺР СһР вҖўР СҡР С’ Р вҖәР СӣР СҷР С’Р вҖәР В¬Р СңР СӣР в„ў Р СҷР С’Р В Р СһР В« (Canvas + Sprite) ---
let TILESET_IMAGE = null;
const SOURCE_TILE_SIZE = 16; // Р ВҳРЎРғРЎвҖҰР С•Р Т‘Р Р…РЎвҖ№Р в„– РЎРӮР В°Р В·Р СҳР ВөРЎРӮ РЎвҖҡР В°Р в„–Р В»Р В° Р РҶ Kenney 1-bit
const SPACING = 1;           // Р СӣРЎвҖҡРЎРғРЎвҖҡРЎС“Р С— Р СҳР ВөР В¶Р Т‘РЎС“ РЎвҖҡР В°Р в„–Р В»Р В°Р СҳР С‘ Р РҶ РЎРғР С—РЎРӮР В°Р в„–РЎвҖҡ-Р В»Р С‘РЎРғРЎвҖҡР Вө
const RENDER_TILE_SIZE = 48; // Р В Р В°Р В·Р СҳР ВөРЎРӮ Р С•РЎвҖҡРЎРӮР С‘РЎРғР С•Р РҶР С”Р С‘ Р Р…Р В° РЎРҢР С”РЎРӮР В°Р Р…Р Вө
let USE_SPRITE_RENDERER = true;
let currentLocalMapPlots = null;
let currentLocalMapSize = { width: 0, height: 0 };

let TILE_SPRITE_MAP = {};
let AVAILABLE_TILES_LIST = "";;

function getSpriteCoords(type) {
    return TILE_SPRITE_MAP[type] || TILE_SPRITE_MAP['void'] || { x: 0, y: 0 };
}

async function loadTileSet() {
    try {
        const response = await fetch('assets/assets/kenny1bit-tagger/tile_tags.json?t=' + Date.now());
        if (response.ok) {
            const data = await response.json();
            if (data.mappings) {
                TILE_SPRITE_MAP = data.mappings;
                AVAILABLE_TILES_LIST = Object.keys(TILE_SPRITE_MAP).join(', ');
                console.log(`[TileSet] Р вҖ”Р В°Р С–РЎРӮРЎС“Р В¶Р ВөР Р… Р СҳР В°Р С—Р С—Р С‘Р Р…Р С– РЎвҖҡР В°Р в„–Р В»Р С•Р РҶ: ${Object.keys(TILE_SPRITE_MAP).length} РЎвӮ¬РЎвҖҡ.`);
            }
        } else {
            console.warn('[TileSet] Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ tileset.json');
        }
    } catch (e) {
        console.error('[TileSet] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ tileset.json:', e);
    }

    return new Promise((resolve) => {
        const img = new Image();
        img.onload = () => {
            TILESET_IMAGE = img;
            console.log('[TileSet] Р вҖ”Р В°Р С–РЎРӮРЎС“Р В¶Р ВөР Р… РЎРғР С—РЎРӮР В°Р в„–РЎвҖҡ-Р В»Р С‘РЎРғРЎвҖҡ Kenney 1-Bit');
            resolve(true);
        };
        img.onerror = (err) => {
            console.error('[TileSet] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ РЎРғР С—РЎРӮР В°Р в„–РЎвҖҡ-Р В»Р С‘РЎРғРЎвҖҡР В°, Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р ВөР Сҳ fallback CSS', err);
            USE_SPRITE_RENDERER = false;
            resolve(false);
        };
        img.src = 'assets/assets/kenny1bit-tagger/Tilesheet/colored-transparent.png';
    });
}

function toggleMapRenderer(useSprite) {
    USE_SPRITE_RENDERER = useSprite;
    if (currentLocalMapPlots && currentLocalMapSize.width) {
        const args = {
            plots: currentLocalMapPlots,
            size: `${currentLocalMapSize.width}x${currentLocalMapSize.height}`,
            description: 'Р СӣР ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С•'
        };
        buildLocalMap(args);
        const fullscreenCanvas = document.getElementById('fullscreen-map-canvas');
        if (fullscreenCanvas && fullscreenCanvas.parentElement) {
            renderCanvasMap(currentLocalMapPlots, currentLocalMapSize.width, currentLocalMapSize.height, fullscreenCanvas);
        }
    }
}







