let activeEraSpecialLore = "";

async function loadActiveEraLore(eraId) {
// Р СҷРЎРҢРЎвӮ¬ Р Т‘Р В»РЎРҸ Р С—Р ВөРЎРӮР ВөР СҳР ВөР Р…Р Р…РЎвҖ№РЎвҖҰ Р С—РЎРӮР С•Р СҳР С—РЎвҖҡР В°, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р Р…Р Вө Р С—Р С•Р Т‘Р С–РЎРӮРЎС“Р В¶Р В°РЎвҖҡРЎРҠ Р С”Р В°Р В¶Р Т‘РЎвҖ№Р в„– РЎРӮР В°Р В·
let promptVariablesCache = {};
    if (!eraId) return;

    if (window.ModAPI && window.ModAPI.isTotalConversion) {
        console.log(`[Total Conversion] Р СҹРЎРӮР С•Р С—РЎС“РЎРғР С” Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ Р РҶР В°Р Р…Р С‘Р В»РЎРҠР Р…Р С•Р С–Р С• Р В»Р С•РЎРӮР В° РЎРҢР С—Р С•РЎвҖҰР С‘ ${eraId}.`);
        activeEraSpecialLore = "";
        if (window.ModAPI) {
            const hookData = { lore: activeEraSpecialLore };
            await window.ModAPI.emit('onEraLoreLoad', hookData, eraId);
            activeEraSpecialLore = hookData.lore;
        }
        return;
    }

    try {
        activeEraSpecialLore = await loadPromptFromFile(`era_lore.${eraId}`);
        
        // --- Р ВҳР СңР СһР вҖўР вҖңР В Р С’Р ВҰР ВҳР РҮ Р СҡР СӣР вҖқР СӣР вҖҷ (Р ВӯР СҹР СӣР ТҗР С’) ---
        if (window.ModAPI) {
            const hookData = { lore: activeEraSpecialLore };
            await window.ModAPI.emit('onEraLoreLoad', hookData, eraId);
            activeEraSpecialLore = hookData.lore;
        }
        // ------------------------------
        
        console.log(`[Context] Р вҖҳР В°Р В·Р В° Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ РЎРҢР С—Р С•РЎвҖҰР С‘ ${eraId} Р С‘Р Р…РЎвҖҡР ВөР С–РЎРӮР С‘РЎРӮР С•Р РҶР В°Р Р…Р В°.`);
    } catch (e) {
        console.error("[Context] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ РЎРҢР С—Р С•РЎвҖҰР С‘:", e);
        activeEraSpecialLore = "// Р вҖқР С•Р С—Р С•Р В»Р Р…Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…РЎвҖ№Р Вө Р Т‘Р В°Р Р…Р Р…РЎвҖ№Р Вө Р С—Р С• РЎРҢР С—Р С•РЎвҖҰР Вө Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р Р…РЎвҖ№.";
    }
}

