// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р РҲР С—РЎРӮР В°Р РҶР В»Р ВөР Р…Р С‘РЎРҸ Р ВӯР С”РЎРӮР В°Р Р…Р С•Р Сҳ Р вҖ”Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ (Р СңР СӣР вҖҷР СӣР вҖў) ---

function populateErasUI(erasData) {
    if (!charEraSelect || !erasData) return;
    charEraSelect.innerHTML = '';
    erasData.forEach((era, index) => {
        const opt = document.createElement('option');
        opt.value = era.id;
        opt.dataset.descriptionKey = era.description_i18n_key || `characterCreation.era${era.id.charAt(0).toUpperCase() + era.id.slice(1)}Desc`;
        opt.textContent = typeof t === 'function' ? t(era.display_name_i18n_key, null, era.name) : era.name;
        if (index === 0) opt.selected = true;
        charEraSelect.appendChild(opt);
    });
    updateEraDescription();
}

function populateRacesUI(racesData) {
    if (!charRaceSelect || !racesData) return;
    const currentValue = charRaceSelect.value;
    charRaceSelect.innerHTML = `<option value="" disabled ${!currentValue ? 'selected' : ''} data-i18n="characterCreation.racePlaceholder">${typeof t === 'function' ? t('characterCreation.racePlaceholder') : '-- Р вҖҷРЎвҖ№Р ВұР ВөРЎРӮР С‘РЎвҖҡР Вө РЎРӮР В°РЎРғРЎС“ --'}</option>`;
    racesData.forEach(race => {
        const opt = document.createElement('option');
        opt.value = race.id;
        const i18nKey = `characterCreation.race${race.id.charAt(0).toUpperCase() + race.id.slice(1)}`;
        opt.textContent = typeof t === 'function' ? t(i18nKey, null, race.name) : race.name;
        if (race.id === currentValue) opt.selected = true;
        charRaceSelect.appendChild(opt);
    });
}

function populateClassesUI(classesData) {
    if (!charClassSelect || !classesData) return;
    const currentValue = charClassSelect.value;
    charClassSelect.innerHTML = `<option value="" disabled ${!currentValue ? 'selected' : ''} data-i18n="characterCreation.classPlaceholder">${typeof t === 'function' ? t('characterCreation.classPlaceholder') : '-- Р вҖҷРЎвҖ№Р ВұР ВөРЎРӮР С‘РЎвҖҡР Вө Р С”Р В»Р В°РЎРғРЎРғ --'}</option>`;
    classesData.forEach(cls => {
        const opt = document.createElement('option');
        opt.value = cls.id;
        opt.textContent = typeof t === 'function' && cls.display_name_i18n_key ? t(cls.display_name_i18n_key, null, cls.name) : cls.name;
        if (cls.id === currentValue) opt.selected = true;
        charClassSelect.appendChild(opt);
    });
}

function updateEraDescription() {
    if (!charEraSelect || !eraDescriptionBox) return;

    // Р СңР В°РЎвҖҰР С•Р Т‘Р С‘Р Сҳ Р РҶРЎвҖ№Р ВұРЎРӮР В°Р Р…Р Р…РЎвҖ№Р в„– РЎРҢР В»Р ВөР СҳР ВөР Р…РЎвҖҡ <option>
    const selectedOption = charEraSelect.options[charEraSelect.selectedIndex];
    if (!selectedOption) {
        eraDescriptionBox.classList.remove('visible');
        eraDescriptionBox.innerHTML = '';
        return;
    }

    // Р СҹР С•Р В»РЎС“РЎвҖЎР В°Р ВөР Сҳ Р С”Р В»РЎРӢРЎвҖЎ Р Т‘Р В»РЎРҸ РЎвҖҡР ВөР С”РЎРғРЎвҖҡР В° Р Р…Р В°Р С—РЎРӮРЎРҸР СҳРЎС“РЎРӢ Р С‘Р В· data-Р В°РЎвҖҡРЎРӮР С‘Р ВұРЎС“РЎвҖҡР В°
    const descriptionKey = selectedOption.dataset.descriptionKey;
    const descriptionText = t(descriptionKey, null, '');

    // Р СҹРЎРӮРЎРҸРЎвҖЎР ВөР Сҳ Р ВұР В»Р С•Р С”, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ РЎРғР СҳР ВөР Р…Р С‘РЎвҖҡРЎРҠ РЎвҖҡР ВөР С”РЎРғРЎвҖҡ Р С‘ Р В·Р В°Р С—РЎС“РЎРғРЎвҖҡР С‘РЎвҖҡРЎРҠ Р В°Р Р…Р С‘Р СҳР В°РЎвҖ Р С‘РЎРӢ Р В·Р В°Р Р…Р С•Р РҶР С•
    eraDescriptionBox.classList.remove('visible');

    setTimeout(() => {
        if (descriptionText) {
            eraDescriptionBox.innerHTML = sanitizeHTML(descriptionText);
            eraDescriptionBox.classList.add('visible');
        } else {
            eraDescriptionBox.innerHTML = '';
        }
    }, 200); // Р СңР ВөР ВұР С•Р В»РЎРҠРЎвӮ¬Р В°РЎРҸ Р В·Р В°Р Т‘Р ВөРЎРӮР В¶Р С”Р В° Р Т‘Р В»РЎРҸ Р С—Р В»Р В°Р РҶР Р…Р С•Р в„– Р В°Р Р…Р С‘Р СҳР В°РЎвҖ Р С‘Р С‘
}

// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ File System Access API ---



// 1. Р СҷР С•Р Р…РЎвҖһР С‘Р С–РЎС“РЎРӮР В°РЎвҖ Р С‘РЎРҸ Р С”Р Р…Р С•Р С—Р С•Р С” (Р СһР С‘Р С—РЎвҖ№ Р ВұРЎРӮР С•РЎРғР С”Р С•Р РҶ)
const quickTags = [
    { label: 'РІСҷвҖқРҝС‘РҸ Attack', type: 'combat', stat: 'atk' },
    { label: 'СҖСҹвҖәРҺРҝС‘РҸ Defend', type: 'combat', stat: 'def' },
    { label: 'СҖСҹРӢРҶ D20', type: 'stat', stat: 'd20' },
    { label: 'СҖСҹвҖҷР„ STR', type: 'stat', stat: 'str' },
    { label: 'СҖСҹВӨС‘ DEX', type: 'stat', stat: 'dex' },
    { label: 'СҖСҹВ§В  INT', type: 'stat', stat: 'int' },
    { label: 'РІСңВӨРҝС‘РҸ CON', type: 'stat', stat: 'con' },
    { label: 'СҖСҹвҖ”РҲРҝС‘РҸ CHA', type: 'stat', stat: 'cha' }
];

// 2. Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р С—Р В°Р Р…Р ВөР В»Р С‘ Р С”Р Р…Р С•Р С—Р С•Р С” (Р вҖҷРЎвҖ№Р В·РЎвҖ№Р РҶР В°Р ВөРЎвҖҡРЎРғРЎРҸ Р С—РЎРӮР С‘ РЎРғРЎвҖҡР В°РЎРӮРЎвҖҡР Вө Р С‘Р С–РЎРӮРЎвҖ№)
function initQuickTags() {
    const container = document.getElementById('quick-tags-bar');
    if (!container) return;

    container.innerHTML = ''; // Р СӣРЎвҖЎР С‘РЎРғРЎвҖҡР С”Р В° Р С—Р ВөРЎРӮР ВөР Т‘ РЎРғР С•Р В·Р Т‘Р В°Р Р…Р С‘Р ВөР Сҳ

    quickTags.forEach(tag => {
        const btn = document.createElement('div');
        btn.className = `tag-chip ${tag.type}`;
        btn.textContent = tag.label;

        // Р СҹРЎРӮР С‘ Р С”Р В»Р С‘Р С”Р Вө РЎРғР С•Р В·Р Т‘Р В°Р ВөР Сҳ Р Р…Р Вө РЎвҖҡР ВөР С”РЎРғРЎвҖҡ, Р В° Р РҶР С‘Р В·РЎС“Р В°Р В»РЎРҠР Р…РЎС“РЎРӢ Р С—Р В»Р В°РЎвӮ¬Р С”РЎС“
        btn.addEventListener('click', (e) => {
            e.preventDefault();
            if (createRollBadge(tag.stat, tag.label)) {
                btn.style.transform = 'scale(1.1)';
                btn.style.filter = 'brightness(1.5)';
                setTimeout(() => {
                    btn.style.transform = '';
                    btn.style.filter = '';
                }, 200);
            }
        });

        container.appendChild(btn);
    });
}

// 3. Р РҺР С•Р В·Р Т‘Р В°Р Р…Р С‘Р Вө Р С—Р В»Р В°РЎвӮ¬Р С”Р С‘ РЎРғ РЎРӮР ВөР В·РЎС“Р В»РЎРҠРЎвҖҡР В°РЎвҖҡР С•Р Сҳ (Р СҡР В°РЎвҖҡР ВөР СҳР В°РЎвҖҡР С‘Р С”Р В° Р С—РЎРӮР С•Р С‘РЎРғРЎвҖҰР С•Р Т‘Р С‘РЎвҖҡ Р В·Р Т‘Р ВөРЎРғРЎРҠ)
function createRollBadge(statKey, labelText) {
    if (!player) return;

    const container = document.getElementById('active-rolls-container');
    if (!container) return;

    if (container.children.length >= 5) return;

    // --- Р С’Р СңР СһР ВҳР В§Р ВҳР Сһ: Р вҖ”Р С’Р СҹР СӣР СҡР ВҳР СңР С’Р СңР ВҳР вҖў Р вҖҳР В Р СӣР РҺР СҷР С’ ---
    // Р вҖўРЎРғР В»Р С‘ Р С‘Р С–РЎРӮР С•Р С” РЎС“Р В¶Р Вө Р ВұРЎРӮР С•РЎРғР В°Р В» РЎРҢРЎвҖҡР С•РЎвҖҡ Р С”РЎС“Р ВұР С‘Р С” Р РҶ РЎРҢРЎвҖҡР С•Р Сҳ РЎвҖҰР С•Р Т‘РЎС“, Р ВұР ВөРЎРӮР ВөР Сҳ РЎРғРЎвҖҡР В°РЎРӮР С•Р Вө Р В·Р Р…Р В°РЎвҖЎР ВөР Р…Р С‘Р Вө.
    // Р ВӯРЎвҖҡР С• Р Р…Р Вө Р Т‘Р В°Р ВөРЎвҖҡ "Р С—Р ВөРЎРӮР ВөР ВұРЎРӮР В°РЎРғРЎвҖ№Р РҶР В°РЎвҖҡРЎРҠ" Р С”РЎС“Р ВұР С‘Р С”, РЎС“Р Т‘Р В°Р В»РЎРҸРЎРҸ Р С—Р В»Р В°РЎвӮ¬Р С”РЎС“.
    let roll;
    if (turnRollMemory[statKey]) {
        roll = turnRollMemory[statKey];
    } else {
        roll = rollRuntimeD20();
        turnRollMemory[statKey] = roll;
    }

    let modifier = 0;
    let cleanLabel = labelText.replace(/[\uD800-\uDBFF][\uDC00-\uDFFF]/g, '').trim();

    switch (statKey) {
        case 'str':
        case 'dex':
        case 'int':
        case 'con':
        case 'cha':
            modifier = getStatModifier(statKey);
            cleanLabel = `${statKey.toUpperCase()} Check`;
            break;
        case 'atk':
            if (['rogue', 'bard', 'ranger'].includes(player.class)) {
                modifier = getStatModifier('dex');
            } else {
                modifier = getStatModifier('str');
            }
            cleanLabel = "Attack";
            break;
        case 'def':
            modifier = getStatModifier('dex');
            cleanLabel = "Defend";
            break;
        case 'd20':
            modifier = 0;
            cleanLabel = "D20 Roll";
            break;
    }

    // Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҸР ВөР Сҳ, Р Р…Р ВөРЎвҖҡ Р В»Р С‘ РЎС“Р В¶Р Вө РЎвҖҡР В°Р С”Р С•Р в„– Р С—Р В»Р В°РЎвӮ¬Р С”Р С‘ Р РҶР С‘Р В·РЎС“Р В°Р В»РЎРҠР Р…Р С•, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р Р…Р Вө Р Т‘РЎС“Р ВұР В»Р С‘РЎРӮР С•Р РҶР В°РЎвҖҡРЎРҠ
    const existingBadges = container.querySelectorAll('.roll-badge');
    for (let badge of existingBadges) {
        if (badge.dataset.statKey === statKey) {
            badge.classList.remove('shake');
            void badge.offsetWidth;
            badge.classList.add('shake');
            return false; // Р РҲР В¶Р Вө Р РҶР С‘РЎРғР С‘РЎвҖҡ
        }
    }

    const total = roll + modifier;
    const sign = modifier >= 0 ? "+" : "";
    const resultText = `[ROLL_RESULT: ${roll} | STAT: ${statKey} | MOD: ${modifier} | TOTAL: ${total}]`;

    const badge = document.createElement('div');
    badge.className = 'roll-badge';
    badge.dataset.statKey = statKey; // Р вҖқР В»РЎРҸ Р С—РЎРӮР С•Р РҶР ВөРЎРӮР С”Р С‘ Р Т‘РЎС“Р ВұР В»Р С‘Р С”Р В°РЎвҖҡР С•Р РҶ

    if (roll === 20) badge.classList.add('crit-success');
    if (roll === 1) badge.classList.add('crit-fail');

    badge.dataset.resultText = resultText;

    // Р СһР ВөР С—Р ВөРЎРӮРЎРҠ Р С‘Р С–РЎРӮР С•Р С” Р РҶР С‘Р Т‘Р С‘РЎвҖҡ Р С‘РЎвҖҡР С•Р С–Р С•Р РҶРЎС“РЎРӢ РЎРғРЎС“Р СҳР СҳРЎС“ Р С‘ Р С‘Р В· РЎвҖЎР ВөР С–Р С• Р С•Р Р…Р В° РЎРғР С•РЎРғРЎвҖҡР С•Р С‘РЎвҖҡ
    const modDisplay = modifier !== 0 ? ` <small style="opacity:0.7; font-size:0.85em;">(${roll}${sign}${modifier})</small>` : ` <small style="opacity:0.7; font-size:0.85em;">(${roll})</small>`;
    badge.innerHTML = `
        <span>${cleanLabel}: ${total}${modDisplay}</span>
        <span class="roll-badge-close" title="Р РҲР Т‘Р В°Р В»Р С‘РЎвҖҡРЎРҠ Р ВұРЎРӮР С•РЎРғР С•Р С”">РІСҡвҖ“</span>
    `;

    badge.querySelector('.roll-badge-close').addEventListener('click', () => {
        badge.remove();
    });

    container.appendChild(badge);
    return true;
}


// 4. Р СҹР В°РЎРӮРЎРғР ВөРЎРӮ РЎвҖҡР ВөР С–Р С•Р РҶ (Р С—РЎРӮР ВөР РҶРЎРӮР В°РЎвҖ°Р В°Р ВөРЎвҖҡ {d20_str} Р РҶ РЎРӮР ВөР В·РЎС“Р В»РЎРҠРЎвҖҡР В°РЎвҖҡ Р ВұРЎРӮР С•РЎРғР С”Р В°)
function parseInlineRolls(text) {
    if (!player) return text;

    // Р В Р ВөР С–РЎС“Р В»РЎРҸРЎРӮР С”Р В° Р С‘РЎвҖ°Р ВөРЎвҖҡ Р РҶРЎРғРЎвҖҳ Р РҶ РЎвҖһР С‘Р С–РЎС“РЎРӮР Р…РЎвҖ№РЎвҖҰ РЎРғР С”Р С•Р ВұР С”Р В°РЎвҖҰ
    return text.replace(/\{(.*?)\}/g, (match, content) => {
        const tag = content.toLowerCase().trim();

        // Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• Р С”Р С•Р СҳР В°Р Р…Р Т‘Р В° Р ВұРЎРӮР С•РЎРғР С”Р В° (Р Р…Р В°РЎвҖЎР С‘Р Р…Р В°Р ВөРЎвҖҡРЎРғРЎРҸ РЎРғ d20_) Р С‘Р В»Р С‘ Р С—РЎРӮР С•РЎРғРЎвҖҡР С• d20
        if (tag.startsWith('d20')) {
            let roll = rollRuntimeD20();
            let modifier = 0;
            let label = "D20";

            // Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• РЎРғР С—Р ВөРЎвҖ Р С‘РЎвҖһР С‘РЎвҖЎР Р…РЎвҖ№Р в„– Р ВұРЎРӮР С•РЎРғР С•Р С” (Р Р…Р В°Р С—РЎРӮР С‘Р СҳР ВөРЎРӮ d20_str)
            if (tag.includes('_')) {
                const statName = tag.split('_')[1];

                switch (statName) {
                    case 'str':
                        modifier = Math.floor((player.stats.str - 10) / 2);
                        label = "STR Check";
                        break;
                    case 'dex':
                        modifier = Math.floor((player.stats.dex - 10) / 2);
                        label = "DEX Check";
                        break;
                    case 'int':
                        modifier = Math.floor((player.stats.int - 10) / 2);
                        label = "INT Check";
                        break;
                    case 'con':
                        modifier = Math.floor((player.stats.con - 10) / 2);
                        label = "CON Check";
                        break;
                    case 'cha':
                        modifier = Math.floor((player.stats.cha - 10) / 2);
                        label = "CHA Check";
                        break;
                    case 'atk':
                        // Р С’Р РҶРЎвҖҡР С•-Р РҶРЎвҖ№Р ВұР С•РЎРӮ РЎРғРЎвҖҡР В°РЎвҖҡР В° Р Т‘Р В»РЎРҸ Р В°РЎвҖҡР В°Р С”Р С‘
                        if (['rogue', 'bard', 'ranger'].includes(player.class)) {
                            modifier = Math.floor((player.stats.dex - 10) / 2);
                            label = "Attack (DEX)";
                        } else {
                            modifier = Math.floor((player.stats.str - 10) / 2);
                            label = "Attack (STR)";
                        }
                        break;
                    case 'def':
                        modifier = Math.floor((player.stats.dex - 10) / 2);
                        label = "Defend";
                        break;
                }
            }

            const total = roll + modifier;
            const sign = modifier >= 0 ? "+" : "";

            // Р ВӨР С•РЎРӮР СҳР В°РЎвҖҡ Р РҶРЎвҖ№Р РҶР С•Р Т‘Р В°: [СҖСҹРӢРҶ STR Check: 15 (roll:12+3)]
            return `[СҖСҹРӢРҶ ${label}: ${total} (roll:${roll}${sign}${modifier})]`;
        }

        // Р вҖўРЎРғР В»Р С‘ РЎвҖҡР ВөР С– Р Р…Р Вө РЎРӮР В°РЎРғР С—Р С•Р В·Р Р…Р В°Р Р…, Р РҶР С•Р В·Р РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р С”Р В°Р С” Р ВөРЎРғРЎвҖҡРЎРҠ
        return match;
    });
}



/**
 * Р РҲР СңР ВҳР вҖҷР вҖўР В Р РҺР С’Р вҖәР В¬Р СңР В«Р в„ў Р Вҳ Р СҹР СӣР вҖәР СңР В«Р в„ў Р РҺР вҖәР вҖўР СҹР СӣР Сҷ Р вҖқР С’Р СңР СңР В«Р Тҗ (SNAPSHOT)
 * Р вҖ”Р Т‘Р ВөРЎРғРЎРҠ РЎРғР С•Р ВұРЎРӮР В°Р Р…РЎвҖ№ Р вҖҷР РҺР вҖў Р Т‘Р В°Р Р…Р Р…РЎвҖ№Р Вө Р С•Р ВұРЎРүР ВөР С”РЎвҖҡР В° player Р ВұР ВөР В· Р С‘РЎРғР С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р в„–.
 */
/**
 * Р СӣР вҖҳР вҖәР вҖўР вҖңР В§Р вҖўР СңР СңР В«Р в„ў Р РҺР вҖәР вҖўР СҹР СӣР Сҷ Р вҖқР вҖәР РҮ Р С’Р вҖҷР СһР Сӣ-Р СһР вҖўР РҺР СһР вҖўР В Р С’
 * Р РҺР С•Р Т‘Р ВөРЎРӮР В¶Р С‘РЎвҖҡ РЎвҖҡР С•Р В»РЎРҠР С”Р С• РЎвҖҡР С•, РЎвҖЎРЎвҖҡР С• Р РҶР С‘Р Т‘Р С‘РЎвҖҡ РЎРғР В°Р Сҳ Р С‘Р С–РЎРӮР С•Р С”, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р Р…Р Вө Р С—Р ВөРЎРӮР ВөР С–РЎРӮРЎС“Р В¶Р В°РЎвҖҡРЎРҠ Р С”Р С•Р Р…РЎвҖҡР ВөР С”РЎРғРЎвҖҡ Р В»Р С•Р С”Р В°Р В»РЎРҠР Р…РЎвҖ№РЎвҖҰ Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„–.
 */
function buildLitePlayerSnapshot() {
    if (!player) return "{}";
    
    const nearbyNpcs = Object.values(player.visibleEntities).filter(e => e.type === 'npc' || e.type === 'enemy' || e.type === 'creature').map(e => ({
        name: e.name,
        type: e.type,
        isHostile: e.isHostile,
        hp: e.stats?.hp
    }));

    const inv = player.container_backpack ? (ContainerRegistry.get(player.container_backpack)?.items || []).map(id => {
        let it = ItemRegistry.get(id);
        return it ? `${it.custom_props?.name || it.prototype_id} (x${it.stack_size})` : null;
    }).filter(Boolean) : [];

    const eq = player.container_equipment ? (ContainerRegistry.get(player.container_equipment)?.items || []).map(id => {
        let it = ItemRegistry.get(id);
        return it ? `${it.slot_index}: ${it.custom_props?.name || it.prototype_id}` : null;
    }).filter(Boolean) : [];

    const activeQuests = Object.values(player.quests || {}).filter(q => q.status === 'active').map(q => q.title + ": " + q.objective);

    return JSON.stringify({
        player: {
            name: player.name,
            gender: player.gender || 'not_specified',
            class: player.class,
            location: player.location,
            hp: `${player.stats.hp}/${player.stats.maxHp}`,
            gold: player.stats.gold
        },
        equipment: eq,
        inventory: inv,
        nearby_entities: nearbyNpcs,
        active_quests: activeQuests
    }, null, 2);
}

function buildFullPlayerSnapshot() {
    if (!player) return "Р СҷР В Р ВҳР СһР ВҳР В§Р вҖўР РҺР СҷР С’Р РҮ Р СӣР РҒР ВҳР вҖҳР СҷР С’: Р вҖқР С’Р СңР СңР В«Р вҖў Р ВҳР вҖңР В Р СӣР СҷР С’ Р СӣР СһР РҺР РҲР СһР РҺР СһР вҖҷР РҲР В®Р Сһ";

    const inHands = player.equipment.right_hand ? player.equipment.right_hand.name : 'Р СңР С‘РЎвҖЎР ВөР С–Р С•';
    
            let worldContextString = "";
        
        const allMapPoints = [
            ...Object.keys(globalLocations || {}).map(k => ({ ...globalLocations[k], id: k })),
            ...Object.values(player.mapMarkers || {})
        ].filter(p => p && p.name);
        const mapCoordsString = allMapPoints.map(p => `${p.name} [ID: ${p.id}]`).join('; ');
        worldContextString += `\n=== Р СҷР С’Р В Р СһР С’ Р СҡР ВҳР В Р С’ (Р вҖқР СӣР РҺР СһР РҲР СҹР СңР В«Р вҖў Р вҖәР СӣР СҷР С’Р ВҰР ВҳР Вҳ Р Вҳ Р ВҳР Тҗ ID) ===\n${mapCoordsString}\n==================================================\n`;

            if (World) {
        worldContextString = "\n=== MASMP STATE VECTORS ===\n";
        let playerRegion = null;
        for (let rId in World.regions) {
            if (player.location.toLowerCase().includes(World.regions[rId].name.toLowerCase())) {
                playerRegion = rId; break;
            }
        }
        if (playerRegion) {
            let r = World.regions[playerRegion];
            let ownerFaction = World.factions[r.factionId];
            let ownerId = ownerFaction ? ownerFaction.id : "none";
            
            worldContextString += `[SYS_VEC | LOC:${r.id} | SEA:${r.current_season} | WTH:${r.weather || "clear"} | FAC:${ownerId} | THR:${r.threat_level} | STAB:${r.stability} | OCC:${r.isOccupied}]\n`;
            
            const marketFallbackPrices = getGameplayRuntimeConfig().economy.market_fallback_prices || {};
            let prices = `food:${Math.round(r.markets.bread ?? requireRuntimeNumber(marketFallbackPrices.bread, 'gameplay_runtime.economy.market_fallback_prices.bread'))},wood:${Math.round(r.markets.wood ?? requireRuntimeNumber(marketFallbackPrices.wood, 'gameplay_runtime.economy.market_fallback_prices.wood'))},ore:${Math.round(r.markets.iron_ore ?? requireRuntimeNumber(marketFallbackPrices.iron_ore, 'gameplay_runtime.economy.market_fallback_prices.iron_ore'))},weap:${Math.round(r.markets.weapons ?? requireRuntimeNumber(marketFallbackPrices.weapons, 'gameplay_runtime.economy.market_fallback_prices.weapons'))}`;
            worldContextString += `[ECON_VEC | LOC:${r.id} | PRICES:${prices}]\n`;
            
            if (r.cityLayout && r.cityLayout.length > 0) {
                let bldgs = r.cityLayout.filter(b => b.type !== 'empty' && b.type !== 'road').map(b => `${b.type}:${b.sublocation_id}`).join(',');
                if (bldgs) worldContextString += `[CITY_VEC | LOC:${r.id} | BLDGS:${bldgs}]\n`;
            }
        }

        let facVecs = [];
        for (let fId in World.factions) {
            let f = World.factions[fId];
            let enemies = Object.keys(f.diplomacy).filter(t => f.diplomacy[t] === 'war').join(',');
            facVecs.push(`[FAC_VEC | ID:${fId} | WEX:${f.warExhaustion} | WAR:${enemies || 'none'}]`);
        }
        worldContextString += facVecs.join('\n') + '\n';

        let goodsStats = {};
        for (let rId in World.regions) {
            let r = World.regions[rId];
            if (!r.vault_id) continue;
            let pop = r.population || 0;
            for (let good in ECONOMY_ITEMS) {
                if (!goodsStats[good]) goodsStats[good] = { stock: 0, demand: 0 };
                goodsStats[good].stock += countRealItems(r.vault_id, good);
                goodsStats[good].demand += pop * 0.01;
            }
        }
        let deficitArray = [];
        for (let good in goodsStats) {
            let ratio = goodsStats[good].demand / (goodsStats[good].stock + 1);
            deficitArray.push({ good: good, ratio: ratio });
        }
        deficitArray.sort((a, b) => b.ratio - a.ratio);
        let top3 = deficitArray.slice(0, 3).map(item => item.good).join(',');
        worldContextString += `[GLOB_ECON_VEC | DEFICIT:${top3 || 'none'}]\n`;

        let activeMonsters = (World.monsters || []).filter(m => m.health > 0).map(m => `${m.type}:${m.region_id}:L${m.level}`).join(',');
        if (activeMonsters) worldContextString += `[MONSTER_VEC | ACT:${activeMonsters}]\n`;

        let activeDisasters = (World.map && World.map.disasters) ? World.map.disasters.filter(d => d.days_active > 0).map(d => `${d.type}:${d.affected_regions.join('-')}`).join(',') : "";
        if (activeDisasters) worldContextString += `[DISASTER_VEC | ACT:${activeDisasters}]\n`;

        let recentNewsStr = "Р СңР ВөРЎвҖҡ РЎРғР РҶР ВөР В¶Р С‘РЎвҖҰ Р Р…Р С•Р РҶР С•РЎРғРЎвҖҡР ВөР в„–.";
        if (typeof World !== 'undefined' && World && World.relevant_news && World.relevant_news.length > 0) {
            recentNewsStr = World.relevant_news.map(n => {
                let daysOld = Math.max(0, (World.current_day || 0) - (n.day || 0));
                return `[${daysOld}d ago, ${n.location}] ${parseLocString(n.text)}`;
            }).join("\n");
        }
        worldContextString += `\n=== RELEVANT EVENTS ===\n${recentNewsStr}\n`;

        worldContextString += "==================================================\n";
    }

    if (typeof World !== 'undefined' && World && World.monsters && World.monsters.length > 0) {
        worldContextString += "\n=== Р ВӯР СҹР ВҳР В§Р вҖўР РҺР СҷР ВҳР вҖў Р В§Р РҲР вҖқР СӣР вҖҷР ВҳР В©Р С’ Р вҖҷ Р СҡР ВҳР В Р вҖў (Р вҖңР вҖәР СӣР вҖҳР С’Р вҖәР В¬Р СңР С’Р РҮ Р РҲР вҖңР В Р СӣР вҖ”Р С’) ===\n";
        World.monsters.forEach(m => {
            if (m.health > 0) {
                worldContextString += `РІРӮСһ ${m.name} (Р СһР С‘Р С—: ${m.type}, Р РҲРЎРӮ: ${m.level}, HP: ${m.health}/${m.maxHealth}, Р С’РЎвҖҡР В°Р С”Р В°: ${m.attack}, Р вҖ”Р В°РЎвҖ°Р С‘РЎвҖҡР В°: ${m.defense}). Р вҖәР С•Р С”Р В°РЎвҖ Р С‘РЎРҸ: ${m.region_id}. Р вҖәР С•Р С–Р С•Р РҶР С•: Р С”Р С•Р Р…РЎвҖҡР ВөР в„–Р Р…Р ВөРЎРӮ ${m.treasure_chest_id}.\n`;
            }
        });
        worldContextString += "Р вҖңР Сҡ Р ВҳР СңР РҺР СһР В Р РҲР СҷР ВҰР ВҳР РҮ: Р вҖўРЎРғР В»Р С‘ Р С‘Р С–РЎРӮР С•Р С” Р РҶРЎРғРЎвҖҡРЎС“Р С—Р В°Р ВөРЎвҖҡ Р РҶ Р ВұР С•Р в„– РЎРғ РЎвҖЎРЎС“Р Т‘Р С•Р РҶР С‘РЎвҖ°Р ВөР Сҳ, Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р в„– Р С”Р С•Р СҳР В°Р Р…Р Т‘РЎС“ `addEnvironment` РЎРғ РЎРҢРЎвҖҡР С‘Р СҳР С‘ РЎРғРЎвҖҡР В°РЎвҖҡР В°Р СҳР С‘. Р СҹРЎРӮР С‘ Р ВөР С–Р С• РЎРғР СҳР ВөРЎРӮРЎвҖҡР С‘ Р СӣР вҖҳР РҮР вҖ”Р С’Р СһР вҖўР вҖәР В¬Р СңР Сӣ Р РҶРЎвҖ№Р В·Р С•Р РҶР С‘ Р С”Р С•Р СҳР В°Р Р…Р Т‘РЎС“ `killMonster` РЎРғ Р В°РЎРӮР С–РЎС“Р СҳР ВөР Р…РЎвҖҡР С•Р Сҳ `monsterId`, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ РЎС“Р Т‘Р В°Р В»Р С‘РЎвҖҡРЎРҠ Р ВөР С–Р С• РЎРғ Р С–Р В»Р С•Р ВұР В°Р В»РЎРҠР Р…Р С•Р в„– Р С”Р В°РЎРӮРЎвҖҡРЎвҖ№.\n==================================================\n";
    }

    const playerPhysicalLocation = resolveActorLocation('player');
    let filteredContainers = Array.from(ContainerRegistry.values())
        .filter(c => c.id !== player.container_backpack && c.id !== player.container_equipment && c.type !== 'npc_inventory')
        .filter(c => {
            const containerLocation = resolveContainerLocation(c.id);
            if (!containerLocation || !playerPhysicalLocation) return false;
            return checkDistance(playerPhysicalLocation, containerLocation);
        })
        .filter(c => getContainerItems(c).length > 0 || c.type === 'faction_vault' || c.owner_id === 'player');
        
    filteredContainers.sort((a, b) => {
        if (a.owner_id === 'player' && b.owner_id !== 'player') return -1;
        if (b.owner_id === 'player' && a.owner_id !== 'player') return 1;
        if (a.type === 'faction_vault' && b.type !== 'faction_vault') return -1;
        if (b.type === 'faction_vault' && a.type !== 'faction_vault') return 1;
        return 0;
    });

    const nearbyContainers = filteredContainers.slice(0, 30).map(c => ({
            id: c.id,
            type: c.type,
            locked: !!c.lock_data?.is_locked,
            owner: c.owner_id,
            location: resolveContainerLocation(c.id)?.region_id || null,
            items: (!c.lock_data?.is_locked && OwnershipService.canAccess('player', c.id, { allowLocked: true, ignoreDistance: false }))
                ? getContainerItems(c).map(id => {
                    const item = ItemRegistry.get(id);
                    if (!item) return null;
                    return {
                        instance_id: item.id,
                        prototype_id: item.prototype_id,
                        name: item.custom_props?.name || item.name || item.prototype_id,
                        quantity: item.stack_size,
                        flags: item.flags || {}
                    };
                }).filter(Boolean)
                : []
        }));

    const nearbyNpcs = Object.values(player.visibleEntities).filter(e => e.type === 'npc').map(npc => {
        const wNpc = World?.npcs[npc.aiIdentifier];
        return {
            id: npc.aiIdentifier,
            name: npc.name,
            inventory_id: wNpc?.inventory_id || null,
            gold: wNpc?.inventory_id ? getGoldAmountInContainer(wNpc.inventory_id) : (wNpc?.inventory?.gold || 0),
            wounds: wNpc?.wounds || []
        };
    });

    return `
{
  "player": {
    "id": "player", "name": "${player.name}", "gender": "${player.gender || 'not_specified'}", "race": "${player.race}", "class": "${player.class}", "level": ${player.stats.level},
    "location": "${player.location}", "hp": ${player.stats.hp}, "maxHp": ${player.stats.maxHp}, "gold": ${player.stats.gold},
    "backpack_id": "${player.container_backpack}", "equipment_id": "${player.container_equipment}",
    "eroticIntensityLevel": ${eroticIntensityLevel}, "eroticPreferences": ${JSON.stringify(eroticPreferences)}
  },
  "inventory_CARRYING_NOW": ${JSON.stringify(player.container_backpack ? getContainerItems(ContainerRegistry.get(player.container_backpack)).map(id => { let it = ItemRegistry.get(id); return it ? { instance_id: it.id, prototype_id: it.prototype_id, name: it.custom_props?.name || it.name || it.prototype_id, quantity: it.stack_size, container_id: it.container_id, slot_index: it.slot_index, flags: it.flags } : null; }).filter(Boolean) : [])},
  "equipment": ${JSON.stringify(player.container_equipment ? getContainerItems(ContainerRegistry.get(player.container_equipment)).map(id => { let it = ItemRegistry.get(id); return it ? { slot: it.slot_index, instance_id: it.id, prototype_id: it.prototype_id, name: it.custom_props?.name || it.name || it.prototype_id } : null; }).filter(Boolean) : [])},
  "nearby_containers": ${JSON.stringify(nearbyContainers)},
  "nearby_npcs": ${JSON.stringify(nearbyNpcs)},
  "quests": ${JSON.stringify(Object.values(player.quests || {}).filter(q => q.status === 'active'))},
  "gm_notes": ${JSON.stringify(player.gmNotes)}
}
${worldContextString}`;
}



async function ensureDirectoryHandleAndPermission() {
    if (window.electronAPI && window.electronAPI.isElectron) {
        return true;
    }
    // Р вҖқР В»РЎРҸ Р РҶР ВөР ВұР В° Р РҶР С•Р В·Р РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ false (Р С‘Р В»Р С‘ РЎРғРЎвҖҡР В°РЎРӮРЎС“РЎРӢ Р В»Р С•Р С–Р С‘Р С”РЎС“, Р ВөРЎРғР В»Р С‘ Р С•Р Р…Р В° РЎвҖҡР В°Р Сҳ Р С•РЎРғРЎвҖҡР В°Р В»Р В°РЎРғРЎРҠ)
    return false;
}





function updateReputationModal() {
    if (!player || !reputationModal) return;
    const modalTitle = document.querySelector('#reputation-modal h4');
    if (modalTitle) modalTitle.textContent = t('gameInterface.reputationModal.title', null, 'Р В Р ВөР С—РЎС“РЎвҖҡР В°РЎвҖ Р С‘РЎРҸ');

    const reputations = player.stats.reputation;
    const contentDiv = document.getElementById('reputation-modal-content');
    if (!contentDiv) return;

    contentDiv.innerHTML = ''; // Р СӣРЎвҖЎР С‘РЎвҖ°Р В°Р ВөР Сҳ РЎРғРЎвҖҡР В°РЎРӮР С•Р Вө РЎРғР С•Р Т‘Р ВөРЎРӮР В¶Р С‘Р СҳР С•Р Вө
    let htmlContent = '';

    const factionKeys = Object.keys(reputations).sort((a, b) => {
        if (a === 'global') return -1; // global Р РҶРЎРғР ВөР С–Р Т‘Р В° Р С—Р ВөРЎРӮР РҶР В°РЎРҸ
        if (b === 'global') return 1;
        return a.localeCompare(b);
    });

    for (const factionKey of factionKeys) {
        const value = reputations[factionKey];
        const factionName = player.factionData?.[factionKey] || factionKey;

        const minRep = -100;
        const maxRep = 100;
        const totalRange = maxRep - minRep;
        let markerPositionPercent = ((value - minRep) / totalRange) * 100;
        markerPositionPercent = Math.max(0, Math.min(100, markerPositionPercent));

        htmlContent += `
            <div class="faction-rep-row">
                <div class="faction-rep-label"><span>${factionName}</span> <span>${value}</span></div>
                <div class="faction-rep-bar-container">
                    <div class="reputation-marker-modal" style="left: ${markerPositionPercent}%;"></div>
                </div>
            </div>
        `;
    }

    contentDiv.innerHTML = sanitizeHTML(htmlContent);
    reputationModal.classList.add('visible');
}

function positionReputationModal(event) {
    if (!reputationModal || !reputationModal.classList.contains('visible')) return;

    const xOffset = 15;
    const yOffset = -10; // Р СҹР С•РЎРҸР РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ РЎвҖЎРЎС“РЎвҖҡРЎРҠ Р РҶРЎвҖ№РЎвӮ¬Р Вө Р С”РЎС“РЎРӮРЎРғР С•РЎРӮР В°

    let newX = event.clientX + xOffset;
    let newY = event.clientY + yOffset;

    const modalRect = reputationModal.getBoundingClientRect();
    const viewportWidth = window.innerWidth;
    const viewportHeight = window.innerHeight;

    // Р СҹРЎРӮР ВөР Т‘Р С•РЎвҖҡР РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р РҶРЎвҖ№РЎвҖҰР С•Р Т‘ Р В·Р В° Р С—РЎРӮР В°Р РҶРЎвҖ№Р в„– Р С”РЎРӮР В°Р в„– РЎРҢР С”РЎРӮР В°Р Р…Р В°
    if (newX + modalRect.width > viewportWidth - 10) {
        newX = event.clientX - modalRect.width - xOffset;
    }
    // Р СҹРЎРӮР ВөР Т‘Р С•РЎвҖҡР РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р РҶРЎвҖ№РЎвҖҰР С•Р Т‘ Р В·Р В° Р Р…Р С‘Р В¶Р Р…Р С‘Р в„– Р С”РЎРӮР В°Р в„–, РЎРғР Т‘Р РҶР С‘Р С–Р В°РЎРҸ Р РҶР РҶР ВөРЎРӮРЎвҖҰ
    if (newY + modalRect.height > viewportHeight - 10) {
        newY = viewportHeight - modalRect.height - 10;
    }
    // Р СҹРЎРӮР ВөР Т‘Р С•РЎвҖҡР РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р РҶРЎвҖ№РЎвҖҰР С•Р Т‘ Р В·Р В° Р В»Р ВөР РҶРЎвҖ№Р в„– Р С‘ Р РҶР ВөРЎРӮРЎвҖҰР Р…Р С‘Р в„– Р С”РЎРӮР В°РЎРҸ
    if (newX < 10) newX = 10;
    if (newY < 10) newY = 10;

    reputationModal.style.left = `${newX}px`;
    reputationModal.style.top = `${newY}px`;
}

function pruneGameLog() {
    const MAX_LOG_MESSAGES = 100; // Р ТҗРЎРӮР В°Р Р…Р С‘Р Сҳ Р РҶ DOM РЎвҖҡР С•Р В»РЎРҠР С”Р С• Р С—Р С•РЎРғР В»Р ВөР Т‘Р Р…Р С‘Р Вө 100 РЎРғР С•Р С•Р ВұРЎвҖ°Р ВөР Р…Р С‘Р в„–
    if (gameLog && gameLog.children.length > MAX_LOG_MESSAGES) {
        // Р РҲР Т‘Р В°Р В»РЎРҸР ВөР Сҳ РЎРғРЎвҖҡР В°РЎРӮРЎвҖ№Р Вө РЎРғР С•Р С•Р ВұРЎвҖ°Р ВөР Р…Р С‘РЎРҸ, Р С—Р С•Р С”Р В° Р С‘РЎвҖҰ Р Р…Р Вө Р С•РЎРғРЎвҖҡР В°Р Р…Р ВөРЎвҖҡРЎРғРЎРҸ Р Р…РЎС“Р В¶Р Р…Р С•Р Вө Р С”Р С•Р В»Р С‘РЎвҖЎР ВөРЎРғРЎвҖҡР РҶР С•
        while (gameLog.children.length > MAX_LOG_MESSAGES) {
            gameLog.removeChild(gameLog.firstChild);
        }
    }
}










// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р Т‘Р В»РЎРҸ localStorage (Fallback) ---




// --- Р СӣРЎвҖҡР С•Р ВұРЎРӮР В°Р В¶Р ВөР Р…Р С‘Р Вө РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р Р…Р С•Р в„– Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘Р С‘ РЎвҖЎР В°РЎвҖҡР В° ---
function displaySavedChatHistory() {
    if (!gameLog) return;
    gameLog.innerHTML = '';
    if (player && player.gameLogHistory && player.gameLogHistory.length > 0) {
        player.gameLogHistory.forEach(entry => {
            addLogMessage(entry.message, entry.type, true, entry.imagePrompt, entry.savedImageBase64);
        });
    } else if (conversationHistory && conversationHistory.length > 0) {
        conversationHistory.forEach(msg => {
            if (msg.parts && msg.parts[0].text) {
                addLogMessage(msg.parts[0].text, msg.role === 'model' ? 'gm-message' : 'user-message', true);
            }
        });
    }
    if (calculationLog) {
        calculationLog.innerHTML = `<p class="system-message" data-i18n="gameInterface.calcLogPanel.empty">${t('gameInterface.calcLogPanel.empty')}</p>`;
        if (player && player.calcLogHistory) {
            player.calcLogHistory.forEach(msg => addCalculationMessage(msg, "calc-info", true));
        }
    }
    gameLog.scrollTo({ top: gameLog.scrollHeight, behavior: 'auto' });
}



// --- Р СңР СӣР вҖҷР С’Р РҮ Р РҺР ВҳР РҺР СһР вҖўР СҡР С’ Р СӣР вҖҳР В Р С’Р вҖҳР СӣР СһР СҷР Вҳ Р РҺР СһР С’Р СһР РҲР РҺ-Р ВӯР ВӨР ВӨР вҖўР СҷР СһР СӣР вҖҷ ---

/**
 * Р вҖңР В»Р В°Р РҶР Р…Р В°РЎРҸ РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРҸ, Р С•Р ВұРЎРӮР В°Р ВұР В°РЎвҖҡРЎвҖ№Р РҶР В°РЎРӢРЎвҖ°Р В°РЎРҸ Р РҶРЎРғР Вө Р В°Р С”РЎвҖҡР С‘Р РҶР Р…РЎвҖ№Р Вө РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ-РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡРЎвҖ№ Р Т‘Р В»РЎРҸ РЎРғРЎС“РЎвҖ°Р Р…Р С•РЎРғРЎвҖҡР С‘ (Р С‘Р С–РЎРӮР С•Р С”Р В°).
 * Р вҖҷРЎвҖ№Р В·РЎвҖ№Р РҶР В°Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶ Р Р…Р В°РЎвҖЎР В°Р В»Р Вө Р С”Р В°Р В¶Р Т‘Р С•Р С–Р С• РЎвҖҰР С•Р Т‘Р В°.
 * @returns {Array<string>} Р СҡР В°РЎРғРЎРғР С‘Р РҶ РЎРғР С•Р С•Р ВұРЎвҖ°Р ВөР Р…Р С‘Р в„– Р Т‘Р В»РЎРҸ Р С‘Р С–РЎРӮР С•Р РҶР С•Р С–Р С• Р В»Р С•Р С–Р В°.
 */
function processStatusEffects() {
    if (!player || !player.statusEffects) {
        return [];
    }

    const logMessages = [];
    const effectsToRemove = [];
    const expiredEffectNames = [];

    for (const effectId in player.statusEffects) {
        const effect = player.statusEffects[effectId];

        // --- Р СңР СӣР вҖҷР С’Р РҮ Р вҖәР СӣР вҖңР ВҳР СҷР С’ Р СҹР В Р СӣР вҖҷР вҖўР В Р СҷР Вҳ Р вҖқР вҖәР ВҳР СһР вҖўР вҖәР В¬Р СңР СӣР РҺР СһР Вҳ ---
        // Р РҺР Р…Р В°РЎвҖЎР В°Р В»Р В° Р С—РЎРӮР С•Р РҶР ВөРЎРӮРЎРҸР ВөР Сҳ, Р Р…Р Вө Р С‘РЎРғРЎвҖҡР ВөР С” Р В»Р С‘ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡ Р РҶ Р СңР С’Р В§Р С’Р вҖәР вҖў РЎРҢРЎвҖҡР С•Р С–Р С• РЎвҖҰР С•Р Т‘Р В°.
        if (effect.duration <= 0) {
            effectsToRemove.push(effectId);
            expiredEffectNames.push(effect.name);
            continue; // Р СҹР ВөРЎРӮР ВөРЎвҖҰР С•Р Т‘Р С‘Р Сҳ Р С” РЎРғР В»Р ВөР Т‘РЎС“РЎРӢРЎвҖ°Р ВөР СҳРЎС“ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡРЎС“, Р Р…Р Вө Р С•Р ВұРЎРӮР В°Р ВұР В°РЎвҖҡРЎвҖ№Р РҶР В°РЎРҸ Р ВөР С–Р С• РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮРЎвҖ№ Р РҶ РЎРҢРЎвҖҡР С•Р Сҳ РЎвҖҰР С•Р Т‘РЎС“
        }

        // 1. Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡР С”Р В° РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮР С•Р РҶ Р Т‘Р В»РЎРҸ Р С’Р СҷР СһР ВҳР вҖҷР СңР В«Р Тҗ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР С•Р РҶ
        if (effect.effects && Array.isArray(effect.effects)) {
            effect.effects.forEach(subEffect => {
                if (subEffect.trigger && subEffect.action) {
                    if (checkEffectTrigger(effect, subEffect.trigger)) {
                        const message = applyEffectAction(player, effect, subEffect.action);
                        if (message) {
                            logMessages.push(message);
                        }
                    }
                }
            });
        }

        // 2. Р РҲР СҳР ВөР Р…РЎРҠРЎвӮ¬Р ВөР Р…Р С‘Р Вө Р Т‘Р В»Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…Р С•РЎРғРЎвҖҡР С‘ Р вҖҷ Р СҷР СӣР СңР ВҰР вҖў Р С•Р ВұРЎРӮР В°Р ВұР С•РЎвҖҡР С”Р С‘ РЎвҖҰР С•Р Т‘Р В°.
        // Р СһР ВөР С—Р ВөРЎРӮРЎРҠ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡ РЎРғ duration: 1 Р ВұРЎС“Р Т‘Р ВөРЎвҖҡ Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С•Р РҶР В°РЎвҖҡРЎРҠ РЎРҢРЎвҖҡР С•РЎвҖҡ РЎвҖҰР С•Р Т‘ Р С‘ Р С‘РЎРғРЎвҖҡР ВөРЎвҖЎР ВөРЎвҖҡ Р С” Р Р…Р В°РЎвҖЎР В°Р В»РЎС“ РЎРғР В»Р ВөР Т‘РЎС“РЎРӢРЎвҖ°Р ВөР С–Р С•.
        effect.duration--;
    }

    // 4. Р РҲР Т‘Р В°Р В»Р ВөР Р…Р С‘Р Вө Р С‘РЎРғРЎвҖҡР ВөР С”РЎвӮ¬Р С‘РЎвҖҰ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР С•Р РҶ Р С‘ Р В·Р В°Р С—РЎС“РЎРғР С” Р С‘РЎвҖҰ on_remove Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘Р в„–
    if (effectsToRemove.length > 0) {
        effectsToRemove.forEach(idToRemove => {
            const removedEffect = player.statusEffects[idToRemove];
            if (removedEffect) {
                let specificActionOccurred = false;

                // Р вҖ”Р В°Р С—РЎС“РЎРғР С”Р В°Р ВөР Сҳ on_remove Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ
                if (removedEffect.effects && Array.isArray(removedEffect.effects)) {
                    removedEffect.effects.forEach(subEffect => {
                        if (subEffect.trigger?.type === 'on_remove') {
                            const message = applyEffectAction(player, removedEffect, subEffect.action);
                            if (message) {
                                logMessages.push(message);
                                specificActionOccurred = true;
                            }
                        }
                    });
                }

                // Р СҹРЎРӮР С‘Р Р…РЎС“Р Т‘Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…Р С•Р Вө Р РҶР С•РЎРғРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…Р С‘Р Вө РЎРғРЎвҖҡР В°РЎвҖҡР С•Р РҶ
                if (removedEffect.originalValues && typeof removedEffect.originalValues === 'object') {
                    for (const statToRestore in removedEffect.originalValues) {
                        const restoreAction = { type: 'restore_stat', stat: statToRestore };
                        const message = applyEffectAction(player, removedEffect, restoreAction);
                        if (message) {
                            logMessages.push(message);
                            specificActionOccurred = true;
                            console.warn(`Р СҹРЎРӮР С‘Р Р…РЎС“Р Т‘Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…Р С•Р Вө Р РҶР С•РЎРғРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…Р С‘Р Вө РЎРғРЎвҖҡР В°РЎвҖҡР В° '${statToRestore}' Р Т‘Р В»РЎРҸ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР В° '${removedEffect.name}', РЎвҖҡ.Р С”. GM Р Р…Р Вө Р С—РЎРӮР ВөР Т‘Р С•РЎРғРЎвҖҡР В°Р РҶР С‘Р В» РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮ on_remove.`);
                        }
                    }
                }

                delete player.statusEffects[idToRemove];

                if (!specificActionOccurred) {
                    logMessages.push(t('gameInterface.commandFeedback.statusEffectRemoved', { effectName: removedEffect.name }));
                }
            }
        });
    }

    // 5. Р СӣР ВұР Р…Р С•Р РҶР В»РЎРҸР ВөР Сҳ UI, Р ВөРЎРғР В»Р С‘ РЎвҖЎРЎвҖҡР С•-РЎвҖҡР С• Р С‘Р В·Р СҳР ВөР Р…Р С‘Р В»Р С•РЎРғРЎРҠ
    if (logMessages.length > 0) {
        updateStatusEffectsDisplay();
        updateCharacterSheet();
    }

    // Р вҖҷР С•Р В·Р РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р С‘Р СҳР ВөР Р…Р В° Р С‘РЎРғРЎвҖҡР ВөР С”РЎвӮ¬Р С‘РЎвҖҰ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР С•Р РҶ Р Т‘Р В»РЎРҸ Р С—Р ВөРЎРӮР ВөР Т‘Р В°РЎвҖЎР С‘ GM
    player.expiredEffectsForGM = expiredEffectNames;
    return logMessages;
}

/**
 * Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҸР ВөРЎвҖҡ, Р Т‘Р С•Р В»Р В¶Р ВөР Р… Р В»Р С‘ РЎРғРЎРӮР В°Р ВұР С•РЎвҖҡР В°РЎвҖҡРЎРҠ РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР В° Р РҶ РЎвҖҡР ВөР С”РЎС“РЎвҖ°Р ВөР Сҳ РЎвҖҰР С•Р Т‘РЎС“.
 * @param {object} effect - Р СҹР С•Р В»Р Р…РЎвҖ№Р в„– Р С•Р ВұРЎРүР ВөР С”РЎвҖҡ РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ-РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР В°.
 * @param {object} trigger - Р СӣР ВұРЎРүР ВөР С”РЎвҖҡ РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮР В°.
 * @returns {boolean} - true, Р ВөРЎРғР В»Р С‘ РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮ РЎРғРЎРӮР В°Р ВұР С•РЎвҖҡР В°Р В».
 */
function checkEffectTrigger(effect, trigger) {
    if (trigger.type === 'on_turn_start') {
        const interval = trigger.interval || 1;
        const turnsPassed = player.stats.turnCount - effect.appliedTurn;
        // Р РҺРЎРӮР В°Р ВұР В°РЎвҖҡРЎвҖ№Р РҶР В°Р ВөРЎвҖҡ Р РҶ 0-Р в„– РЎвҖҰР С•Р Т‘ (РЎРғРЎРӮР В°Р В·РЎС“ Р С—РЎРӮР С‘ Р С—РЎРӮР С‘Р СҳР ВөР Р…Р ВөР Р…Р С‘Р С‘) Р С‘ Р С”Р В°Р В¶Р Т‘РЎвҖ№Р в„– 'interval' РЎвҖҰР С•Р Т‘ Р С—Р С•РЎРғР В»Р Вө
        return turnsPassed >= 0 && turnsPassed % interval === 0;
    }
    // Р вҖ”Р Т‘Р ВөРЎРғРЎРҠ Р СҳР С•Р В¶Р Р…Р С• Р Т‘Р С•Р ВұР В°Р РҶР С‘РЎвҖҡРЎРҠ Р Т‘РЎРӮРЎС“Р С–Р С‘Р Вө РЎвҖҡР С‘Р С—РЎвҖ№ РЎвҖҡРЎРӮР С‘Р С–Р С–Р ВөРЎРӮР С•Р РҶ: on_damage_taken, on_attack, Р С‘ РЎвҖҡ.Р Т‘.
    return false;
}

/**
 * Р СҹРЎРӮР С‘Р СҳР ВөР Р…РЎРҸР ВөРЎвҖҡ Р С”Р С•Р Р…Р С”РЎРӮР ВөРЎвҖҡР Р…Р С•Р Вө Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘Р Вө РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР В° Р С” РЎРғРЎС“РЎвҖ°Р Р…Р С•РЎРғРЎвҖҡР С‘.
 * @param {object} entity - Р РҺРЎС“РЎвҖ°Р Р…Р С•РЎРғРЎвҖҡРЎРҠ, Р Р…Р В° Р С”Р С•РЎвҖҡР С•РЎРӮРЎС“РЎРӢ Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶРЎС“Р ВөРЎвҖҡ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡ (Р С—Р С•Р С”Р В° РЎвҖҡР С•Р В»РЎРҠР С”Р С• player).
 * @param {object} effect - Р В Р С•Р Т‘Р С‘РЎвҖҡР ВөР В»РЎРҠРЎРғР С”Р С‘Р в„– РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ-РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡ (Р Т‘Р В»РЎРҸ РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р С‘РЎРҸ originalValues).
 * @param {object} action - Р СӣР ВұРЎРүР ВөР С”РЎвҖҡ Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ.
 * @returns {string|null} Р РҺР С•Р С•Р ВұРЎвҖ°Р ВөР Р…Р С‘Р Вө Р Т‘Р В»РЎРҸ Р В»Р С•Р С–Р В° Р С‘Р В»Р С‘ null.
 */
function applyEffectAction(entity, effect, action) {
    let message = null;
    try {
        switch (action.type) {
            case 'modify_stat': {
                const { stat, change } = action;
                const changeValue = parseInt(change, 10);
                if (!entity.stats || isNaN(changeValue)) break;

                const oldValue = entity.stats[stat] || 0;
                entity.stats[stat] = oldValue + changeValue;

                // Р СӣР С–РЎРӮР В°Р Р…Р С‘РЎвҖЎР ВөР Р…Р С‘РЎРҸ
                if (stat === 'hp') {
                    entity.stats.hp = Math.max(0, Math.min(entity.stats.hp, entity.stats.maxHp));
                }
                if (stat === 'mana' && entity.class === 'mage') {
                    entity.stats.mana = Math.max(0, Math.min(entity.stats.mana, entity.stats.maxMana));
                }

                const statName = t(`gameInterface.characterPanel.${stat}`, null, stat);
                const changeText = changeValue > 0 ? `+${changeValue}` : changeValue;
                message = t('gameInterface.log.effectModifyStat', { effectName: effect.name, statName: statName, change: changeText });
                break;
            }
            case 'set_stat': {
                const { stat, value } = action;
                const setValue = parseInt(value, 10);
                if (!entity.stats || isNaN(setValue)) break;

                // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ Р С•РЎРӮР С‘Р С–Р С‘Р Р…Р В°Р В»РЎРҠР Р…Р С•Р Вө Р В·Р Р…Р В°РЎвҖЎР ВөР Р…Р С‘Р Вө, Р ВөРЎРғР В»Р С‘ Р С•Р Р…Р С• Р ВөРЎвҖ°Р Вө Р Р…Р Вө РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р С•
                if (!effect.originalValues) {
                    effect.originalValues = {};
                }
                if (effect.originalValues[stat] === undefined) {
                    effect.originalValues[stat] = entity.stats[stat] || 0;
                }

                entity.stats[stat] = setValue;
                const statName = t(`gameInterface.characterPanel.${stat}`, null, stat);
                message = t('gameInterface.log.effectSetStat', { effectName: effect.name, statName: statName, value: setValue });
                break;
            }
            case 'restore_stat': {
                const { stat } = action;
                if (effect.originalValues && effect.originalValues[stat] !== undefined) {
                    entity.stats[stat] = effect.originalValues[stat];
                    const statName = t(`gameInterface.characterPanel.${stat}`, null, stat);
                    message = t('gameInterface.log.effectRestoreStat', { effectName: effect.name, statName: statName, value: entity.stats[stat] });
                    delete effect.originalValues[stat]; // Р СӣРЎвҖЎР С‘РЎвҖ°Р В°Р ВөР Сҳ РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р Р…Р С•Р Вө Р В·Р Р…Р В°РЎвҖЎР ВөР Р…Р С‘Р Вө
                }
                break;
            }
        }
    } catch (e) {
        console.error("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С—РЎРӮР С‘Р СҳР ВөР Р…Р ВөР Р…Р С‘РЎРҸ Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР В°:", e, action);
    }
    return message;
}

// --- Р РҺР С‘РЎРғРЎвҖҡР ВөР СҳР В° Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р С‘Р в„– / Р вҖ”Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ (Р СӣРЎРғР Р…Р С•Р РҶР Р…РЎвҖ№Р Вө РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘) ---


/**
 * Р вҖ”Р В°Р С–РЎРӮРЎС“Р В¶Р В°Р ВөРЎвҖҡ Р С‘Р С–РЎРӮРЎС“ Р С‘Р В· РЎС“Р С”Р В°Р В·Р В°Р Р…Р Р…Р С•Р С–Р С• РЎРғР В»Р С•РЎвҖҡР В°.
 * Р СҹРЎРӮР С‘Р С•РЎРӮР С‘РЎвҖҡР ВөРЎвҖҡ Р С•РЎвҖҡР Т‘Р В°Р ВөРЎвҖҡРЎРғРЎРҸ File System Access API, Р ВөРЎРғР В»Р С‘ Р Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р Р…Р С•, Р С‘Р Р…Р В°РЎвҖЎР Вө Р С‘РЎРғР С—Р С•Р В»РЎРҠР В·РЎС“Р ВөРЎвҖҡРЎРғРЎРҸ localStorage.
 * Р СӣР ВұР ВөРЎРғР С—Р ВөРЎвҖЎР С‘Р РҶР В°Р ВөРЎвҖҡ Р С•Р ВұРЎРӮР В°РЎвҖҡР Р…РЎС“РЎРӢ РЎРғР С•Р РҶР СҳР ВөРЎРғРЎвҖҡР С‘Р СҳР С•РЎРғРЎвҖҡРЎРҠ РЎРғР С• РЎРғРЎвҖҡР В°РЎРӮРЎвҖ№Р СҳР С‘ РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р С‘РЎРҸР СҳР С‘.
 * @param {string} slotType - 'manual' Р С‘Р В»Р С‘ 'auto'.
 * @param {number} slotId - ID РЎРғР В»Р С•РЎвҖҡР В°.
 */











// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р РҲР С—РЎРӮР В°Р РҶР В»Р ВөР Р…Р С‘РЎРҸ Р ВӯР С”РЎРӮР В°Р Р…Р В°Р СҳР С‘ ---
function setActiveScreen(screenId) {
    const overlays = [
        document.getElementById('custom-alert-modal'),
        document.getElementById('save-slot-modal'),
        document.getElementById('custom-confirm-modal'),
        document.getElementById('menu-overlay'),
        document.getElementById('loading-overlay'),
        document.getElementById('ai-error-modal')
    ];
    overlays.forEach(el => { if (el) { el.classList.remove('visible'); el.style.display = 'none'; } });

    const allScreens = [mainMenu, settingsMenu, characterCreationScreen, loadGameScreen, helpScreen, narratorSelectionScreen, worldSetupScreen, gameInterface, document.getElementById('mods-menu')];
    const currentActive = document.querySelector('.menu-screen.active-screen, .main-menu-screen.active-screen, .game-container.active-screen');
    const targetScreen = document.getElementById(screenId);

    const executeSwap = () => {
        allScreens.forEach(screen => {
            if (screen) {
                screen.classList.remove('active-screen');
                if (screen.id !== screenId) screen.style.display = 'none';
            }
        });
        if (targetScreen) {
            targetScreen.style.display = 'flex';
            requestAnimationFrame(() => {
                targetScreen.classList.add('active-screen');
                if (screenId === 'character-creation-screen') {
                    const nameInput = document.getElementById('char-name-input');
                    if (nameInput) nameInput.focus();
                }
            });
        }
    };

    // Р С’Р Р…Р С‘Р СҳР В°РЎвҖ Р С‘РЎРҸ РЎС“РЎвҖҰР С•Р Т‘Р В° Р С‘Р В· Р С–Р В»Р В°Р РҶР Р…Р С•Р С–Р С• Р СҳР ВөР Р…РЎРӢ
    if (currentActive && currentActive.id === 'main-menu' && screenId !== 'main-menu') {
        const leftBlock = currentActive.querySelector('.mm-left-block');
        if (leftBlock) leftBlock.style.animation = 'slideOutLeft 0.3s forwards cubic-bezier(0.7, 0, 0.3, 1)';
        setTimeout(executeSwap, 250);
    } 
    // Р С’Р Р…Р С‘Р СҳР В°РЎвҖ Р С‘РЎРҸ Р РҶР С•Р В·Р РҶРЎРӮР В°РЎвҖҡР В° Р РҶ Р С–Р В»Р В°Р РҶР Р…Р С•Р Вө Р СҳР ВөР Р…РЎРӢ
    else if (screenId === 'main-menu') {
        if (currentActive) currentActive.classList.remove('active-screen'); // Р СңР В°РЎвҖЎР С‘Р Р…Р В°Р ВөР Сҳ РЎвҖһР ВөР в„–Р Т‘-Р В°РЎС“РЎвҖҡ РЎвҖҡР ВөР С”РЎС“РЎвҖ°Р ВөР С–Р С•
        setTimeout(() => {
            executeSwap();
            const leftBlock = targetScreen.querySelector('.mm-left-block');
            if (leftBlock) leftBlock.style.animation = 'slideInLeft 0.4s forwards cubic-bezier(0.2, 0.8, 0.2, 1)';
        }, 200);
    } 
    // Р СӣР ВұРЎвҖ№РЎвҖЎР Р…РЎвҖ№Р в„– Р С—Р ВөРЎРӮР ВөРЎвҖҰР С•Р Т‘
    else {
        executeSwap();
    }
}

// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р Т‘Р В»РЎРҸ Р РҶР С”Р В»Р В°Р Т‘Р С•Р С” Р СҹР С•Р СҳР С•РЎвҖ°Р С‘ ---
window.openHelpTab = function(evt, tabName) {
    const tabContents = document.querySelectorAll('.help-tab-content');
    tabContents.forEach(content => content.classList.remove('active'));

    const tabBtns = document.querySelectorAll('.help-tab-btn');
    tabBtns.forEach(btn => btn.classList.remove('active'));

    const targetTab = document.getElementById(tabName);
    if (targetTab) targetTab.classList.add('active');
    
    if (evt && evt.currentTarget) evt.currentTarget.classList.add('active');
};

window.openHelpSubTab = function(evt, tabName) {
    const container = evt.currentTarget.closest('.help-tab-content');
    const tabContents = container.querySelectorAll('.sub-tab-content');
    tabContents.forEach(content => {
        content.classList.remove('active');
    });

    const tabBtns = container.querySelectorAll('.sub-tab-btn');
    tabBtns.forEach(btn => btn.classList.remove('active'));

    const targetTab = document.getElementById(tabName);
    if (targetTab) {
        targetTab.classList.add('active');
    }
    
    if (evt && evt.currentTarget) evt.currentTarget.classList.add('active');
};

// --- CSP-compliant event delegation (replaces inline onclick/onmouseover/onmouseout handlers) ---
document.addEventListener('DOMContentLoaded', function() {
    // Help tab buttons (data-help-tab attribute)
    document.querySelectorAll('.help-tab-btn[data-help-tab]').forEach(btn => {
        btn.addEventListener('click', function(evt) {
            const tabName = this.getAttribute('data-help-tab');
            if (tabName) window.openHelpTab(evt, tabName);
        });
    });

    // Help sub-tab buttons (data-help-subtab attribute)
    document.querySelectorAll('.sub-tab-btn[data-help-subtab]').forEach(btn => {
        btn.addEventListener('click', function(evt) {
            const tabName = this.getAttribute('data-help-subtab');
            if (tabName) window.openHelpSubTab(evt, tabName);
        });
    });

    // Close map modal button (replaces onmouseover/onmouseout inline handlers)
    const closeMapBtn = document.getElementById('close-map-modal-btn');
    if (closeMapBtn) {
        closeMapBtn.addEventListener('mouseenter', function() { this.style.color = '#e74c3c'; });
        closeMapBtn.addEventListener('mouseleave', function() { this.style.color = '#7f8c8d'; });
    }

    // Close examine modal button (replaces inline onclick handler)
    const closeExamineBtn = document.getElementById('close-examine-modal-btn');
    if (closeExamineBtn) {
        closeExamineBtn.addEventListener('click', function() {
            const modal = document.getElementById('item-examine-modal');
            if (modal) {
                modal.classList.remove('visible');
                setTimeout(() => { modal.style.display = 'none'; }, 300);
            }
        });
    }
});

// --- Custom Alert Modal ---
function showCustomAlert(message) {
    const modal = document.getElementById('custom-alert-modal');
    const messageP = document.getElementById('custom-alert-message');
    const closeBtn = document.getElementById('custom-alert-close');

    if (!modal || !messageP || !closeBtn) {
        alert(message);
        return;
    }

    messageP.textContent = message;
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('visible'), 10);

    const closeAlert = () => {
        modal.classList.remove('visible');
        setTimeout(() => modal.style.display = 'none', 300);
    };

    closeBtn.onclick = closeAlert;
    modal.addEventListener('click', (event) => {
        if (event.target === modal) {
            closeAlert();
        }
    });
}

function showAiErrorModal(errorText, isInitial, onRetry, customTitle = null, customDesc = null) {
    if (!aiErrorModal) return;

    const titleH3 = aiErrorModal.querySelector('h3');
    if (customTitle && titleH3) {
        titleH3.innerHTML = `<i class="fas fa-exclamation-triangle"></i> ${customTitle}`;
    } else if (titleH3) {
        titleH3.innerHTML = `<i class="fas fa-exclamation-triangle"></i> Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р СҡР В°РЎРғРЎвҖҡР ВөРЎРӮР В° Р ВҳР С–РЎРӮРЎвҖ№`;
    }

    let mainText = "";
    let detailsText = errorText;

    // Р В Р В°Р В·Р Т‘Р ВөР В»РЎРҸР ВөР Сҳ РЎвҖЎР ВөР В»Р С•Р РҶР ВөР С”Р С•РЎвҖЎР С‘РЎвҖҡР В°Р ВөР СҳРЎС“РЎРӢ РЎвҖЎР В°РЎРғРЎвҖҡРЎРҠ Р С‘ РЎвҖҡР ВөРЎвҖҰР Р…Р С‘РЎвҖЎР ВөРЎРғР С”Р С‘Р Вө Р Т‘Р ВөРЎвҖҡР В°Р В»Р С‘
    if (typeof errorText === 'string' && errorText.includes('\n\n[Р СҷР С•Р Т‘:')) {
        let parts = errorText.split('\n\n[Р СҷР С•Р Т‘:');
        mainText = parts[0];
        detailsText = '[Р СҷР С•Р Т‘:' + parts[1];
    }

    if (customDesc) {
        aiErrorMessage.textContent = customDesc;
        aiErrorCancelBtn.textContent = "Р СӣРЎвҖҡР СҳР ВөР Р…Р В°";
    } else if (mainText) {
        // FIX: Р вҖҷРЎвҖ№Р РҶР С•Р Т‘Р С‘Р Сҳ Р С—Р С•Р Р…РЎРҸРЎвҖҡР Р…РЎС“РЎРӢ Р С—РЎРӮР С‘РЎвҖЎР С‘Р Р…РЎС“ Р С•РЎвӮ¬Р С‘Р ВұР С”Р С‘ Р С—РЎРӮРЎРҸР СҳР С• Р РҶ РЎвҖ Р ВөР Р…РЎвҖҡРЎРӮ Р С•Р С”Р Р…Р В°
        aiErrorMessage.textContent = mainText;
        aiErrorCancelBtn.textContent = isInitial ? "Р вҖҷ Р С–Р В»Р В°Р РҶР Р…Р С•Р Вө Р СҳР ВөР Р…РЎРӢ" : "Р СӣРЎвҖҡР СҳР ВөР Р…Р В° (Р СӣРЎРғРЎвҖҡР В°РЎвҖҡРЎРҠРЎРғРЎРҸ Р РҶ Р С‘Р С–РЎРӮР Вө)";
    } else if (isInitial) {
        aiErrorMessage.textContent = "Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ РЎРғР С–Р ВөР Р…Р ВөРЎРӮР С‘РЎРӮР С•Р РҶР В°РЎвҖҡРЎРҠ Р СҳР С‘РЎРӮ. Р СҡР В°Р С–Р С‘РЎвҖЎР ВөРЎРғР С”Р С‘Р Вө Р С—Р С•РЎвҖҡР С•Р С”Р С‘ Р С—РЎРӮР ВөРЎРӮР РҶР В°Р В»Р С‘РЎРғРЎРҠ.";
        aiErrorCancelBtn.textContent = "Р вҖҷ Р С–Р В»Р В°Р РҶР Р…Р С•Р Вө Р СҳР ВөР Р…РЎРӢ";
    } else {
        aiErrorMessage.textContent = "Р СҡР В°РЎРғРЎвҖҡР ВөРЎРӮ Р ВҳР С–РЎРӮРЎвҖ№ Р С—Р С•РЎвҖҡР ВөРЎРӮРЎРҸР В» Р Р…Р С‘РЎвҖҡРЎРҠ Р С—Р С•Р РҶР ВөРЎРғРЎвҖҡР РҶР С•Р РҶР В°Р Р…Р С‘РЎРҸ. Р СҹРЎРӮР С•Р С‘Р В·Р С•РЎвӮ¬Р В»Р В° Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘.";
        aiErrorCancelBtn.textContent = "Р СӣРЎвҖҡР СҳР ВөР Р…Р В° (Р СӣРЎРғРЎвҖҡР В°РЎвҖҡРЎРҠРЎРғРЎРҸ Р РҶ Р С‘Р С–РЎРӮР Вө)";
    }

    aiErrorDetailsContent.textContent = detailsText;
    aiErrorDetailsContent.style.display = 'none';
    aiErrorDetailsToggle.textContent = "Р СҹР С•Р С”Р В°Р В·Р В°РЎвҖҡРЎРҠ Р Т‘Р ВөРЎвҖҡР В°Р В»Р С‘ Р С•РЎвӮ¬Р С‘Р ВұР С”Р С‘";

    aiErrorModal.style.display = 'flex';
    setTimeout(() => aiErrorModal.classList.add('visible'), 10);

    const isRateLimitOrUnavailable = typeof errorText === 'string' && (errorText.includes('429') || errorText.includes('503'));
    if (isRateLimitOrUnavailable && !isInitial) {
        aiErrorRetryBtn.textContent = "Р РҺР СҳР ВөР Р…Р С‘РЎвҖҡРЎРҠ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ (Fallback) Р С‘ Р С—Р С•Р РҶРЎвҖҡР С•РЎРӮР С‘РЎвҖҡРЎРҠ";
        aiErrorRetryBtn.onclick = () => {
            closeAiErrorModal();
            // Fallback Р Р…Р В° РЎРғРЎвҖҡР В°Р ВұР С‘Р В»РЎРҠР Р…РЎС“РЎРӢ Р ВұР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…РЎС“РЎРӢ/Р Т‘Р ВөРЎвӮ¬Р ВөР РҶРЎС“РЎРӢ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ
            if (currentApiProvider === 'openrouter') {
                openrouterModelId = 'google/gemini-2.0-flash-lite-preview-02-05:free';
                localStorage.setItem('openrouterModelId', openrouterModelId);
            } else if (currentApiProvider === 'gemini') {
                geminiModelId = 'gemini-2.0-flash-lite';
                localStorage.setItem('geminiModelId', geminiModelId);
            }
            addLogMessage("РІСҷВ РҝС‘РҸ Р СҡР С•Р Т‘Р ВөР В»РЎРҠ Р В°Р РҶРЎвҖҡР С•Р СҳР В°РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘ Р С‘Р В·Р СҳР ВөР Р…Р ВөР Р…Р В° Р Р…Р В° РЎРӮР ВөР В·Р ВөРЎРӮР РҶР Р…РЎС“РЎРӢ Р С‘Р В·-Р В·Р В° Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р Р…Р С•РЎРғРЎвҖҡР С‘ РЎРғР ВөРЎРӮР РҶР ВөРЎРӮР В°.", "system-message");
            if (onRetry) onRetry();
        };
    } else {
        aiErrorRetryBtn.textContent = "Р СҹР С•Р РҶРЎвҖҡР С•РЎРӮР С‘РЎвҖҡРЎРҠ Р В·Р В°Р С—РЎРӮР С•РЎРғ";
        aiErrorRetryBtn.onclick = () => {
            closeAiErrorModal();
            if (isInitial) {
                // Р СҹР С•Р В»Р Р…РЎвҖ№Р в„– РЎРғР ВұРЎРӮР С•РЎРғ Р С” РЎРғР С•РЎРғРЎвҖҡР С•РЎРҸР Р…Р С‘РЎРӢ Р Т‘Р С• РЎРғРЎвҖҡР В°РЎРӮРЎвҖҡР В°
                if (player) exitToMainMenu();
                startNewGameSetup(); // Р СҹР ВөРЎРӮР ВөР В·Р В°Р С—РЎС“РЎРғР С” РЎРғ Р Р…РЎС“Р В»РЎРҸ
            } else {
                if (onRetry) onRetry();
            }
        };
    }

    aiErrorCancelBtn.onclick = () => {
        closeAiErrorModal();
        if (isInitial) {
            exitToMainMenu();
        } else {
            isWaitingForAI = false;
            
            // FIX: Р вҖңР В»РЎС“Р ВұР С•Р С”Р В°РЎРҸ Р С•РЎвҖЎР С‘РЎРғРЎвҖҡР С”Р В° РЎРғР С•РЎРғРЎвҖҡР С•РЎРҸР Р…Р С‘Р в„– Р С—РЎС“РЎвҖҡР ВөРЎвӮ¬Р ВөРЎРғРЎвҖҡР РҶР С‘РЎРҸ Р Т‘Р В»РЎРҸ РЎРӮР В°Р В·Р ВұР В»Р С•Р С”Р С‘РЎРӮР С•Р РҶР С”Р С‘ UI
            if (player && player.travel && player.travel.active) {
                player.travel.paused = true;
                player.travel.pauseReason = "api_error";
                player.travel.currentEvents = null; // Р РҲР Т‘Р В°Р В»РЎРҸР ВөР Сҳ Р В·Р В°Р РҶР С‘РЎРғРЎвӮ¬Р С‘Р Вө РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ, Р ВұР В»Р С•Р С”Р С‘РЎРӮРЎС“РЎРӢРЎвҖ°Р С‘Р Вө Р С‘Р Р…Р С—РЎС“РЎвҖҡ
                player.travel.interactTarget = null;
            }
            if (player && player.currentJourney) {
                player.currentJourney.isPausedForCheck = false;
            }

            const suggestedContainer = document.getElementById('suggested-actions-container');
            if (suggestedContainer) {
                suggestedContainer.innerHTML = '';
                suggestedContainer.style.display = 'none';
            }

            if (userInput) {
                userInput.disabled = false;
                // Р вҖҷР С•РЎРғРЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөР Сҳ РЎвҖҡР ВөР С”РЎРғРЎвҖҡ Р С‘Р С–РЎРӮР С•Р С”Р В°, Р РҶРЎвҖ№РЎРӮР ВөР В·Р В°РЎРҸ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳР Р…РЎвҖ№Р Вө РЎвҖҡРЎРҢР С–Р С‘ Р С”РЎС“Р ВұР С‘Р С”Р С•Р РҶ
                if (lastUserMessageForRetry && !lastUserMessageForRetry.includes("[SYSTEM:")) {
                    userInput.value = lastUserMessageForRetry.replace(/\[ROLL_RESULT:.*?\]/gi, '').trim();
                }
                userInput.focus();
            }
            if (sendButton) sendButton.disabled = false;
            
            updateCharacterSheet(); // Р СҹРЎРӮР С‘Р Р…РЎС“Р Т‘Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…Р С• Р С—Р ВөРЎРӮР ВөРЎРӮР С‘РЎРғР С•Р РҶРЎвҖ№Р РҶР В°Р ВөР Сҳ Р С‘Р Р…РЎвҖҡР ВөРЎРӮРЎвҖһР ВөР в„–РЎРғ
        }
    };
}

function closeAiErrorModal() {
    if (!aiErrorModal) return;
    aiErrorModal.classList.remove('visible');
    setTimeout(() => aiErrorModal.style.display = 'none', 300);
}

document.addEventListener('DOMContentLoaded', () => {
    if (aiErrorDetailsToggle) {
        aiErrorDetailsToggle.addEventListener('click', () => {
            if (aiErrorDetailsContent.style.display === 'none') {
                aiErrorDetailsContent.style.display = 'block';
                aiErrorDetailsToggle.textContent = "Р РҺР С”РЎРӮРЎвҖ№РЎвҖҡРЎРҠ Р Т‘Р ВөРЎвҖҡР В°Р В»Р С‘ Р С•РЎвӮ¬Р С‘Р ВұР С”Р С‘";
            } else {
                aiErrorDetailsContent.style.display = 'none';
                aiErrorDetailsToggle.textContent = "Р СҹР С•Р С”Р В°Р В·Р В°РЎвҖҡРЎРҠ Р Т‘Р ВөРЎвҖҡР В°Р В»Р С‘ Р С•РЎвӮ¬Р С‘Р ВұР С”Р С‘";
            }
        });
    }
});

// --- РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ РЎРӮР В°РЎРғРЎвҖЎР ВөРЎвҖҡР В° Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ ---
function addCalculationMessage(message, type = "calc-info", isRestoring = false) {
    if (!calculationLog) return;
    if (!isRestoring && player) {
        if (!player.calcLogHistory) player.calcLogHistory = [];
        player.calcLogHistory.push(message);
        if (player.calcLogHistory.length > 50) player.calcLogHistory.shift();
    }
    const emptyMessage = calculationLog.querySelector('p[data-i18n="gameInterface.calcLogPanel.empty"]');
    if (emptyMessage && calculationLog.children.length === 1 && calculationLog.firstElementChild === emptyMessage) {
        calculationLog.innerHTML = '';
    }
    const messageElement = document.createElement('p');
    messageElement.textContent = message;
    calculationLog.appendChild(messageElement);
    calculationLog.scrollTo({ top: calculationLog.scrollHeight, behavior: 'smooth' });
}






async function loadAndDecryptBuiltInKeys() {
    // Р вҖ”Р В°Р С–Р В»РЎС“РЎвӮ¬Р С”Р В° Р Т‘Р В»РЎРҸ Р РҶРЎРғРЎвҖҡРЎРӮР С•Р ВөР Р…Р Р…РЎвҖ№РЎвҖҰ Р С”Р В»РЎРӢРЎвҖЎР ВөР в„– (Р РҶР С•Р В·Р РҶРЎРӮР В°РЎвҖ°Р В°Р ВөР Сҳ Р С—РЎС“РЎРғРЎвҖҡР С•Р в„– Р СҳР В°РЎРғРЎРғР С‘Р РҶ, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р С‘Р В·Р ВұР ВөР В¶Р В°РЎвҖҡРЎРҠ ReferenceError)
    return [];
}

async function fetchAndSelectBuiltInKey() {
    const keys = await loadAndDecryptBuiltInKeys();
    if (!keys || keys.length === 0) {
        currentBuiltInKey = null;
        GEMINI_API_KEY = '';
        isUsingBuiltInKey = false;
        localStorage.removeItem(BUILT_IN_KEY_STORAGE_FLAG);
        if (apiKeyInput) apiKeyInput.disabled = false;
        updateApiKeyStatus();
        return false;
    }

    const randomIndex = Math.floor(Math.random() * keys.length);
    currentBuiltInKey = keys[randomIndex];
    GEMINI_API_KEY = currentBuiltInKey;
    isUsingBuiltInKey = true;
    localStorage.setItem(BUILT_IN_KEY_STORAGE_FLAG, 'true');
    localStorage.removeItem('geminiApiKey');
    if (apiKeyInput) {
        apiKeyInput.value = '';
        apiKeyInput.disabled = true;
    }
    console.log("Р вҖҷРЎвҖ№Р ВұРЎРӮР В°Р Р… Р РҶРЎРғРЎвҖҡРЎРӮР С•Р ВөР Р…Р Р…РЎвҖ№Р в„– API Р С”Р В»РЎРӢРЎвҖЎ.");
    updateApiKeyStatus();
    return true;
}

function updateApiKeyStatus() {
    let statusKey;
    let statusClass;
    let keyIsMissing = false;

    if (currentApiProvider === 'local' || currentApiProvider === 'dummy') {
        statusKey = 'mainMenu.apiKeyStatusNotRequired';
        statusClass = 'status-ok';
    } else if (isUsingBuiltInKey) {
        statusKey = 'mainMenu.apiKeyStatusFound';
        statusClass = 'status-ok';
    } else {
        let keyToCheck = geminiApiKey;
        switch (currentApiProvider) {
            case 'gemini':
                keyToCheck = geminiApiKeys[currentGeminiKeyIndex] || geminiApiKey;
                break;
            case 'llmost':
                keyToCheck = llmostApiKey;
                break;
            case 'openrouter':
                keyToCheck = openrouterApiKey;
                break;
            case 'deepseek':
                keyToCheck = deepseekApiKey;
                break;
            case 'omniroute':
                keyToCheck = omnirouteApiKey;
                break;
        }

        if (keyToCheck && keyToCheck.trim() !== '') {
            statusKey = 'mainMenu.apiKeyStatusFound';
            statusClass = 'status-ok';
        } else {
            statusKey = 'mainMenu.apiKeyStatusMissing';
            statusClass = 'status-error';
            keyIsMissing = true;
        }
    }

    if (apiKeyStatus) {
        apiKeyStatus.textContent = t(statusKey, {
            provider: currentApiProvider.charAt(0).toUpperCase() + currentApiProvider.slice(1)
        });
        apiKeyStatus.className = `api-key-status ${statusClass}`;
    }

    if (newGameButton) {
        newGameButton.disabled = keyIsMissing;
        newGameButton.title = keyIsMissing ? t('mainMenu.tooltips.newGameDisabled', 'Р вҖҷР РҶР ВөР Т‘Р С‘РЎвҖҡР Вө API Р С”Р В»РЎРӢРЎвҖЎ Р РҶ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р в„–Р С”Р В°РЎвҖҰ, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Р Р…Р В°РЎвҖЎР В°РЎвҖҡРЎРҠ') : t('mainMenu.tooltips.newGame', 'Р СңР В°РЎвҖЎР В°РЎвҖҡРЎРҠ Р Р…Р С•Р РҶР С•Р Вө Р С—РЎРӮР С‘Р С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р Вө');
    }
}

function saveApiKey() {
    const newKey = document.getElementById('api-key-input').value.trim();
    if (newKey) {
        localStorage.setItem('geminiApiKey', newKey);
        GEMINI_API_KEY = newKey;
        isUsingBuiltInKey = false;
        localStorage.setItem('useBuiltInApiKey_v1', 'false');
        // Р вҖ”Р С’Р СҡР вҖўР СңР С’ ALERT
        showCustomAlert(t('settingsMenu.apiKeySaved', null, 'API Р С”Р В»РЎРӢРЎвҖЎ РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…!'));
    } else {
        localStorage.removeItem('geminiApiKey');
        GEMINI_API_KEY = '';
        // Р вҖ”Р С’Р СҡР вҖўР СңР С’ ALERT
        showCustomAlert(t('settingsMenu.apiKeyRemovedOrEmpty', null, 'API Р С”Р В»РЎРӢРЎвҖЎ РЎС“Р Т‘Р В°Р В»Р ВөР Р….'));
    }
    updateApiKeyStatus();
}

// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р СҡРЎС“Р В·РЎвҖ№Р С”Р С‘ ---
// --- Р вҖўР вҖқР ВҳР СңР С’Р РҮ Р вҖәР СӣР вҖңР ВҳР СҷР С’ Р СҡР РҲР вҖ”Р В«Р СҷР Вҳ ---
function playMenuMusic() {
    if (!audioPlayer) return;
    if (!audioPlayer.paused) return; // Р РҲР В¶Р Вө Р С‘Р С–РЎРӮР В°Р ВөРЎвҖҡ

    playMusic(0); // Р вҖ”Р В°Р С—РЎС“РЎРғР С”Р В°Р ВөР Сҳ menu_theme.mp3

    // Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡР С”Р В° Р ВұР В»Р С•Р С”Р С‘РЎРӮР С•Р РҶР С”Р С‘ Р В°Р РҶРЎвҖҡР С•Р С—Р В»Р ВөРЎРҸ Р ВұРЎРӮР В°РЎС“Р В·Р ВөРЎРӮР С•Р Сҳ
    if (audioPlayer.paused) {
        document.addEventListener('click', () => {
            if (audioPlayer.paused) playMusic(0);
        }, { once: true });
    }
}

function stopMenuMusic() {
    // Р СҡРЎС“Р В·РЎвҖ№Р С”Р В° Р ВұР С•Р В»РЎРҠРЎвӮ¬Р Вө Р Р…Р Вө Р С•РЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөРЎвҖҡРЎРғРЎРҸ Р С—РЎРӮР С‘ Р С—Р ВөРЎРӮР ВөРЎвҖҰР С•Р Т‘Р Вө Р РҶ Р С‘Р С–РЎРӮРЎС“!
    // Р СӣР Р…Р В° Р С—Р В»Р В°Р РҶР Р…Р С• Р С—РЎРӮР С•Р Т‘Р С•Р В»Р В¶Р В°Р ВөРЎвҖҡ Р С‘Р С–РЎРӮР В°РЎвҖҡРЎРҠ РЎвҖһР С•Р Р…Р С•Р Сҳ.
    console.log("Р СҹР ВөРЎРӮР ВөРЎвҖҰР С•Р Т‘ Р РҶ Р С‘Р С–РЎРӮРЎС“: Р СҳРЎС“Р В·РЎвҖ№Р С”Р В° Р С—РЎРӮР С•Р Т‘Р С•Р В»Р В¶Р В°Р ВөРЎвҖҡ Р С‘Р С–РЎРӮР В°РЎвҖҡРЎРҠ.");
}

// Р вҖ”Р В°Р С—РЎС“РЎРғР С”Р В°Р ВөР Сҳ Р С—РЎРӮР С‘ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р Вө РЎРғРЎвҖҡРЎРӮР В°Р Р…Р С‘РЎвҖ РЎвҖ№
window.addEventListener('DOMContentLoaded', () => {
    playMenuMusic();
});

function playMusic(index) {
    if (!audioPlayer || musicFiles.length === 0 || index < 0 || index >= musicFiles.length) {
        console.warn("Р СңР Вө РЎС“Р Т‘Р В°Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶР С•РЎРғР С—РЎРӮР С•Р С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР С‘ Р СҳРЎС“Р В·РЎвҖ№Р С”РЎС“: Р Р…Р ВөРЎвҖҡ Р С—Р В»Р ВөР ВөРЎРӮР В°, Р Р…Р ВөРЎвҖҡ РЎвҖһР В°Р в„–Р В»Р С•Р РҶ Р С‘Р В»Р С‘ Р Р…Р ВөР РҶР ВөРЎРӮР Р…РЎвҖ№Р в„– Р С‘Р Р…Р Т‘Р ВөР С”РЎРғ.", index);
        return;
    }
    if (!userInteractedForMusic && currentTrackIndex !== -1) {
        console.log("Р СҡРЎС“Р В·РЎвҖ№Р С”Р В° Р В·Р В°Р ВұР В»Р С•Р С”Р С‘РЎРӮР С•Р РҶР В°Р Р…Р В° Р Т‘Р С• Р С—Р ВөРЎРӮР РҶР С•Р С–Р С• Р РҶР В·Р В°Р С‘Р СҳР С•Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ Р С—Р С•Р В»РЎРҠР В·Р С•Р РҶР В°РЎвҖҡР ВөР В»РЎРҸ РЎРғ Р С”Р Р…Р С•Р С—Р С”Р С•Р в„– Р С—Р ВөРЎРӮР ВөР С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘РЎРҸ.");
        return;
    }

    const trackSrc = SOUND_FOLDER_PATH + musicFiles[index];
    if (audioPlayer.currentSrc.endsWith(trackSrc) && !audioPlayer.paused) {
        console.log(`Р СһРЎРӮР ВөР С” ${musicFiles[index]} РЎС“Р В¶Р Вө Р С‘Р С–РЎРӮР В°Р ВөРЎвҖҡ.`);
        return;
    }

    console.log(`Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° Р РҶР С•РЎРғР С—РЎРӮР С•Р С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР С‘ Р СҳРЎС“Р В·РЎвҖ№Р С”РЎС“: ${musicFiles[index]}`);
    audioPlayer.src = trackSrc;
    audioPlayer.volume = musicVolume;
    audioPlayer.loop = true; // Р вҖ”Р В°РЎвҖ Р С‘Р С”Р В»Р С‘Р РҶР В°Р ВөР Сҳ РЎвҖҡРЎРӮР ВөР С”

    const playPromise = audioPlayer.play();

    if (playPromise !== undefined) {
        playPromise.then(_ => {
            console.log(`Р ВҳР С–РЎРӮР В°Р ВөРЎвҖҡ: ${musicFiles[index]}`);
            isMusicPlaying = true;
            currentTrackIndex = index;
            updateMusicToggleButton(true);
        }).catch(error => {
            console.warn(`Р вҖҷР С•РЎРғР С—РЎРӮР С•Р С‘Р В·Р РҶР ВөР Т‘Р ВөР Р…Р С‘Р Вө Р СҳРЎС“Р В·РЎвҖ№Р С”Р С‘ Р Р…Р Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р Т‘Р В»РЎРҸ ${musicFiles[index]}:`, error);
            isMusicPlaying = false;
            updateMusicToggleButton(false);
        });
    } else {
        isMusicPlaying = !audioPlayer.paused;
        currentTrackIndex = index;
        updateMusicToggleButton(isMusicPlaying);
    }
}

function pauseMusic() {
    if (!audioPlayer || audioPlayer.paused) return;
    audioPlayer.pause();
    isMusicPlaying = false;
    updateMusicToggleButton(false);
    console.log("Р СҡРЎС“Р В·РЎвҖ№Р С”Р В° Р Р…Р В° Р С—Р В°РЎС“Р В·Р Вө.");
}

function toggleMusic() {
    if (!toggleMusicButton) return;

    if (!userInteractedForMusic) {
        userInteractedForMusic = true;
        console.log("Р СӣР ВұР Р…Р В°РЎРӮРЎС“Р В¶Р ВөР Р…Р С• Р РҶР В·Р В°Р С‘Р СҳР С•Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘Р Вө Р С—Р С•Р В»РЎРҠР В·Р С•Р РҶР В°РЎвҖҡР ВөР В»РЎРҸ, Р РҶР С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р Вө Р РҶР С•РЎРғР С—РЎРӮР С•Р С‘Р В·Р РҶР ВөР Т‘Р ВөР Р…Р С‘РЎРҸ Р СҳРЎС“Р В·РЎвҖ№Р С”Р С‘.");
        if (!isMusicPlaying) {
            const indexToPlay = currentTrackIndex >= 0 ? currentTrackIndex : 0;
            playMusic(indexToPlay);
        }
        return;
    }

    if (isMusicPlaying) {
        pauseMusic();
    } else {
        if (audioPlayer.readyState >= 2 && audioPlayer.currentSrc) {
            const playPromise = audioPlayer.play();
            if (playPromise !== undefined) {
                playPromise.then(() => {
                    isMusicPlaying = true;
                    updateMusicToggleButton(true);
                }).catch(e => console.error("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р РҶР С•Р В·Р С•Р ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С‘РЎРҸ Р СҳРЎС“Р В·РЎвҖ№Р С”Р С‘:", e));
            } else {
                isMusicPlaying = true;
                updateMusicToggleButton(true);
            }
        } else {
            playMusic(0);
        }
    }
}

function updateMusicToggleButton(isPlaying) {
    if (!toggleMusicIcon || !toggleMusicButton) return;
    if (isPlaying) {
        toggleMusicIcon.classList.remove('fa-volume-off', 'fa-play');
        toggleMusicIcon.classList.add('fa-volume-high');
        toggleMusicButton.title = t('gameInterface.toggleMusicButtonTitlePause', "Р СҹР В°РЎС“Р В·Р В°");
    } else {
        toggleMusicIcon.classList.remove('fa-volume-high', 'fa-pause');
        toggleMusicIcon.classList.add('fa-volume-off');
        toggleMusicButton.title = t('gameInterface.toggleMusicButtonTitlePlay', "Р вҖҷР С”Р В»РЎРӢРЎвҖЎР С‘РЎвҖҡРЎРҠ Р СҳРЎС“Р В·РЎвҖ№Р С”РЎС“");
    }
    toggleMusicButton.dataset.i18n = isPlaying
        ? "[title]gameInterface.toggleMusicButtonTitlePause"
        : "[title]gameInterface.toggleMusicButtonTitlePlay";
}

function playNextTrack() {
    if (musicFiles.length === 0) return;
    let nextIndex = (currentTrackIndex + 1) % musicFiles.length;
    playMusic(nextIndex);
}

function setupMusicPlayer() {
    if (!audioPlayer) return;
    audioPlayer.addEventListener('ended', playNextTrack);
}

// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ TTS (Text-to-Speech) ---
function setupTTS() {
    if (!hasElectronAPI) {
        console.warn("Р вҖәР С•Р С”Р В°Р В»РЎРҠР Р…РЎвҖ№Р в„– TTS РЎРӮР В°Р ВұР С•РЎвҖҡР В°Р ВөРЎвҖҡ РЎвҖҡР С•Р В»РЎРҠР С”Р С• Р РҶ Electron-Р РҶР ВөРЎРӮРЎРғР С‘Р С‘.");
        if (ttsVoiceSelectorGroup) ttsVoiceSelectorGroup.style.display = 'none';
        return;
    }

    if (ttsVoiceSelectorGroup) ttsVoiceSelectorGroup.style.display = 'block';
    loadTTSVoices();

    if (ttsVoiceSelect) {
        ttsVoiceSelect.addEventListener('change', handleTTSVoiceChange);
    }
}

function loadTTSVoices() {
    // Р вҖ“Р ВөРЎРғРЎвҖҡР С”Р С• Р В·Р В°Р Т‘Р В°Р Р…Р Р…РЎвҖ№Р в„– РЎРғР С—Р С‘РЎРғР С•Р С” Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„–, Р С”Р С•РЎвҖҡР С•РЎРӮРЎвҖ№Р Вө Р СҳРЎвҖ№ Р С—Р С•Р В»Р С•Р В¶Р С‘Р Сҳ Р РҶ Р С—Р В°Р С—Р С”РЎС“ assets/tts
    ttsVoices = [
        { name: "Р ВҳРЎРӮР С‘Р Р…Р В° (Р В РЎС“РЎРғРЎРғР С”Р С‘Р в„–, Р вҖ“Р ВөР Р…РЎРғР С”Р С‘Р в„–)", file: "ru_RU-irina-medium.onnx", lang: "ru" },
        { name: "Р вҖқР СҳР С‘РЎвҖҡРЎРӮР С‘Р в„– (Р В РЎС“РЎРғРЎРғР С”Р С‘Р в„–, Р СҡРЎС“Р В¶РЎРғР С”Р С•Р в„–)", file: "ru_RU-dmitri-medium.onnx", lang: "ru" },
        { name: "Amy (English, Female)", file: "en_US-amy-medium.onnx", lang: "en" }
    ];

    if (!ttsVoiceSelect) return;
    ttsVoiceSelect.innerHTML = '';

    ttsVoices.forEach(voice => {
        const option = document.createElement('option');
        option.value = voice.file;
        option.textContent = voice.name;
        ttsVoiceSelect.appendChild(option);
    });

    const savedVoiceFile = localStorage.getItem(TTS_VOICE_STORAGE_KEY);
    if (savedVoiceFile && ttsVoices.some(v => v.file === savedVoiceFile)) {
        ttsVoiceSelect.value = savedVoiceFile;
        selectedTTSVoice = ttsVoices.find(v => v.file === savedVoiceFile);
    } else {
        selectTTSVoice();
    }
}

function selectTTSVoice() {
    const targetLang = currentLanguage;
    let voice = ttsVoices.find(v => v.lang === targetLang) || ttsVoices[0];
    if (voice) {
        selectedTTSVoice = voice;
        if (ttsVoiceSelect) ttsVoiceSelect.value = voice.file;
    }
}

function handleTTSVoiceChange(event) {
    const selectedFile = event.target.value;
    const voice = ttsVoices.find(v => v.file === selectedFile);
    if (voice) {
        selectedTTSVoice = voice;
        localStorage.setItem(TTS_VOICE_STORAGE_KEY, voice.file);
        console.log(`[TTS] Р вҖҷРЎвҖ№Р ВұРЎРӮР В°Р Р… Р В»Р С•Р С”Р В°Р В»РЎРҠР Р…РЎвҖ№Р в„– Р С–Р С•Р В»Р С•РЎРғ: ${voice.name}`);
        speakText(t('tts.voiceTest', 'Р СһР ВөРЎРғРЎвҖҡ Р С–Р С•Р В»Р С•РЎРғР В°'));
    }
}

/**
 * Р В Р В°РЎРғРЎРғРЎвҖЎР С‘РЎвҖҡРЎвҖ№Р РҶР В°Р ВөРЎвҖҡ Р СҹР СӣР вҖәР СңР В«Р в„ў Р СҳР С•Р Т‘Р С‘РЎвҖһР С‘Р С”Р В°РЎвҖҡР С•РЎРӮ Р Т‘Р В»РЎРҸ РЎвҖҰР В°РЎРӮР В°Р С”РЎвҖҡР ВөРЎРӮР С‘РЎРғРЎвҖҡР С‘Р С”Р С‘, РЎС“РЎвҖЎР С‘РЎвҖҡРЎвҖ№Р РҶР В°РЎРҸ РЎРғРЎвҖҡР В°РЎвҖҡРЎвҖ№, РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡРЎвҖ№ Р С‘ РЎС“Р СҳР ВөР Р…Р С‘РЎРҸ.
 * @param {string} statKey - Р СҷР В»РЎРӢРЎвҖЎ РЎвҖҰР В°РЎРӮР В°Р С”РЎвҖҡР ВөРЎРӮР С‘РЎРғРЎвҖҡР С‘Р С”Р С‘ ('str', 'dex', 'int', 'con', 'cha').
 * @returns {number} - Р ВҳРЎвҖҡР С•Р С–Р С•Р РҶРЎвҖ№Р в„– Р СҳР С•Р Т‘Р С‘РЎвҖһР С‘Р С”Р В°РЎвҖҡР С•РЎРӮ.
 */
function getStatModifier(statKey) {
    if (!player || !player.stats[statKey]) {
        return 0;
    }

    // Р РҒР В°Р С– 1: Р вҖҳР В°Р В·Р С•Р РҶРЎвҖ№Р в„– Р СҳР С•Р Т‘Р С‘РЎвҖһР С‘Р С”Р В°РЎвҖҡР С•РЎРӮ Р С•РЎвҖҡ РЎвҖҰР В°РЎРӮР В°Р С”РЎвҖҡР ВөРЎРӮР С‘РЎРғРЎвҖҡР С‘Р С”Р С‘
    let baseModifier = Math.floor((player.stats[statKey] - 10) / 2);
    let totalBonus = 0;
    let logMessages = [];

    // Р РҒР В°Р С– 2: Р РҲРЎвҖЎР ВөРЎвҖҡ Р ВұР В°РЎвҖһРЎвҖһР С•Р РҶ Р С‘ Р Т‘Р ВөР ВұР В°РЎвҖһРЎвҖһР С•Р РҶ Р С•РЎвҖҡ РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ-РЎРҢРЎвҖһРЎвҖһР ВөР С”РЎвҖҡР С•Р РҶ
    if (player.statusEffects) {
        for (const effectId in player.statusEffects) {
            const effect = player.statusEffects[effectId];
            if (effect.effects && Array.isArray(effect.effects)) {
                for (const subEffect of effect.effects) {
                    if (subEffect.action && subEffect.action.stat === statKey && subEffect.action.type === 'modify_stat') {
                        const change = parseInt(subEffect.action.change, 10);
                        if (!isNaN(change)) {
                            totalBonus += change;
                            logMessages.push(`Р ВӯРЎвҖһРЎвҖһР ВөР С”РЎвҖҡ '${effect.name}': ${change > 0 ? '+' : ''}${change} Р С” ${statKey.toUpperCase()}`);
                        }
                    }
                }
            }
        }
    }

    // Р РҒР В°Р С– 3: Р РҲРЎвҖЎР ВөРЎвҖҡ Р ВұР С•Р Р…РЎС“РЎРғР С•Р РҶ Р С•РЎвҖҡ Р С—Р В°РЎРғРЎРғР С‘Р РҶР Р…РЎвҖ№РЎвҖҰ РЎС“Р СҳР ВөР Р…Р С‘Р в„– (Р РҲР Р…Р С‘Р РҶР ВөРЎРӮРЎРғР В°Р В»РЎРҠР Р…РЎвҖ№Р в„– Р С—Р В°РЎРӮРЎРғР ВөРЎРӮ)
    if (player.skills) {
        for (const skillId in player.skills) {
            const skill = player.skills[skillId];
            if (skill.skillType && skill.skillType.toLowerCase().includes('Р С—Р В°РЎРғРЎРғР С‘Р РҶ') && skill.effectsJSON) {
                try {
                    const parsedEffects = typeof skill.effectsJSON === 'string' ? JSON.parse(skill.effectsJSON) : skill.effectsJSON;
                    for (const subEffect of parsedEffects) {
                        if (subEffect.action && subEffect.action.stat === statKey && subEffect.action.type === 'modify_stat') {
                            const change = parseInt(subEffect.action.change, 10);
                            if (!isNaN(change)) {
                                totalBonus += change;
                                logMessages.push(`Р РҲР СҳР ВөР Р…Р С‘Р Вө '${skill.name}': ${change > 0 ? '+' : ''}${change}`);
                            }
                        }
                    }
                } catch (e) { console.error("Error parsing skill effects", e); }
            }
        }
    }

    // Р РҒР В°Р С– 4: (Р вҖ”Р В°Р Т‘Р ВөР В» Р Р…Р В° Р ВұРЎС“Р Т‘РЎС“РЎвҖ°Р ВөР Вө) Р РҲРЎвҖЎР ВөРЎвҖҡ Р ВұР С•Р Р…РЎС“РЎРғР С•Р РҶ Р С•РЎвҖҡ РЎРҢР С”Р С‘Р С—Р С‘РЎРӮР С•Р РҶР В°Р Р…Р Р…РЎвҖ№РЎвҖҰ Р С—РЎРӮР ВөР Т‘Р СҳР ВөРЎвҖҡР С•Р РҶ
    // for (const itemId in player.equipment) { ... }

    const finalModifier = baseModifier + totalBonus;

    if (logMessages.length > 0) {
        console.log(`[getStatModifier] Р В Р В°РЎРғРЎвҖЎР ВөРЎвҖҡ Р Т‘Р В»РЎРҸ ${statKey.toUpperCase()}: Р вҖҳР В°Р В·Р В° ${baseModifier}, Р вҖҳР С•Р Р…РЎС“РЎРғРЎвҖ№ ${totalBonus} -> Р ВҳРЎвҖҡР С•Р С– ${finalModifier}. Р СҹРЎРӮР С‘РЎвҖЎР С‘Р Р…РЎвҖ№:`, logMessages.join('; '));
    }

    return finalModifier;
}

function toggleTTS() {
    if (!speechSynthesis) return;
    isTTSEnabled = !isTTSEnabled;
    updateTTSToggleButton(isTTSEnabled);
    if (!isTTSEnabled && speechSynthesis.speaking) {
        speechSynthesis.cancel();
    }
    const statusMessage = isTTSEnabled ? t('tts.enabled', 'Р СӣР В·Р РҶРЎС“РЎвҖЎР С”Р В° Р РҶР С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р В°.') : t('tts.disabled', 'Р СӣР В·Р РҶРЎС“РЎвҖЎР С”Р В° Р РҶРЎвҖ№Р С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р В°.');
    console.log(statusMessage);
}

function updateTTSToggleButton(isEnabled) {
    if (!toggleTTSIcon || !toggleTTSButton) return;
    if (isEnabled) {
        toggleTTSIcon.classList.remove('fa-comment-dots');
        toggleTTSIcon.classList.add('fa-comment-slash');
        toggleTTSButton.title = t('gameInterface.toggleTTSButtonTitlePause', "Р вҖҷРЎвҖ№Р С”Р В»РЎРӢРЎвҖЎР С‘РЎвҖҡРЎРҠ Р С•Р В·Р РҶРЎС“РЎвҖЎР С”РЎС“");
    } else {
        toggleTTSIcon.classList.remove('fa-comment-slash');
        toggleTTSIcon.classList.add('fa-comment-dots');
        toggleTTSButton.title = t('gameInterface.toggleTTSButtonTitlePlay', "Р вҖҷР С”Р В»РЎРӢРЎвҖЎР С‘РЎвҖҡРЎРҠ Р С•Р В·Р РҶРЎС“РЎвҖЎР С”РЎС“");
    }
    toggleTTSButton.dataset.i18n = isEnabled
        ? "[title]gameInterface.toggleTTSButtonTitlePause"
        : "[title]gameInterface.toggleTTSButtonTitlePlay";
}

async function speakText(text) {
    if (!text || text.trim() === '' || !selectedTTSVoice) return;

    // Р СӣРЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөР Сҳ Р С—РЎРӮР ВөР Т‘РЎвҖ№Р Т‘РЎС“РЎвҖ°РЎС“РЎРӢ РЎРӮР ВөРЎвҖЎРЎРҠ, Р ВөРЎРғР В»Р С‘ Р С•Р Р…Р В° Р ВұРЎвҖ№Р В»Р В°
    if (currentAudio) {
        currentAudio.pause();
        currentAudio = null;
    }

    console.log(`[TTS] Р вҖңР ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘РЎРҸ Р В°РЎС“Р Т‘Р С‘Р С• Р Т‘Р В»РЎРҸ: "${text.substring(0, 30)}..."`);

    try {
        // Р СӣРЎвҖҡР С—РЎРӮР В°Р РҶР В»РЎРҸР ВөР Сҳ РЎвҖҡР ВөР С”РЎРғРЎвҖҡ Р РҶ Node.js Р Т‘Р В»РЎРҸ Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘ РЎвҖЎР ВөРЎРӮР ВөР В· Piper
        const result = await window.electronAPI.speakText(text, selectedTTSVoice.file);

        if (result.success) {
            currentAudio = new Audio(result.audioPath);
            currentAudio.volume = 0.8;
            currentAudio.play();
        } else {
            console.error("[TTS] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘:", result.error);
            showCustomAlert("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° TTS: Р вҖқР РҶР С‘Р В¶Р С•Р С” Р С‘Р В»Р С‘ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Р С–Р С•Р В»Р С•РЎРғР В° Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р…РЎвҖ№. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө Р С—Р В°Р С—Р С”РЎС“ assets/tts/");
        }
    } catch (e) {
        console.error("[TTS] Р СҷРЎРӮР С‘РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р В°РЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° Р РҶРЎвҖ№Р В·Р С•Р РҶР В° IPC:", e);
    }
}

// Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРҸ Р С–Р ВөР Р…Р ВөРЎРӮР В°РЎвҖ Р С‘Р С‘ Р С‘Р В·Р С•Р ВұРЎРӮР В°Р В¶Р ВөР Р…Р С‘Р в„– РЎС“Р Т‘Р В°Р В»Р ВөР Р…Р В°


async function loadItemsReference() {
    if (window.ModAPI && window.ModAPI.isTotalConversion) {
        console.log(`[Total Conversion] Р СҹРЎРӮР С•Р С—РЎС“РЎРғР С” Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ Р РҶР В°Р Р…Р С‘Р В»РЎРҠР Р…Р С•Р С–Р С• РЎРғР С—РЎРӮР В°Р РҶР С•РЎвҖЎР Р…Р С‘Р С”Р В° Р С—РЎРӮР ВөР Т‘Р СҳР ВөРЎвҖҡР С•Р РҶ.`);
        itemsReferenceData = [];
        return;
    }

    const isDefault = currentLanguage === DEFAULT_LANGUAGE;
    const { primary, fallback } = getLocalizedRuntimeAssetPaths(
        isDefault ? 'items_reference_default' : 'items_reference_template',
        'items_reference_default',
        { lang: currentLanguage }
    );
    const filePath = primary || fallback;
    console.log(`Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ РЎРғР С—РЎРӮР В°Р РҶР С•РЎвҖЎР Р…Р С‘Р С” Р С—РЎРӮР ВөР Т‘Р СҳР ВөРЎвҖҡР С•Р РҶ Р С‘Р В·: ${filePath}`);
    try {
        let response = await fetch(`${filePath}?t=${Date.now()}`);
        if (!response.ok && !isDefault) {
            response = await fetch(`${fallback}?t=${Date.now()}`);
        }
        if (!response.ok) throw new Error(`HTTP Р С•РЎвӮ¬Р С‘Р ВұР С”Р В°! РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ: ${response.status}`);
        
        itemsReferenceData = await response.json();
        console.log(`Р РҺР С—РЎРӮР В°Р РҶР С•РЎвҖЎР Р…Р С‘Р С” Р С—РЎРӮР ВөР Т‘Р СҳР ВөРЎвҖҡР С•Р РҶ (${itemsReferenceData.length} РЎвӮ¬РЎвҖҡ.) РЎС“РЎРғР С—Р ВөРЎвӮ¬Р Р…Р С• Р В·Р В°Р С–РЎРӮРЎС“Р В¶Р ВөР Р… Р С‘ РЎРӮР В°Р В·Р С•Р ВұРЎРӮР В°Р Р….`);
    } catch (error) {
        console.error(`Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ Р С‘Р В»Р С‘ РЎРӮР В°Р В·Р С•Р ВұРЎРӮР В°РЎвҖҡРЎРҠ РЎРғР С—РЎРӮР В°Р РҶР С•РЎвҖЎР Р…Р С‘Р С” Р С—РЎРӮР ВөР Т‘Р СҳР ВөРЎвҖҡР С•Р РҶ:`, error);
        itemsReferenceData = [];
    }
}

// --- Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘Р С‘ Р вҖәР С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘Р С‘ ---
async function loadLanguagesConfig() {
    try {
        const response = await fetch('assets/localizations/languages.json');
        if (!response.ok) throw new Error(`HTTP Р С•РЎвӮ¬Р С‘Р ВұР С”Р В°! РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ: ${response.status}`);
        availableLanguages = await response.json();
        console.log("Р вҖқР С•РЎРғРЎвҖҡРЎС“Р С—Р Р…РЎвҖ№Р Вө РЎРҸР В·РЎвҖ№Р С”Р С‘ Р В·Р В°Р С–РЎРӮРЎС“Р В¶Р ВөР Р…РЎвҖ№:", availableLanguages);
        populateLanguageSelector();
    } catch (error) {
        console.error("Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ Р С”Р С•Р Р…РЎвҖһР С‘Р С–РЎС“РЎРӮР В°РЎвҖ Р С‘РЎРӢ РЎРҸР В·РЎвҖ№Р С”Р С•Р РҶ:", error);
        availableLanguages = {
            [DEFAULT_LANGUAGE]: { name: (DEFAULT_LANGUAGE === 'ru' ? 'Р В РЎС“РЎРғРЎРғР С”Р С‘Р в„–' : 'Default'), file: `assets/localizations/${DEFAULT_LANGUAGE}.json` }
        };
        populateLanguageSelector();
    }
}

function populateLanguageSelector() {
    if (!languageSelect) return;
    languageSelect.innerHTML = '';

    for (const langCode in availableLanguages) {
        const option = document.createElement('option');
        option.value = langCode;
        option.textContent = availableLanguages[langCode].name;
        if (langCode === currentLanguage) {
            option.selected = true;
        }
        languageSelect.appendChild(option);
    }

    languageSelect.removeEventListener('change', handleLanguageChange);
    languageSelect.addEventListener('change', handleLanguageChange);
}

function handleLanguageChange(event) {
    const newLang = event.target.value;
    setLanguage(newLang);
}

async function loadTranslations(langCode) {
    const langConfig = availableLanguages[langCode];
    if (!langConfig || !langConfig.file) {
        console.error(`Р СҷР С•Р Р…РЎвҖһР С‘Р С–РЎС“РЎРӮР В°РЎвҖ Р С‘РЎРҸ РЎвҖһР В°Р в„–Р В»Р В° Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘Р В° Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р…Р В° Р Т‘Р В»РЎРҸ РЎРҸР В·РЎвҖ№Р С”Р В°: ${langCode}`);
        translations = {};
        return;
    }

    const fileUrl = `${langConfig.file}?t=${Date.now()}`;
    console.log(`Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘РЎвҖ№ Р С‘Р В·: ${fileUrl}`);

    try {
        const response = await fetch(fileUrl, {
            cache: 'no-store',
            headers: {
                'Cache-Control': 'no-cache, no-store, must-revalidate',
                'Pragma': 'no-cache',
                'Expires': '0'
            }
        });

        if (!response.ok) throw new Error(`HTTP Р С•РЎвӮ¬Р С‘Р ВұР С”Р В°! РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ: ${response.status}, Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ ${response.url}`);
        const responseText = await response.text();

        try {
            translations = JSON.parse(responseText);
            console.log(`Р СҹР ВөРЎРӮР ВөР РҶР С•Р Т‘РЎвҖ№ Р Т‘Р В»РЎРҸ '${langCode}' РЎС“РЎРғР С—Р ВөРЎвӮ¬Р Р…Р С• РЎРӮР В°Р В·Р С•Р ВұРЎРӮР В°Р Р…РЎвҖ№.`);
        } catch (parseError) {
            console.error(`Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В Р С’Р вҖ”Р СӣР вҖҳР В Р С’Р СһР В¬ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘РЎвҖ№ Р Т‘Р В»РЎРҸ ${langCode} Р С—Р С•РЎРғР В»Р Вө Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘. Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°:`, parseError);
            console.error("--- Р СҹРЎРӮР С•Р ВұР В»Р ВөР СҳР Р…РЎвҖ№Р в„– JSON РЎвҖҡР ВөР С”РЎРғРЎвҖҡ, Р С—Р С•Р В»РЎС“РЎвҖЎР ВөР Р…Р Р…РЎвҖ№Р в„– Р ВұРЎРӮР В°РЎС“Р В·Р ВөРЎРӮР С•Р Сҳ: ---");
            const errorPosition = parseError.message.match(/position (\d+)/);
            if (errorPosition && errorPosition[1]) {
                const pos = parseInt(errorPosition[1], 10);
                const contextLength = 50;
                console.error(responseText.substring(Math.max(0, pos - contextLength), Math.min(responseText.length, pos + contextLength)));
                console.error(`^^^ Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°, Р РҶР ВөРЎРӮР С•РЎРҸРЎвҖҡР Р…Р С•, Р С•Р С”Р С•Р В»Р С• Р С—Р С•Р В·Р С‘РЎвҖ Р С‘Р С‘ ${pos} ^^^`);
            } else {
                console.error(responseText.substring(0, 500) + '...');
            }
            console.error("---------------------------------------------");
            translations = {};
        }

    } catch (fetchError) {
        console.error(`Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р вҖ”Р С’Р вҖңР В Р РҲР вҖ”Р ВҳР СһР В¬ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘РЎвҖ№ Р Т‘Р В»РЎРҸ ${langCode}:`, fetchError);
        translations = {};
    }
}

async function setLanguage(langCode) {
    if (!availableLanguages[langCode]) {
        console.warn(`Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° РЎС“РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С‘РЎвҖҡРЎРҠ Р Р…Р ВөР С—Р С•Р Т‘Р Т‘Р ВөРЎРӮР В¶Р С‘Р РҶР В°Р ВөР СҳРЎвҖ№Р в„– РЎРҸР В·РЎвҖ№Р С”: ${langCode}. Р вҖҷР С•Р В·Р РҶРЎРӮР В°РЎвҖҡ Р С” РЎРҸР В·РЎвҖ№Р С”РЎС“ Р С—Р С• РЎС“Р СҳР С•Р В»РЎвҖЎР В°Р Р…Р С‘РЎРӢ.`);
        langCode = DEFAULT_LANGUAGE;
    }

    const previousLanguage = currentLanguage;
    currentLanguage = langCode;
    localStorage.setItem(LANGUAGE_STORAGE_KEY, currentLanguage);
    console.log(`Р РҲРЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С”Р В° РЎРҸР В·РЎвҖ№Р С”Р В° Р Р…Р В°: ${currentLanguage}`);

    document.documentElement.lang = currentLanguage;

    if (languageSelect) {
        languageSelect.value = currentLanguage;
    }

    await loadTranslations(currentLanguage);
    applyTranslations();

    if (speechSynthesis) {
        loadTTSVoices();
        if (isTTSEnabled && speechSynthesis.speaking) {
            speechSynthesis.cancel();
        }
    }

    const isGameActive = gameInterface && gameInterface.classList.contains('active-screen');

    if (currentLanguage !== previousLanguage && !isGameActive) {
        try {
            await loadLore(DEFAULT_WORLD_ID, currentLanguage);
            await loadGlobalLocations(DEFAULT_WORLD_ID, currentLanguage, player ? player.era : getRuntimeDefaultEraId());
            await loadItemsReference();
            await loadPredefinedEffects();
            updateMapDisplay();
        } catch (error) {
            console.error(error);
        }
    }
    updateDynamicUIText();
    updateApiKeyStatus();
}

function applyTranslations() {
    const elements = document.querySelectorAll('[data-i18n]');

    elements.forEach(el => {
        if (el.id === 'level-info') { // level-info Р С•Р ВұР Р…Р С•Р РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ Р С•РЎвҖҡР Т‘Р ВөР В»РЎРҠР Р…Р С• РЎвҖЎР ВөРЎРӮР ВөР В· updateCharacterSheet
            return;
        }

        const keyWithOptions = el.dataset.i18n;
        let key = keyWithOptions;
        let attribute = 'textContent'; // Р СҹР С• РЎС“Р СҳР С•Р В»РЎвҖЎР В°Р Р…Р С‘РЎРӢ Р С•Р ВұР Р…Р С•Р РҶР В»РЎРҸР ВөР Сҳ РЎвҖҡР ВөР С”РЎРғРЎвҖҡР С•Р РҶР С•Р Вө РЎРғР С•Р Т‘Р ВөРЎРӮР В¶Р С‘Р СҳР С•Р Вө

        // Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҸР ВөР Сҳ, РЎС“Р С”Р В°Р В·Р В°Р Р… Р В»Р С‘ Р В°РЎвҖҡРЎРӮР С‘Р ВұРЎС“РЎвҖҡ Р РҶ data-i18n (Р Р…Р В°Р С—РЎРӮР С‘Р СҳР ВөРЎРӮ, [placeholder]key.name)
        if (key.startsWith('[')) {
            const match = key.match(/^\[(.*?)\](.*)/);
            if (match) {
                attribute = match[1];
                key = match[2];
            }
        }

        let variables = null;
        if (el.dataset.i18nVariables) {
            try {
                // Р вҖ”Р В°Р СҳР ВөР Р…РЎРҸР ВөР Сҳ Р С•Р Т‘Р С‘Р Р…Р В°РЎРӮР Р…РЎвҖ№Р Вө Р С”Р В°Р РҶРЎвҖ№РЎвҖЎР С”Р С‘ Р Р…Р В° Р Т‘Р РҶР С•Р в„–Р Р…РЎвҖ№Р Вө Р Т‘Р В»РЎРҸ Р С”Р С•РЎРӮРЎРӮР ВөР С”РЎвҖҡР Р…Р С•Р С–Р С• JSON.parse
                const jsonString = el.dataset.i18nVariables.replace(/'/g, '"');
                variables = JSON.parse(jsonString);
            } catch (e) {
                console.error(`Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРӮР В°Р В·Р ВұР С•РЎРӮР В° Р С—Р ВөРЎРӮР ВөР СҳР ВөР Р…Р Р…РЎвҖ№РЎвҖҰ i18n Р Т‘Р В»РЎРҸ Р С”Р В»РЎРӢРЎвҖЎР В° "${key}":`, e, el.dataset.i18nVariables);
            }
        }

        let translation = t(key, variables); // Р СҹР С•Р В»РЎС“РЎвҖЎР В°Р ВөР Сҳ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘

        if (translation !== key) { // Р вҖўРЎРғР В»Р С‘ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘ Р Р…Р В°Р в„–Р Т‘Р ВөР Р… Р С‘ Р С•Р Р… Р Р…Р Вө РЎРӮР В°Р РҶР ВөР Р… РЎРғР В°Р СҳР С•Р СҳРЎС“ Р С”Р В»РЎРӢРЎвҖЎРЎС“
            if (attribute === 'textContent') {
                el.textContent = translation; // Safe: textContent doesn't parse HTML
            } else if (attribute === 'innerHTML') {
                el.innerHTML = sanitizeHTML(translation);
            } else if (el.hasAttribute(attribute)) {
                el.setAttribute(attribute, translation);
            } else {
                // Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• РЎРғР С—Р ВөРЎвҖ Р С‘Р В°Р В»РЎРҠР Р…РЎвҖ№Р в„– Р В°РЎвҖҡРЎРӮР С‘Р ВұРЎС“РЎвҖҡ, Р С”Р С•РЎвҖҡР С•РЎРӮРЎвҖ№Р в„– Р Р…Р Вө РЎРҸР РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ РЎРғРЎвҖҡР В°Р Р…Р Т‘Р В°РЎРӮРЎвҖҡР Р…РЎвҖ№Р Сҳ HTML Р В°РЎвҖҡРЎРӮР С‘Р ВұРЎС“РЎвҖҡР С•Р Сҳ
                // (Р Р…Р В°Р С—РЎРӮР С‘Р СҳР ВөРЎРӮ, data-custom-attr), РЎвҖҡР С• el.setAttribute РЎРғРЎРӮР В°Р ВұР С•РЎвҖҡР В°Р ВөРЎвҖҡ.
                // Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• РЎРғР РҶР С•Р в„–РЎРғРЎвҖҡР РҶР С• Р С•Р ВұРЎРүР ВөР С”РЎвҖҡР В° (Р Р…Р В°Р С—РЎРӮР С‘Р СҳР ВөРЎРӮ, el.value), РЎвҖҡР С• Р Р…РЎС“Р В¶Р Р…Р С• Р С•Р ВұРЎРӮР В°Р ВұР В°РЎвҖҡРЎвҖ№Р РҶР В°РЎвҖҡРЎРҠ Р С•РЎвҖҡР Т‘Р ВөР В»РЎРҠР Р…Р С• Р С‘Р В»Р С‘ РЎС“Р ВұР ВөР Т‘Р С‘РЎвҖҡРЎРҠРЎРғРЎРҸ,
                // РЎвҖЎРЎвҖҡР С• РЎвҖҡР В°Р С”Р С‘Р Вө РЎРғР В»РЎС“РЎвҖЎР В°Р С‘ Р С—Р С•Р С”РЎРӮРЎвҖ№РЎвҖҡРЎвҖ№ Р РҶ updateDynamicUIText Р С‘Р В»Р С‘ Р Т‘РЎРӮРЎС“Р С–Р С‘РЎвҖҰ РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРҸРЎвҖҰ.
                // Р вҖқР В»РЎРҸ Р ВұР С•Р В»РЎРҠРЎвӮ¬Р С‘Р Р…РЎРғРЎвҖҡР РҶР В° РЎРғР В»РЎС“РЎвҖЎР В°Р ВөР РҶ (title, placeholder) setAttribute РЎРғРЎРӮР В°Р ВұР С•РЎвҖҡР В°Р ВөРЎвҖҡ.
                el.setAttribute(attribute, translation);
                // console.warn(`Р ВҰР ВөР В»Р ВөР РҶР С•Р в„– Р В°РЎвҖҡРЎРӮР С‘Р ВұРЎС“РЎвҖҡ "${attribute}" Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р… Р С‘Р В»Р С‘ Р Р…Р Вө РЎРҸР РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ РЎРғРЎвҖҡР В°Р Р…Р Т‘Р В°РЎРӮРЎвҖҡР Р…РЎвҖ№Р Сҳ Р Р…Р В° РЎРҢР В»Р ВөР СҳР ВөР Р…РЎвҖҡР Вө Р Т‘Р В»РЎРҸ Р С”Р В»РЎРӢРЎвҖЎР В°: ${key}. Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° РЎС“РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР С‘РЎвҖҡРЎРҠ РЎвҖЎР ВөРЎРӮР ВөР В· setAttribute.`);
            }
        } else if (!el.innerHTML && (attribute === 'textContent' || attribute === 'innerHTML')) {
            // Р вҖўРЎРғР В»Р С‘ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘ Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р… Р С‘ РЎРҢР В»Р ВөР СҳР ВөР Р…РЎвҖҡ Р С—РЎС“РЎРғРЎвҖҡ, Р С—Р С•Р С”Р В°Р В·РЎвҖ№Р РҶР В°Р ВөР Сҳ Р С”Р В»РЎРӢРЎвҖЎ Р Т‘Р В»РЎРҸ Р С•РЎвҖҡР В»Р В°Р Т‘Р С”Р С‘
            el.innerHTML = `[${key}]`;
        }
    });
    // updateApiKeyStatus(); // Р РҲР В¶Р Вө Р РҶРЎвҖ№Р В·РЎвҖ№Р РҶР В°Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶ setLanguage
}

function t(key, variables = null, fallback = null) {
    let translation = undefined;
    
    // Р РҺР Р…Р В°РЎвҖЎР В°Р В»Р В° Р С‘РЎвҖ°Р ВөР Сҳ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘ Р РҶ РЎРғР В»Р С•Р РҶР В°РЎРӮРЎРҸРЎвҖҰ Р СҳР С•Р Т‘Р С•Р РҶ
    if (window.ModAPI && window.ModAPI.customTranslations && window.ModAPI.customTranslations[currentLanguage]) {
        translation = key.split('.').reduce((obj, i) => obj?.[i], window.ModAPI.customTranslations[currentLanguage]);
    }
    
    // Р вҖўРЎРғР В»Р С‘ Р СҳР С•Р Т‘ Р Р…Р Вө Р С—Р ВөРЎРӮР ВөР С•Р С—РЎРӮР ВөР Т‘Р ВөР В»Р С‘Р В» РЎРғРЎвҖҡРЎРӮР С•Р С”РЎС“, Р С‘РЎвҖ°Р ВөР Сҳ Р РҶ Р ВұР В°Р В·Р С•Р РҶР С•Р в„– Р С‘Р С–РЎРӮР Вө
    if (translation === undefined) {
        translation = key.split('.').reduce((obj, i) => obj?.[i], translations);
    }

    if (typeof translation !== 'string') {
        translation = fallback !== null ? fallback : key;
    }

    if (variables && typeof translation === 'string') {
        for (const varKey in variables) {
            const regex = new RegExp(`\\{${varKey}\\}`, 'g');
            translation = translation.replace(regex, variables[varKey]);
        }
    }
    return translation || (fallback !== null ? fallback : key);
}

function updateDynamicUIText() {
    document.title = t('appName');

    const inventoryPanelTitle = document.querySelector('.inventory .panel-toggle > span:first-child');
    if (inventoryPanelTitle) {
        inventoryPanelTitle.innerHTML = t('gameInterface.inventoryPanel.title', {
            count: `<span id="inventory-count">${player && player.inventory ? Object.keys(player.inventory).length : 0}</span>`,
            capacity: `<span id="inventory-capacity">${player ? player.inventoryCapacity : 10}</span>`
        });
    }
    const charPanelTitle = document.querySelector('.character-sheet .panel-toggle > span:first-child');
    if (charPanelTitle) {
        charPanelTitle.textContent = t('gameInterface.characterPanel.title');
    }
    const questPanelTitle = document.querySelector('.quests .panel-toggle > span:first-child');
    if (questPanelTitle) {
        questPanelTitle.textContent = t('gameInterface.questPanel.title');
    }
    const skillsPanelTitle = document.querySelector('.skills-panel .panel-toggle > span:first-child');
    if (skillsPanelTitle) {
        skillsPanelTitle.textContent = t('gameInterface.skillsPanel.title');
    }
    const mapPanelTitle = document.querySelector('.map-panel .panel-toggle > span:first-child');
    if (mapPanelTitle) {
        mapPanelTitle.textContent = t('gameInterface.mapPanel.title');
    }
    const environmentPanelTitle = document.querySelector('.environment-panel .panel-toggle > span:first-child'); // Р СңР СӣР вҖҷР СӣР вҖў
    if (environmentPanelTitle) {
        environmentPanelTitle.textContent = t('gameInterface.environmentPanel.title');
    }
    const calcLogPanelTitle = document.querySelector('.calculation-log-panel .panel-toggle > span:first-child');
    if (calcLogPanelTitle) {
        calcLogPanelTitle.textContent = t('gameInterface.calcLogPanel.title');
    }

    const echoMemoryPanelTitle = document.querySelector('.echo-memory-panel .panel-toggle > span:first-child');
    if (echoMemoryPanelTitle) {
        echoMemoryPanelTitle.textContent = t('gameInterface.echoMemoryPanel.title');
    }
    const worldChroniclesPanelTitle = document.querySelector('.world-chronicles-panel .panel-toggle > span:first-child');
    if (worldChroniclesPanelTitle) {
        worldChroniclesPanelTitle.textContent = t('gameInterface.worldChroniclesPanel.title');
    }
    const tradeJournalPanelTitle = document.querySelector('.trade-journal-panel .panel-toggle > span:first-child');
    if (tradeJournalPanelTitle) {
        tradeJournalPanelTitle.textContent = t('gameInterface.tradeJournalPanel.title', null, 'Р СһР С•РЎРӮР С–Р С•Р РҶРЎвҖ№Р в„– Р вҖ“РЎС“РЎРӮР Р…Р В°Р В»');
    }
    const portPanelTitle = document.querySelector('.port-panel .panel-toggle > span:first-child');
    if (portPanelTitle) {
        portPanelTitle.textContent = t('gameInterface.portPanel.title', null, 'Р СҹР С•РЎРӮРЎвҖҡ');
    }
    const clearEchoBtn = document.getElementById('clear-echo-memory-btn');
    if (clearEchoBtn) {
        clearEchoBtn.textContent = t('gameInterface.echoMemoryPanel.clearButton');
    }
    const calcLogEmpty = calculationLog ? calculationLog.querySelector('p[data-i18n="gameInterface.calcLogPanel.empty"]') : null;
    if (calcLogEmpty && calculationLog.children.length === 1 && calculationLog.firstElementChild === calcLogEmpty) {
        calcLogEmpty.textContent = t('gameInterface.calcLogPanel.empty');
    }

    statIncreaseButtons.forEach(button => {
        const stat = button.getAttribute('data-stat');
        if (stat) {
            button.title = t('gameInterface.characterPanel.increaseStatTooltip', { statName: stat.toUpperCase() });
        }
    });

    const maxManual = document.getElementById('max-manual-saves');
    const maxAuto = document.getElementById('max-auto-saves');
    const manualTitleSpan = document.querySelector('#load-game-screen h2:nth-of-type(1) span[data-i18n]');
    const autoTitleSpan = document.querySelector('#load-game-screen h2:nth-of-type(2) span[data-i18n]');

    if (maxManual) maxManual.textContent = MAX_MANUAL_SAVES;
    if (maxAuto) maxAuto.textContent = MAX_AUTO_SAVES;
    if (manualTitleSpan) manualTitleSpan.innerHTML = t('loadGame.manualSavesTitle', { max: `<span id="max-manual-saves">${MAX_MANUAL_SAVES}</span>` });
    if (autoTitleSpan) autoTitleSpan.innerHTML = t('loadGame.autoSavesTitle', { max: `<span id="max-auto-saves">${MAX_AUTO_SAVES}</span>` });

    if (typeof populateRacesUI === 'function' && window.RACES_DATA) populateRacesUI(window.RACES_DATA);
    if (typeof populateClassesUI === 'function' && window.CLASSES_DATA) populateClassesUI(window.CLASSES_DATA);

    if (player && gameInterface && gameInterface.classList.contains('active-screen')) {
        if (gameTitle) gameTitle.textContent = t('appName') + ` | ${player.name}`;
    } else if (mainMenu && mainMenu.classList.contains('active-screen')) {
        const mainMenuTitle = mainMenu.querySelector('h1');
        if (mainMenuTitle) mainMenuTitle.textContent = t('mainMenu.title');
        if (gameTitle) gameTitle.textContent = t('appName');
    } else {
        if (gameTitle) gameTitle.textContent = t('appName');
    }

    if (inventoryList && inventoryList.children.length === 1 && inventoryList.firstElementChild.tagName === 'LI') {
        const li = inventoryList.firstElementChild;
        if (Object.keys(player?.inventory || {}).length === 0) {
            li.textContent = t('gameInterface.inventoryPanel.empty');
            li.removeAttribute('title');
            li.style.cursor = 'default';
        }
    }
    if (questList && questList.children.length === 1 && questList.firstElementChild.tagName === 'LI') {
        const li = questList.firstElementChild;
        if (Object.keys(player?.quests || {}).filter(q => player.quests[q].status === 'active').length === 0) {
            li.textContent = t('gameInterface.questPanel.empty');
        }
    }
    if (skillsList && skillsList.children.length === 1 && skillsList.firstElementChild.tagName === 'LI') {
        const li = skillsList.firstElementChild;
        if (Object.keys(player?.skills || {}).length === 0) {
            li.textContent = t('gameInterface.skillsPanel.empty');
            li.style.cursor = 'default';
        }
    }
    if (customLocationsList && customLocationsList.children.length === 1 && customLocationsList.firstElementChild.tagName === 'LI') {
        const li = customLocationsList.firstElementChild;
        if (Object.keys(player?.mapMarkers || {}).length === 0) {
            li.textContent = t('gameInterface.mapPanel.noCustom');
        }
    }
    if (environmentList && environmentList.children.length === 1 && environmentList.firstElementChild.tagName === 'LI') { // Р СңР СӣР вҖҷР СӣР вҖў
        const li = environmentList.firstElementChild;
        if (Object.keys(player?.visibleEntities || {}).length === 0) {
            li.textContent = t('gameInterface.environmentPanel.empty');
            li.style.cursor = 'default';
        }
    }
    // Р СҷР Р…Р С•Р С—Р С”Р С‘ Р СҳРЎС“Р В·РЎвҖ№Р С”Р С‘ Р С‘ TTS РЎС“Р Т‘Р В°Р В»Р ВөР Р…РЎвҖ№ Р С‘Р В· Р РҶР ВөРЎРӮРЎвҖҰР Р…Р ВөР в„– Р С—Р В°Р Р…Р ВөР В»Р С‘
    if (globalLocationsList && globalLocationsList.children.length === 1 && globalLocationsList.firstElementChild.tagName === 'LI') {
        const li = globalLocationsList.firstElementChild;
        if (Object.keys(globalLocations || {}).filter(key => key !== 'startLocation').length === 0) {
            if (worldLore.startsWith(t('error.prefix', 'Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°:')) || worldLore === "Р вҖ”Р В°Р С–РЎРӮРЎС“Р В·Р С”Р В° Р В»Р С•РЎРӮР В°...") {
                li.textContent = t('gameInterface.mapPanel.errorWorldData');
            } else {
                li.textContent = t('gameInterface.mapPanel.noGlobal');
            }
        }
    }
}

// --- Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р СҹРЎРӮР С‘Р В»Р С•Р В¶Р ВөР Р…Р С‘РЎРҸ ---
async function initializeApp() {

    // Р РҺР В»РЎС“РЎвӮ¬Р В°РЎвҖҡР ВөР В»РЎРҠ Р С—РЎРӮР С•Р С–РЎРӮР ВөРЎРғРЎРғР В° Р Р…Р В°РЎвҖҡР С‘Р РҶР Р…Р С•Р С–Р С• Р Т‘Р РҶР С‘Р В¶Р С”Р В°
    if (window.electronAPI && window.electronAPI.onNexusProgress) {
        window.electronAPI.onNexusProgress((message) => {
            const loadingText = document.getElementById('loading-text');
            if (loadingText) {
                let parsedMessage = message;
                const jsonStart = message.indexOf('{');
                if (jsonStart !== -1 && message.includes('"loc_key"')) {
                    const prefix = message.substring(0, jsonStart);
                    const jsonStr = message.substring(jsonStart);
                    parsedMessage = prefix + parseLocString(jsonStr);
                }
                loadingText.textContent = parsedMessage;
            }
            console.log("[Nexus Progress]", message);
        });
    }

    // Р РҺР В»РЎС“РЎвӮ¬Р В°РЎвҖҡР ВөР В»РЎРҠ РЎРӮР ВөР В°Р В»РЎвҖҡР В°Р в„–Р Сҳ-Р С•Р ВұР Р…Р С•Р РҶР В»Р ВөР Р…Р С‘Р в„– Р С•РЎвҖҡ Р Т‘Р РҶР С‘Р В¶Р С”Р В° РІРӮвҖқ Р СҳР С‘РЎРӮ Р С•Р ВұР Р…Р С•Р РҶР В»РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ Р СҳР С–Р Р…Р С•Р РҶР ВөР Р…Р Р…Р С•
    // FIX: Engine now sends lightweight delta updates (time, homeostasis, dirty items/containers)
    // instead of the entire world every 500ms. Full world is fetched on demand via getFullState.
    if (window.electronAPI && window.electronAPI.onNexusRealtimeUpdate) {
        window.electronAPI.onNexusRealtimeUpdate((data) => {
            if (!World) return;
            // Apply lightweight updates from engine delta
            if (data.time) World.time = data.time;
            if (data.homeostasis) World.homeostasis = data.homeostasis;
            if (data.tick !== undefined) World.tick = data.tick;
            if (data.current_day !== undefined) World.current_day = data.current_day;
            if (data.items) data.items.forEach(([k, v]) => ItemRegistry.set(k, v));
            if (data.containers) data.containers.forEach(([k, v]) => setContainer(k, v));
            if (data.deleted_items) data.deleted_items.forEach(id => ItemRegistry.delete(id));
            if (data.deleted_containers) data.deleted_containers.forEach(id => ContainerRegistry.delete(id));
            processMonsterQuests();

            if (data.trek_events && data.trek_events.length > 0) {
                LivingRoads.handleEvents(data.trek_events);
            }

            if (typeof updateEnvironmentPanel === 'function') updateEnvironmentPanel();
            if (typeof updateHoldingsDisplay === 'function') updateHoldingsDisplay();
            updateTimeDisplay();
        });
    }

    // в”Җв”Җ Mod API Engine Hook System в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // Connects C++ engine hook events to ModAPI.on() subscriptions

    // 1. Legacy hook_request (engine waits for world response)
    if (window.electronAPI && window.electronAPI.onNexusHookRequest) {
        window.electronAPI.onNexusHookRequest(async (hookName, world) => {
            if (window.ModAPI) await ModAPI.emit(hookName, { world });
            if (window.electronAPI.sendNexusHookResponse) {
                await window.electronAPI.sendNexusHookResponse(world);
            }
        });
    }

    // 2. New hook_event (fire-and-forget, specific event data only)
    if (window.electronAPI && window.electronAPI.onNexusHookEvent) {
        window.electronAPI.onNexusHookEvent(async (hookName, data) => {
            if (window.ModAPI) await ModAPI.emit(hookName, data);
        });
    }
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    console.log("Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р С—РЎРӮР С‘Р В»Р С•Р В¶Р ВөР Р…Р С‘РЎРҸ...");

    currentApiProvider = localStorage.getItem('apiProvider') || 'gemini';
    usePromptCaching = localStorage.getItem('usePromptCaching') !== 'false';
    useThinkingMode = localStorage.getItem('useThinkingMode') === 'true';
    thinkingBudget = parseInt(localStorage.getItem('thinkingBudget')) || 2048;
    reasoningEffort = localStorage.getItem('reasoningEffort') || 'medium';
    allowNSFW = localStorage.getItem('allowNSFW') === 'true';
    eroticIntensityLevel = parseInt(localStorage.getItem('eroticIntensityLevel')) || 2;
    try {
        eroticPreferences = JSON.parse(localStorage.getItem('eroticPreferences')) || {
            pregnancyRisk: true,
            diseaseRisk: true,
            reputationConsequences: true,
            pornoMode: false
        };
    } catch (e) {
        eroticPreferences = { pregnancyRisk: true, diseaseRisk: true, reputationConsequences: true, pornoMode: false };
    }
    try { geminiApiKeys = JSON.parse(localStorage.getItem('geminiApiKeys')) || []; } catch (e) { geminiApiKeys = []; }
    geminiApiKey = geminiApiKeys.length > 0 ? geminiApiKeys[0] : '';
    geminiModelId = localStorage.getItem('geminiModelId') || 'gemini-3.1-flash-lite-preview';
    llmostApiKey = localStorage.getItem('llmostApiKey') || '';
    llmostModelId = localStorage.getItem('llmostModelId') || 'openai/gpt-4';
    openrouterApiKey = localStorage.getItem('openrouterApiKey') || '';
    openrouterModelId = localStorage.getItem('openrouterModelId') || 'anthropic/claude-3-haiku';
    deepseekApiKey = localStorage.getItem('deepseekApiKey') || '';
    deepseekModelId = localStorage.getItem('deepseekModelId') || 'deepseek-chat';
    omnirouteApiKey = localStorage.getItem('omnirouteApiKey') || '';
    omnirouteModelId = localStorage.getItem('omnirouteModelId') || 'anthropic/claude-3-sonnet';
    omnirouteBaseUrl = localStorage.getItem('omnirouteBaseUrl') || 'https://api.omniroute.ai/v1/chat/completions';
    localApiUrl = localStorage.getItem('localApiUrl') || 'http://localhost:1234/v1/chat/completions';
    localModelId = localStorage.getItem('localModelId') || 'local-model';
    imgApiProvider = localStorage.getItem('imgApiProvider') || 'pollinations';
    imgApiKey = localStorage.getItem('imgApiKey') || '';
    
    aiPlayerProvider = localStorage.getItem('aiPlayerProvider') || 'openrouter';
    aiPlayerModelId = localStorage.getItem('aiPlayerModelId') || 'google/gemma-2-9b-it:free';
    aiPlayerApiKey = localStorage.getItem('aiPlayerApiKey') || '';
    aiPlayerLocalUrl = localStorage.getItem('aiPlayerLocalUrl') || 'http://localhost:1234/v1/chat/completions';
    aiPlayerTurnLimit = parseInt(localStorage.getItem('aiPlayerTurnLimit')) || 20;

    imgModelId = localStorage.getItem('imgModelId') || 'dall-e-3';
    enableImageGeneration = localStorage.getItem('enableImageGeneration') !== 'false';
    enableLocalMap = localStorage.getItem('enableLocalMap') !== 'false';
    enableDeepSetup = localStorage.getItem('enableDeepSetup') === 'true';

    initSettingsUI();

    // Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ ModKit Р вҖқР Сӣ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ Р В»Р С•РЎРӮР В° Р С‘ Р В»Р С•Р С”Р В°РЎвҖ Р С‘Р в„–
    if (typeof initModKit === 'function') {
        await initModKit();
    }

    await loadLanguagesConfig();
    currentLanguage = localStorage.getItem(LANGUAGE_STORAGE_KEY) || DEFAULT_LANGUAGE;
    if (!availableLanguages[currentLanguage]) {
        currentLanguage = DEFAULT_LANGUAGE;
    }
    document.documentElement.lang = currentLanguage;
    if (languageSelect) {
        languageSelect.value = currentLanguage;
    }
    await loadTranslations(currentLanguage);
    applyTranslations();

        await loadTileSet();

    const results = await Promise.allSettled([
        (typeof window.ensureRuntimeDataLoaded === 'function'
            ? window.ensureRuntimeDataLoaded().then(() => syncRuntimeRegistries())
            : Promise.resolve()),
        loadLore(DEFAULT_WORLD_ID, currentLanguage),
        loadGlobalLocations(DEFAULT_WORLD_ID, currentLanguage),
        loadSkillsReference(DEFAULT_WORLD_ID, currentLanguage),
        loadEnvironmentCommandsGuide(DEFAULT_WORLD_ID, currentLanguage),
        loadItemsReference(),
        loadCombatSystemRules(),
        loadPredefinedEffects(),
        loadPromptFromFile('auto_tester').then(t => autoTesterPromptTemplate = t)
    ]);

    const failedLoads = results.filter(result => result.status === 'rejected');

    if (failedLoads.length > 0) {
        console.error("Р СҷР В Р ВҳР СһР ВҳР В§Р вҖўР РҺР СҷР С’Р РҮ Р СӣР РҒР ВҳР вҖҳР СҷР С’: Р СңР Вө РЎС“Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С‘РЎвҖҡРЎРҠ Р С•РЎРғР Р…Р С•Р РҶР Р…РЎвҖ№Р Вө РЎвҖһР В°Р в„–Р В»РЎвҖ№ Р С‘Р С–РЎРӮРЎвҖ№:");
        failedLoads.forEach(result => console.error(result.reason));

        if (worldLore.startsWith('Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°:') || Object.keys(globalLocations).length === 0) {
            alert(t('error.worldLoadFailed', { worldId: DEFAULT_WORLD_ID }));
            return;
        }
    }

    updateMapDisplay();

    if (hasElectronAPI) {
        updateFSAStatus();
    } else if (fsaApiAvailable) {
        const handleFromDB = await getDirectoryHandleFromDB();
        if (handleFromDB && typeof handleFromDB.queryPermission === 'function') {
            directoryHandle = handleFromDB;
            if (await verifyDirectoryHandlePermission(directoryHandle)) {
                updateFSAStatus(directoryHandle, 'granted_from_db');
            } else {
                directoryHandle = null;
                await saveDirectoryHandleToDB(null);
                updateFSAStatus(null, 'permission_revoked_on_load');
            }
        }
    }

    updateApiKeyStatus();
    setupTTS();
    setupMusicPlayer();

    setActiveScreen('main-menu');
    setupEventListeners();

    // equipmentElements РЎвҖҡР ВөР С—Р ВөРЎРӮРЎРҠ Р В·Р В°Р С—Р С•Р В»Р Р…РЎРҸР ВөРЎвҖҡРЎРғРЎРҸ Р Т‘Р С‘Р Р…Р В°Р СҳР С‘РЎвҖЎР ВөРЎРғР С”Р С‘ Р РҶ populateEquipmentUI()

    startBackgroundChanger();
    updateDynamicUIText();

    console.log("Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р С—РЎРӮР С‘Р В»Р С•Р В¶Р ВөР Р…Р С‘РЎРҸ Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…Р В°.");
}


// --- Р РҲР СҹР В Р С’Р вҖҷР вҖәР вҖўР СңР ВҳР вҖў UI Р СңР С’Р РҺР СһР В Р СӣР вҖўР Сҷ ---
function initSettingsUI() {
    const providerSelect = document.getElementById('api-provider-select');
    const modelIdInput = document.getElementById('model-id-input');

    // Р СңР В°РЎвҖҰР С•Р Т‘Р С‘Р Сҳ Р РҶРЎРғР Вө Р С–РЎРӮРЎС“Р С—Р С—РЎвҖ№ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р ВөР С”
    const settingsGroups = {
        gemini: document.getElementById('gemini-settings-group'),
        llmost: document.getElementById('llmost-settings-group'),
        openrouter: document.getElementById('openrouter-settings-group'),
        deepseek: document.getElementById('deepseek-settings-group'),
        omniroute: document.getElementById('omniroute-settings-group'),
        local: document.getElementById('local-settings-group')
    };

    // Р СңР В°РЎвҖҰР С•Р Т‘Р С‘Р Сҳ Р РҶРЎРғР Вө Р С—Р С•Р В»РЎРҸ Р Т‘Р В»РЎРҸ API Р С”Р В»РЎРӢРЎвҖЎР ВөР в„–
    const keyInputs = {
        gemini: document.getElementById('gemini-api-key-input'),
        llmost: document.getElementById('llmost-api-key-input'),
        openrouter: document.getElementById('openrouter-api-key-input'),
        deepseek: document.getElementById('deepseek-api-key-input'),
        omniroute: document.getElementById('omniroute-api-key-input')
    };

    const localUrlInput = document.getElementById('local-url-input');

    // Р ВӨРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРҸ Р Т‘Р В»РЎРҸ Р С—Р ВөРЎРӮР ВөР С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘РЎРҸ Р РҶР С‘Р Т‘Р С‘Р СҳР С•РЎРғРЎвҖҡР С‘ Р С‘ Р В·Р В°Р С–РЎРӮРЎС“Р В·Р С”Р С‘ Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ
    const switchProviderView = (provider) => {
        // 1. Р РҺР С”РЎРӮРЎвҖ№Р РҶР В°Р ВөР Сҳ Р РҶРЎРғР Вө Р С–РЎРӮРЎС“Р С—Р С—РЎвҖ№
        Object.values(settingsGroups).forEach(group => {
            if (group) group.style.display = 'none';
        });

        // 2. Р СҹР С•Р С”Р В°Р В·РЎвҖ№Р РҶР В°Р ВөР Сҳ Р Р…РЎС“Р В¶Р Р…РЎС“РЎРӢ Р С–РЎРӮРЎС“Р С—Р С—РЎС“
        if (settingsGroups[provider]) {
            settingsGroups[provider].style.display = 'block';
        }

        // 3. Р вҖ”Р В°Р С–РЎРӮРЎС“Р В¶Р В°Р ВөР Сҳ Р С‘ РЎС“РЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөР Сҳ ID Р СҳР С•Р Т‘Р ВөР В»Р С‘ Р Т‘Р В»РЎРҸ Р РҶРЎвҖ№Р ВұРЎРӮР В°Р Р…Р Р…Р С•Р С–Р С• Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°
        let modelId = '';
        switch (provider) {
            case 'gemini': modelId = geminiModelId; break;
            case 'llmost': modelId = llmostModelId; break;
            case 'openrouter': modelId = openrouterModelId; break;
            case 'deepseek': modelId = deepseekModelId; break;
            case 'omniroute': modelId = omnirouteModelId; break;
            case 'local': modelId = localModelId; break; // Р вҖқР В»РЎРҸ LM Studio РЎРҢРЎвҖҡР С• РЎвҖҡР С•Р В¶Р Вө ID
            case 'dummy': modelId = 'dummy-test-model'; break;
        }
        if (modelIdInput) modelIdInput.value = modelId;

        // Р СӣР ВұР Р…Р С•Р РҶР В»РЎРҸР ВөР Сҳ Р В·Р В°Р С–Р С•Р В»Р С•Р РҶР С•Р С” Р Т‘Р В»РЎРҸ Р С—Р С•Р В»РЎРҸ Р РҶР РҶР С•Р Т‘Р В° Р СҳР С•Р Т‘Р ВөР В»Р С‘
        const modelLabel = document.querySelector('#model-id-input-group label');
        if (modelLabel) modelLabel.textContent = t('settingsMenu.modelIdLabelFor', { provider: provider.charAt(0).toUpperCase() + provider.slice(1) });
    };

    // Р РҲРЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөР Сҳ Р Р…Р В°РЎвҖЎР В°Р В»РЎРҠР Р…РЎвҖ№Р Вө Р В·Р Р…Р В°РЎвҖЎР ВөР Р…Р С‘РЎРҸ Р С‘Р В· Р С–Р В»Р С•Р ВұР В°Р В»РЎРҠР Р…РЎвҖ№РЎвҖҰ Р С—Р ВөРЎРӮР ВөР СҳР ВөР Р…Р Р…РЎвҖ№РЎвҖҰ
    if (providerSelect) providerSelect.value = currentApiProvider;
    const cachingCheckbox = document.getElementById('prompt-caching-checkbox');
    if (cachingCheckbox) cachingCheckbox.checked = usePromptCaching;

    const thinkingCheckbox = document.getElementById('thinking-mode-checkbox');
    const thinkingGroup = document.getElementById('thinking-settings-group');
    const thinkingSlider = document.getElementById('thinking-budget-slider');
    const thinkingValue = document.getElementById('thinking-budget-value');
    const effortSelect = document.getElementById('reasoning-effort-select');

    if (thinkingCheckbox && thinkingGroup) {
        thinkingCheckbox.checked = useThinkingMode;
        thinkingGroup.style.display = useThinkingMode ? 'block' : 'none';

        thinkingCheckbox.addEventListener('change', (e) => {
            thinkingGroup.style.display = e.target.checked ? 'block' : 'none';
        });
    }
    if (thinkingSlider && thinkingValue) {
        thinkingSlider.value = thinkingBudget;
        thinkingValue.textContent = thinkingBudget;
        thinkingSlider.addEventListener('input', (e) => {
            thinkingValue.textContent = e.target.value;
        });
    }
    if (effortSelect) {
        effortSelect.value = reasoningEffort;
    }

    const nsfwCheckbox = document.getElementById('nsfw-mode-checkbox');
    const eroticSettingsGroup = document.getElementById('erotic-settings-group');
    if (nsfwCheckbox) {
        nsfwCheckbox.checked = allowNSFW;

        // Р СҹР С•Р С”Р В°Р В·Р В°РЎвҖҡРЎРҠ/РЎРғР С”РЎРӮРЎвҖ№РЎвҖҡРЎРҠ РЎРҢРЎРӮР С•РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘Р Вө Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р в„–Р С”Р С‘ Р РҶ Р В·Р В°Р РҶР С‘РЎРғР С‘Р СҳР С•РЎРғРЎвҖҡР С‘ Р С•РЎвҖҡ NSFW
        if (eroticSettingsGroup) {
            eroticSettingsGroup.style.display = allowNSFW ? 'block' : 'none';
        }

        // Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡРЎвҖЎР С‘Р С” Р С‘Р В·Р СҳР ВөР Р…Р ВөР Р…Р С‘РЎРҸ NSFW РЎвҖЎР ВөР С”Р ВұР С•Р С”РЎРғР В°
        nsfwCheckbox.addEventListener('change', (e) => {
            if (eroticSettingsGroup) {
                eroticSettingsGroup.style.display = e.target.checked ? 'block' : 'none';
            }
        });
    }

    // Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ РЎРҢРЎРӮР С•РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘РЎвҖҰ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р ВөР С”
    const eroticIntensitySlider = document.getElementById('erotic-intensity-slider');
    const eroticIntensityValue = document.getElementById('erotic-intensity-value');
    const pregnancyRiskCheckbox = document.getElementById('pregnancy-risk-checkbox');
    const diseaseRiskCheckbox = document.getElementById('disease-risk-checkbox');
    const reputationConsequencesCheckbox = document.getElementById('reputation-consequences-checkbox');
    const pornoModeCheckbox = document.getElementById('porno-mode-checkbox');

    if (eroticIntensitySlider && eroticIntensityValue) {
        eroticIntensitySlider.value = eroticIntensityLevel;
        eroticIntensityValue.textContent = eroticIntensityLevel;
        eroticIntensitySlider.addEventListener('input', (e) => {
            eroticIntensityValue.textContent = e.target.value;
        });
    }

    if (pregnancyRiskCheckbox) pregnancyRiskCheckbox.checked = eroticPreferences.pregnancyRisk;
    if (diseaseRiskCheckbox) diseaseRiskCheckbox.checked = eroticPreferences.diseaseRisk;
    if (reputationConsequencesCheckbox) reputationConsequencesCheckbox.checked = eroticPreferences.reputationConsequences;
    if (pornoModeCheckbox) pornoModeCheckbox.checked = eroticPreferences.pornoMode;

    if (keyInputs.gemini) keyInputs.gemini.value = geminiApiKeys.join('\n');
    if (keyInputs.llmost) keyInputs.llmost.value = llmostApiKey;
    if (keyInputs.openrouter) keyInputs.openrouter.value = openrouterApiKey;
    if (keyInputs.deepseek) keyInputs.deepseek.value = deepseekApiKey;
    if (keyInputs.omniroute) keyInputs.omniroute.value = omnirouteApiKey;
    const omnirouteUrlInput = document.getElementById('omniroute-base-url-input');
    if (omnirouteUrlInput) omnirouteUrlInput.value = omnirouteBaseUrl;
    if (localUrlInput) localUrlInput.value = localApiUrl;

    // Load image settings
    const imgGenCheckbox = document.getElementById('enable-img-gen-checkbox');
    const deepSetupCheckbox = document.getElementById('enable-deep-setup-checkbox');
    if (deepSetupCheckbox) deepSetupCheckbox.checked = enableDeepSetup;
    
    if (imgGenCheckbox) imgGenCheckbox.checked = enableImageGeneration;
    const imgProviderSelect = document.getElementById('img-provider-select');
    if (imgProviderSelect) imgProviderSelect.value = imgApiProvider;
    const imgModelInput = document.getElementById('img-model-input');
    if (imgModelInput) imgModelInput.value = imgModelId;
    const imgKeyInput = document.getElementById('img-key-input');
    
    const aiPlayerProvSelect = document.getElementById('ai-player-provider-select');
    if (aiPlayerProvSelect) aiPlayerProvSelect.value = aiPlayerProvider;
    const aiPlayerModelInp = document.getElementById('ai-player-model-input');
    if (aiPlayerModelInp) aiPlayerModelInp.value = aiPlayerModelId;
    const aiPlayerKeyInp = document.getElementById('ai-player-key-input');
    if (aiPlayerKeyInp) {
        aiPlayerKeyInp.value = aiPlayerProvider === 'local' ? aiPlayerLocalUrl : aiPlayerApiKey;
                const aiPlayerLimitInp = document.getElementById('ai-player-turn-limit');
        if (aiPlayerLimitInp) aiPlayerLimitInp.value = aiPlayerTurnLimit;

if (aiPlayerProvSelect) {
            aiPlayerProvSelect.addEventListener('change', () => {
                aiPlayerKeyInp.value = aiPlayerProvSelect.value === 'local' ? aiPlayerLocalUrl : aiPlayerApiKey;
            });
        }
    }

    if (imgKeyInput) imgKeyInput.value = imgApiKey;

    // Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р РҶР Р…РЎС“РЎвҖҡРЎРӮР ВөР Р…Р Р…Р С‘РЎвҖҰ Р РҶР С”Р В»Р В°Р Т‘Р С•Р С” (Sub-tabs) РЎвҖҡР С•Р В»РЎРҠР С”Р С• Р Т‘Р В»РЎРҸ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р ВөР С”
    const settingsMenuEl = document.getElementById('settings-menu');
    if (settingsMenuEl) {
        const subTabBtns = settingsMenuEl.querySelectorAll('.sub-tab-btn');
        const subTabContents = settingsMenuEl.querySelectorAll('.sub-tab-content');
        subTabBtns.forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.preventDefault();
                subTabBtns.forEach(b => b.classList.remove('active'));
                subTabContents.forEach(c => c.classList.remove('active'));
                btn.classList.add('active');
                const targetId = btn.getAttribute('data-subtab');
                if (targetId) document.getElementById(targetId).classList.add('active');
            });
        });
    }


    // Р РҲРЎРғРЎвҖҡР В°Р Р…Р В°Р РҶР В»Р С‘Р РҶР В°Р ВөР Сҳ Р С—Р ВөРЎРӮР РҶР С•Р Р…Р В°РЎвҖЎР В°Р В»РЎРҠР Р…Р С•Р Вө Р С•РЎвҖҡР С•Р ВұРЎРӮР В°Р В¶Р ВөР Р…Р С‘Р Вө
    switchProviderView(currentApiProvider);

    // Р вҖҷР ВөРЎвӮ¬Р В°Р ВөР Сҳ Р С•Р ВұРЎРӮР В°Р ВұР С•РЎвҖҡРЎвҖЎР С‘Р С” РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ
    if (providerSelect) {
        providerSelect.addEventListener('change', () => {
            currentApiProvider = providerSelect.value;
            switchProviderView(currentApiProvider);
        });
    }

    // Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р РҶР С”Р В»Р В°Р Т‘Р С•Р С” Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р ВөР С”
    const tabBtns = document.querySelectorAll('.settings-tab-btn');
    const tabContents = document.querySelectorAll('.settings-tab-content');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            tabBtns.forEach(b => b.classList.remove('active'));
            tabContents.forEach(c => c.classList.remove('active'));
            btn.classList.add('active');
            document.getElementById(btn.dataset.tab).classList.add('active');
        });
    });

    // Р ВҳР Р…Р С‘РЎвҖ Р С‘Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ Р С—Р С•Р В»Р В·РЎС“Р Р…Р С”Р С•Р РҶ Р В·Р РҶРЎС“Р С”Р В°
        const autoSaveSelect = document.getElementById('autosave-interval-select');
    if (autoSaveSelect) autoSaveSelect.value = autoSaveIntervalMs.toString();


const musicSlider = document.getElementById('music-volume-slider');
    const musicValue = document.getElementById('music-volume-value');
    const sfxSlider = document.getElementById('sfx-volume-slider');
    const sfxValue = document.getElementById('sfx-volume-value');

    if (musicSlider) {
        musicSlider.value = Math.round(musicVolume * 100);
        musicValue.textContent = musicSlider.value + '%';
        musicSlider.addEventListener('input', (e) => {
            musicVolume = e.target.value / 100;
            musicValue.textContent = e.target.value + '%';
            if (audioPlayer) audioPlayer.volume = musicVolume;
        });
    }

    if (sfxSlider) {
        sfxSlider.value = Math.round(sfxVolume * 100);
        sfxValue.textContent = sfxSlider.value + '%';
        sfxSlider.addEventListener('input', (e) => {
            sfxVolume = e.target.value / 100;
            sfxValue.textContent = e.target.value + '%';
            updateSfxVolume();
            playSfx(clickSfx); // Р СҹРЎРӮР С•Р С‘Р С–РЎРӮРЎвҖ№Р РҶР В°Р ВөР Сҳ Р В·Р РҶРЎС“Р С” Р Т‘Р В»РЎРҸ РЎвҖҡР ВөРЎРғРЎвҖҡР В° Р С–РЎРӮР С•Р СҳР С”Р С•РЎРғРЎвҖҡР С‘
        });
    }
}

// --- Р РҺР СӣР ТҗР В Р С’Р СңР вҖўР СңР ВҳР вҖў Р СңР С’Р РҺР СһР В Р СӣР вҖўР Сҷ ---
// Р вҖ”Р В°Р СҳР ВөР Р…Р С‘ РЎРғРЎвҖҡР В°РЎРӮРЎС“РЎРӢ РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРӢ saveApiKey Р Р…Р В° РЎРҢРЎвҖҡРЎС“ (Р С‘Р В»Р С‘ Р С•Р ВұР Р…Р С•Р РҶР С‘ РЎРғР В»РЎС“РЎвӮ¬Р В°РЎвҖҡР ВөР В»РЎРҠ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘РЎРҸ)
function getFriendlyApiErrorMessage(status, rawText) {
    // Р ТҗР В°РЎРӮР Т‘Р С”Р С•Р Т‘Р Р…РЎвҖ№Р в„– РЎРғР В»Р С•Р РҶР В°РЎРӮРЎРҠ Р Р…Р В° РЎРғР В»РЎС“РЎвҖЎР В°Р в„– РЎРғР ВұР С•РЎРҸ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳРЎвҖ№ Р В»Р С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘Р С‘ (t())
    const fallbacks = {
        400: "Р СңР ВөР РҶР ВөРЎРӮР Р…РЎвҖ№Р в„– Р В·Р В°Р С—РЎРӮР С•РЎРғ. Р вҖҷР С•Р В·Р СҳР С•Р В¶Р Р…Р С•, Р С”Р С•Р Р…РЎвҖҡР ВөР С”РЎРғРЎвҖҡ РЎРғР В»Р С‘РЎвӮ¬Р С”Р С•Р Сҳ Р РҶР ВөР В»Р С‘Р С” Р С‘Р В»Р С‘ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Р Р…Р Вө Р С—Р С•Р Т‘Р Т‘Р ВөРЎРӮР В¶Р С‘Р РҶР В°Р ВөРЎвҖҡ Р РҶРЎвҖ№Р ВұРЎРӮР В°Р Р…Р Р…РЎвҖ№Р Вө Р С—Р В°РЎРӮР В°Р СҳР ВөРЎвҖҡРЎРӮРЎвҖ№.",
        401: "Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В°Р РҶРЎвҖҡР С•РЎРӮР С‘Р В·Р В°РЎвҖ Р С‘Р С‘. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө Р С—РЎРӮР В°Р РҶР С‘Р В»РЎРҠР Р…Р С•РЎРғРЎвҖҡРЎРҠ API Р С”Р В»РЎРӢРЎвҖЎР В°.",
        402: "Р СңР ВөР Т‘Р С•РЎРғРЎвҖҡР В°РЎвҖҡР С•РЎвҖЎР Р…Р С• РЎРғРЎРӮР ВөР Т‘РЎРғРЎвҖҡР РҶ Р Р…Р В° Р ВұР В°Р В»Р В°Р Р…РЎРғР Вө Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°. Р СҹР С•Р С—Р С•Р В»Р Р…Р С‘РЎвҖҡР Вө РЎРғРЎвҖЎРЎвҖҳРЎвҖҡ Р С‘Р В»Р С‘ РЎРғР СҳР ВөР Р…Р С‘РЎвҖҡР Вө Р СҳР С•Р Т‘Р ВөР В»РЎРҠ.",
        403: "Р вҖқР С•РЎРғРЎвҖҡРЎС“Р С— Р В·Р В°Р С—РЎРӮР ВөРЎвҖ°Р ВөР Р…. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө API Р С”Р В»РЎРӢРЎвҖЎ Р С‘Р В»Р С‘ Р С•Р С–РЎРӮР В°Р Р…Р С‘РЎвҖЎР ВөР Р…Р С‘РЎРҸ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°.",
        429: "Р РҺР В»Р С‘РЎвӮ¬Р С”Р С•Р Сҳ Р СҳР Р…Р С•Р С–Р С• Р В·Р В°Р С—РЎРӮР С•РЎРғР С•Р РҶ (Р вҖәР С‘Р СҳР С‘РЎвҖҡ Р С‘РЎРғРЎвҖЎР ВөРЎРӮР С—Р В°Р Р…). Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• Р ВұР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р В°РЎРҸ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ, Р С—Р С•Р Т‘Р С•Р В¶Р Т‘Р С‘РЎвҖҡР Вө Р Р…Р ВөР СҳР Р…Р С•Р С–Р С• Р С‘Р В»Р С‘ РЎРғР СҳР ВөР Р…Р С‘РЎвҖҡР Вө Р СҳР С•Р Т‘Р ВөР В»РЎРҠ.",
        500: "Р вҖҷР Р…РЎС“РЎвҖҡРЎРӮР ВөР Р…Р Р…РЎРҸРЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎРӮР РҶР ВөРЎРӮР В° Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ.",
        502: "Р СҹР В»Р С•РЎвҖҰР С•Р в„– РЎвӮ¬Р В»РЎРӢР В·. Р РҺР ВөРЎРӮР РҶР ВөРЎРӮ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ Р РҶРЎРӮР ВөР СҳР ВөР Р…Р Р…Р С• Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р ВөР Р….",
        503: "Р РҺР ВөРЎРӮР РҶР ВөРЎРӮ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ Р С—Р ВөРЎРӮР ВөР С–РЎРӮРЎС“Р В¶Р ВөР Р…. Р СҹР С•Р РҶРЎвҖҡР С•РЎРӮР С‘РЎвҖҡР Вө Р С—Р С•Р С—РЎвҖ№РЎвҖҡР С”РЎС“ Р С—Р С•Р В·Р В¶Р Вө.",
        504: "Р вҖҷРЎРӮР ВөР СҳРЎРҸ Р С•Р В¶Р С‘Р Т‘Р В°Р Р…Р С‘РЎРҸ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° Р С•РЎвҖҡ РЎРғР ВөРЎРӮР РҶР ВөРЎРӮР В° Р ВҳР Вҳ Р С‘РЎРғРЎвҖҡР ВөР С”Р В»Р С•.",
        'network': "Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎвҖҡР С‘. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө Р С—Р С•Р Т‘Р С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р Вө Р С” Р С‘Р Р…РЎвҖҡР ВөРЎРӮР Р…Р ВөРЎвҖҡРЎС“ Р С‘Р В»Р С‘ Р С•РЎвҖҡР С”Р В»РЎРӢРЎвҖЎР С‘РЎвҖҡР Вө VPN/AdBlock."
    };
    
    let friendlyText = t(`apiErrors.${status}`, null, "");
    // Р вҖўРЎРғР В»Р С‘ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘ Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р… Р С‘Р В»Р С‘ Р РҶР ВөРЎРӮР Р…РЎС“Р В» РЎРғР В°Р Сҳ Р С”Р В»РЎРӢРЎвҖЎ
    if (!friendlyText || friendlyText === `apiErrors.${status}`) {
        friendlyText = fallbacks[status] || t('apiErrors.unknown', null, "Р СңР ВөР С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР Р…Р В°РЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° API.");
    }
    return `${friendlyText}\n\n[Р СҷР С•Р Т‘: ${status}] Р вҖқР ВөРЎвҖҡР В°Р В»Р С‘: ${rawText}`;
}


async function pingProvider() {
    const provider = document.getElementById('api-provider-select').value;
    const resultDiv = document.getElementById('ping-provider-result');
    const btn = document.getElementById('ping-provider-btn');
    if (!resultDiv || !btn) return;

    resultDiv.style.display = 'block';
    resultDiv.innerHTML = '<i class="fas fa-spinner fa-spin" style="color: #f39c12;"></i> Р СҹР С‘Р Р…Р С– Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°...';
    btn.disabled = true;

    let url = ''; let headers = {}; let key = '';
    try {
        switch (provider) {
            case 'gemini':
                key = document.getElementById('gemini-api-key-input').value.trim() || geminiApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = `https://generativelanguage.googleapis.com/v1beta/models?key=${key}`;
                break;
            case 'openrouter':
                key = document.getElementById('openrouter-api-key-input').value.trim() || openrouterApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://openrouter.ai/api/v1/auth/key";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'llmost':
                key = document.getElementById('llmost-api-key-input').value.trim() || llmostApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://llmost.ru/api/v1/models";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'deepseek':
                key = document.getElementById('deepseek-api-key-input').value.trim() || deepseekApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://api.deepseek.com/models";
                headers['Authorization'] = `Bearer ${key}`;
                headers['Accept'] = 'application/json';
                break;
            case 'omniroute':
                key = document.getElementById('omniroute-api-key-input').value.trim() || omnirouteApiKey;
                let baseUrl = document.getElementById('omniroute-base-url-input').value.trim() || omnirouteBaseUrl;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = baseUrl.replace(/\/chat\/completions\/?$/, '/models');
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'local':
                let lUrl = document.getElementById('local-url-input').value.trim() || localApiUrl;
                url = lUrl.replace(/\/chat\/completions\/?$/, '/models');
                break;
            case 'dummy':
                resultDiv.innerHTML = '<span style="color: #2ecc71;"><i class="fas fa-check"></i> Р вҖ”Р В°Р С–Р В»РЎС“РЎвӮ¬Р С”Р В° Р С–Р С•РЎвҖҡР С•Р РҶР В°!</span>';
                btn.disabled = false;
                setTimeout(() => resultDiv.style.display = 'none', 3000);
                return;
        }

        const response = await fetch(url, { method: 'GET', headers: headers });
        if (response.ok) {
            resultDiv.innerHTML = `<span style="color: #2ecc71;"><i class="fas fa-check"></i> Р РҺР С•Р ВөР Т‘Р С‘Р Р…Р ВөР Р…Р С‘Р Вө РЎС“РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…Р С•! Р СҷР В»РЎРӢРЎвҖЎ Р РҶР В°Р В»Р С‘Р Т‘Р ВөР Р….</span>`;
        } else {
            const errText = await response.text();
            let shortMsg = t(`apiErrors.${response.status}`, null, `Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° ${response.status}`);
            resultDiv.innerHTML = `<span style="color: #e74c3c;" title="${errText.replace(/"/g, '&quot;')}"><i class="fas fa-times"></i> ${shortMsg} (Р СҷР С•Р Т‘: ${response.status})</span>`;
        }
    } catch (e) {
        let shortMsg = e.message.includes('fetch') ? t('apiErrors.network', null, 'Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎвҖҡР С‘') : e.message;
        resultDiv.innerHTML = `<span style="color: #e74c3c;"><i class="fas fa-times"></i> ${shortMsg}</span>`;
    } finally {
        btn.disabled = false;
    }
}

async function fetchModels() {
    const provider = document.getElementById('api-provider-select').value;
    const btn = document.getElementById('fetch-models-btn');
    if (!btn) return;

    const originalIcon = btn.innerHTML;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i>';
    btn.disabled = true;

    let url = ''; let headers = {}; let key = ''; let isGemini = false;
    try {
        switch (provider) {
            case 'gemini':
                key = document.getElementById('gemini-api-key-input').value.trim() || geminiApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = `https://generativelanguage.googleapis.com/v1beta/models?key=${key}`;
                isGemini = true;
                break;
            case 'openrouter':
                key = document.getElementById('openrouter-api-key-input').value.trim() || openrouterApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://openrouter.ai/api/v1/models";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'llmost':
                key = document.getElementById('llmost-api-key-input').value.trim() || llmostApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://llmost.ru/api/v1/models";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'deepseek':
                key = document.getElementById('deepseek-api-key-input').value.trim() || deepseekApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://api.deepseek.com/models";
                headers['Authorization'] = `Bearer ${key}`;
                headers['Accept'] = 'application/json';
                break;
            case 'omniroute':
                key = document.getElementById('omniroute-api-key-input').value.trim() || omnirouteApiKey;
                let baseUrl = document.getElementById('omniroute-base-url-input').value.trim() || omnirouteBaseUrl;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = baseUrl.replace(/\/chat\/completions\/?$/, '/models');
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'local':
                let lUrl = document.getElementById('local-url-input').value.trim() || localApiUrl;
                url = lUrl.replace(/\/chat\/completions\/?$/, '/models');
                break;
            case 'dummy':
                if (typeof showCustomAlert === 'function') showCustomAlert("Р вҖ”Р В°Р С–Р В»РЎС“РЎвӮ¬Р С”Р В° Р Р…Р Вө Р С‘Р СҳР ВөР ВөРЎвҖҡ РЎРғР С—Р С‘РЎРғР С”Р В° Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„–.");
                return;
        }

        const response = await fetch(url, { method: 'GET', headers: headers });
        if (response.ok) {
            const data = await response.json();
            let models = [];
            
            if (isGemini && data.models) {
                models = data.models.map(m => {
                    let id = m.name.replace('models/', '');
                    let type = 'text';
                    if (id.includes('vision') || id.includes('image') || id.includes('nano-banana')) type = 'vision';
                    else if (id.includes('tts') || id.includes('audio')) type = 'audio';
                    else if (id.includes('embed')) type = 'embedding';
                    
                    let isThinking = id.includes('thinking') || id.includes('reasoning');
                    let isCaching = id.includes('gemini-1.5') || id.includes('gemini-2.0');

                    return {
                        id: id, name: m.displayName || id, desc: m.description || 'Р СӣРЎвҖһР С‘РЎвҖ Р С‘Р В°Р В»РЎРҠР Р…Р В°РЎРҸ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Google Gemini.',
                        type: type, free: false, context: m.inputTokenLimit || null, priceText: 'Р вҖәР С‘Р СҳР С‘РЎвҖҡРЎвҖ№ API (Free Tier)',
                        caching: isCaching, thinking: isThinking
                    };
                });
            } else if (provider === 'openrouter' && data.data) {
                models = data.data.map(m => {
                    let type = 'text';
                    if (m.id.includes('vision') || (m.architecture && m.architecture.modality && m.architecture.modality.includes('image'))) type = 'vision';
                    
                    let p_prompt = m.pricing && m.pricing.prompt ? parseFloat(m.pricing.prompt) * 1000000 : -1;
                    let p_comp = m.pricing && m.pricing.completion ? parseFloat(m.pricing.completion) * 1000000 : -1;
                    let isFree = (p_prompt === 0 && p_comp === 0) || m.id.endsWith(':free');
                    let priceText = '';
                    if (isFree) priceText = 'Р вҖҳР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р С•';
                    else if (p_prompt >= 0 && p_comp >= 0) {
                        let pr_str = p_prompt < 0.01 ? p_prompt.toFixed(4) : p_prompt.toFixed(2);
                        let cmp_str = p_comp < 0.01 ? p_comp.toFixed(4) : p_comp.toFixed(2);
                        priceText = `$${pr_str} / $${cmp_str} Р В·Р В° 1M`;
                    } else priceText = 'Р СҹР В»Р В°РЎвҖҡР Р…Р В°РЎРҸ';
                    
                    let isCaching = m.architecture && m.architecture.prompt_caching;
                    let idLower = m.id.toLowerCase();
                    let isThinking = idLower.includes('r1') || idLower.includes('o1') || idLower.includes('o3') || idLower.includes('thinking') || idLower.includes('reasoning');

                    return {
                        id: m.id, name: m.name || m.id, desc: m.description || '', type: type, free: isFree,
                        context: m.context_length, priceText: priceText, caching: isCaching, thinking: isThinking
                    };
                });
            } else if (data.data && Array.isArray(data.data)) {
                models = data.data.map(m => {
                    let idLower = (m.id || "").toLowerCase();
                    let isThinking = idLower.includes('r1') || idLower.includes('o1') || idLower.includes('o3') || idLower.includes('thinking') || idLower.includes('reasoning');
                    return { id: m.id, name: m.name || m.id, desc: '', type: 'text', free: false, priceText: 'Р СҹР С• РЎвҖҡР В°РЎРӮР С‘РЎвҖһРЎС“ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°', caching: false, thinking: isThinking };
                });
            } else if (Array.isArray(data)) {
                models = data.map(m => {
                    let idLower = (m.id || m.name || "").toLowerCase();
                    let isThinking = idLower.includes('r1') || idLower.includes('o1') || idLower.includes('o3') || idLower.includes('thinking') || idLower.includes('reasoning');
                    return { id: m.id || m.name, name: m.name || m.id, desc: '', type: 'text', free: false, priceText: 'Р СҹР С• РЎвҖҡР В°РЎРӮР С‘РЎвҖһРЎС“ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°', caching: false, thinking: isThinking };
                });
            }

            models = models.filter(m => m.type !== 'embedding');

            if (models.length > 0) {
                showModelSelector(models);
            } else {
                if (typeof showCustomAlert === 'function') showCustomAlert("Р РҺР РҶРЎРҸР В·РЎРҠ Р ВөРЎРғРЎвҖҡРЎРҠ, Р Р…Р С• РЎРғР С—Р С‘РЎРғР С•Р С” Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„– Р С—РЎС“РЎРғРЎвҖҡ.");
            }
        } else {
            const errText = await response.text();
            if (typeof showCustomAlert === 'function') showCustomAlert(getFriendlyApiErrorMessage(response.status, errText));
        }
    } catch (e) {
        let shortMsg = e.message.includes('fetch') ? t('apiErrors.network', null, 'Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎвҖҡР С‘') : e.message;
        if (typeof showCustomAlert === 'function') showCustomAlert("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С—Р С•Р В»РЎС“РЎвҖЎР ВөР Р…Р С‘РЎРҸ РЎРғР С—Р С‘РЎРғР С”Р В° Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„–: " + shortMsg);
    } finally {
        btn.innerHTML = originalIcon;
        btn.disabled = false;
    }
}


function getFriendlyApiErrorMessage(status, rawText) {
    // Р ТҗР В°РЎРӮР Т‘Р С”Р С•Р Т‘Р Р…РЎвҖ№Р в„– РЎРғР В»Р С•Р РҶР В°РЎРӮРЎРҠ Р Р…Р В° РЎРғР В»РЎС“РЎвҖЎР В°Р в„– РЎРғР ВұР С•РЎРҸ РЎРғР С‘РЎРғРЎвҖҡР ВөР СҳРЎвҖ№ Р В»Р С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘Р С‘ (t())
    const fallbacks = {
        400: "Р СңР ВөР РҶР ВөРЎРӮР Р…РЎвҖ№Р в„– Р В·Р В°Р С—РЎРӮР С•РЎРғ. Р вҖҷР С•Р В·Р СҳР С•Р В¶Р Р…Р С•, Р С”Р С•Р Р…РЎвҖҡР ВөР С”РЎРғРЎвҖҡ РЎРғР В»Р С‘РЎвӮ¬Р С”Р С•Р Сҳ Р РҶР ВөР В»Р С‘Р С” Р С‘Р В»Р С‘ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Р Р…Р Вө Р С—Р С•Р Т‘Р Т‘Р ВөРЎРӮР В¶Р С‘Р РҶР В°Р ВөРЎвҖҡ Р РҶРЎвҖ№Р ВұРЎРӮР В°Р Р…Р Р…РЎвҖ№Р Вө Р С—Р В°РЎРӮР В°Р СҳР ВөРЎвҖҡРЎРӮРЎвҖ№.",
        401: "Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В°Р РҶРЎвҖҡР С•РЎРӮР С‘Р В·Р В°РЎвҖ Р С‘Р С‘. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө Р С—РЎРӮР В°Р РҶР С‘Р В»РЎРҠР Р…Р С•РЎРғРЎвҖҡРЎРҠ API Р С”Р В»РЎРӢРЎвҖЎР В°.",
        402: "Р СңР ВөР Т‘Р С•РЎРғРЎвҖҡР В°РЎвҖҡР С•РЎвҖЎР Р…Р С• РЎРғРЎРӮР ВөР Т‘РЎРғРЎвҖҡР РҶ Р Р…Р В° Р ВұР В°Р В»Р В°Р Р…РЎРғР Вө Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°. Р СҹР С•Р С—Р С•Р В»Р Р…Р С‘РЎвҖҡР Вө РЎРғРЎвҖЎРЎвҖҳРЎвҖҡ Р С‘Р В»Р С‘ РЎРғР СҳР ВөР Р…Р С‘РЎвҖҡР Вө Р СҳР С•Р Т‘Р ВөР В»РЎРҠ.",
        403: "Р вҖқР С•РЎРғРЎвҖҡРЎС“Р С— Р В·Р В°Р С—РЎРӮР ВөРЎвҖ°Р ВөР Р…. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө API Р С”Р В»РЎРӢРЎвҖЎ Р С‘Р В»Р С‘ Р С•Р С–РЎРӮР В°Р Р…Р С‘РЎвҖЎР ВөР Р…Р С‘РЎРҸ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°.",
        429: "Р РҺР В»Р С‘РЎвӮ¬Р С”Р С•Р Сҳ Р СҳР Р…Р С•Р С–Р С• Р В·Р В°Р С—РЎРӮР С•РЎРғР С•Р РҶ (Р вҖәР С‘Р СҳР С‘РЎвҖҡ Р С‘РЎРғРЎвҖЎР ВөРЎРӮР С—Р В°Р Р…). Р вҖўРЎРғР В»Р С‘ РЎРҢРЎвҖҡР С• Р ВұР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р В°РЎРҸ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ, Р С—Р С•Р Т‘Р С•Р В¶Р Т‘Р С‘РЎвҖҡР Вө Р Р…Р ВөР СҳР Р…Р С•Р С–Р С• Р С‘Р В»Р С‘ РЎРғР СҳР ВөР Р…Р С‘РЎвҖҡР Вө Р СҳР С•Р Т‘Р ВөР В»РЎРҠ.",
        500: "Р вҖҷР Р…РЎС“РЎвҖҡРЎРӮР ВөР Р…Р Р…РЎРҸРЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎРӮР РҶР ВөРЎРӮР В° Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ.",
        502: "Р СҹР В»Р С•РЎвҖҰР С•Р в„– РЎвӮ¬Р В»РЎРӢР В·. Р РҺР ВөРЎРӮР РҶР ВөРЎРӮ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ Р РҶРЎРӮР ВөР СҳР ВөР Р…Р Р…Р С• Р Р…Р ВөР Т‘Р С•РЎРғРЎвҖҡРЎС“Р С—Р ВөР Р….",
        503: "Р РҺР ВөРЎРӮР РҶР ВөРЎРӮ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В° Р ВҳР Вҳ Р С—Р ВөРЎРӮР ВөР С–РЎРӮРЎС“Р В¶Р ВөР Р…. Р СҹР С•Р РҶРЎвҖҡР С•РЎРӮР С‘РЎвҖҡР Вө Р С—Р С•Р С—РЎвҖ№РЎвҖҡР С”РЎС“ Р С—Р С•Р В·Р В¶Р Вө.",
        504: "Р вҖҷРЎРӮР ВөР СҳРЎРҸ Р С•Р В¶Р С‘Р Т‘Р В°Р Р…Р С‘РЎРҸ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° Р С•РЎвҖҡ РЎРғР ВөРЎРӮР РҶР ВөРЎРӮР В° Р ВҳР Вҳ Р С‘РЎРғРЎвҖҡР ВөР С”Р В»Р С•.",
        'network': "Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎвҖҡР С‘. Р СҹРЎРӮР С•Р РҶР ВөРЎРӮРЎРҠРЎвҖҡР Вө Р С—Р С•Р Т‘Р С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р Вө Р С” Р С‘Р Р…РЎвҖҡР ВөРЎРӮР Р…Р ВөРЎвҖҡРЎС“ Р С‘Р В»Р С‘ Р С•РЎвҖҡР С”Р В»РЎРӢРЎвҖЎР С‘РЎвҖҡР Вө VPN/AdBlock."
    };
    
    let friendlyText = t(`apiErrors.${status}`, null, "");
    // Р вҖўРЎРғР В»Р С‘ Р С—Р ВөРЎРӮР ВөР РҶР С•Р Т‘ Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р… Р С‘Р В»Р С‘ Р РҶР ВөРЎРӮР Р…РЎС“Р В» РЎРғР В°Р Сҳ Р С”Р В»РЎРӢРЎвҖЎ
    if (!friendlyText || friendlyText === `apiErrors.${status}`) {
        friendlyText = fallbacks[status] || t('apiErrors.unknown', null, "Р СңР ВөР С‘Р В·Р РҶР ВөРЎРғРЎвҖҡР Р…Р В°РЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° API.");
    }
    return `${friendlyText}\n\n[Р СҷР С•Р Т‘: ${status}] Р вҖқР ВөРЎвҖҡР В°Р В»Р С‘: ${rawText}`;
}


async function testApiConnection() {
    const provider = document.getElementById('api-provider-select').value;
    const resultDiv = document.getElementById('test-api-result');
    const btn = document.getElementById('test-api-connection-btn');

    if (!resultDiv || !btn) return;

    resultDiv.style.display = 'block';
    resultDiv.innerHTML = '<i class="fas fa-spinner fa-spin" style="color: #f39c12;"></i> Р СҹР С•Р Т‘Р С”Р В»РЎРӢРЎвҖЎР ВөР Р…Р С‘Р Вө...';
    btn.disabled = true;

    let url = '';
    let headers = {};
    let key = '';
    let isGemini = false;

    try {
        switch (provider) {
            case 'gemini':
                key = document.getElementById('gemini-api-key-input').value.trim() || geminiApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = `https://generativelanguage.googleapis.com/v1beta/models?key=${key}`;
                isGemini = true;
                break;
            case 'openrouter':
                key = document.getElementById('openrouter-api-key-input').value.trim() || openrouterApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://openrouter.ai/api/v1/models";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'llmost':
                key = document.getElementById('llmost-api-key-input').value.trim() || llmostApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://llmost.ru/api/v1/models";
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'deepseek':
                key = document.getElementById('deepseek-api-key-input').value.trim() || deepseekApiKey;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = "https://api.deepseek.com/models";
                headers['Authorization'] = `Bearer ${key}`;
                headers['Accept'] = 'application/json';
                break;
            case 'omniroute':
                key = document.getElementById('omniroute-api-key-input').value.trim() || omnirouteApiKey;
                let baseUrl = document.getElementById('omniroute-base-url-input').value.trim() || omnirouteBaseUrl;
                if (!key) throw new Error("Р СҷР В»РЎРӢРЎвҖЎ Р Р…Р Вө Р РҶР РҶР ВөР Т‘Р ВөР Р…");
                url = baseUrl.replace(/\/chat\/completions\/?$/, '/models');
                headers['Authorization'] = `Bearer ${key}`;
                break;
            case 'local':
                let lUrl = document.getElementById('local-url-input').value.trim() || localApiUrl;
                url = lUrl.replace(/\/chat\/completions\/?$/, '/models');
                break;
            case 'dummy':
                resultDiv.innerHTML = '<span style="color: #2ecc71;"><i class="fas fa-check"></i> Р вҖ”Р В°Р С–Р В»РЎС“РЎвӮ¬Р С”Р В° Р С–Р С•РЎвҖҡР С•Р РҶР В°!</span>';
                btn.disabled = false;
                setTimeout(() => resultDiv.style.display = 'none', 2000);
                return;
        }

        const response = await fetch(url, { method: 'GET', headers: headers });

        if (response.ok) {
            const data = await response.json();
            resultDiv.innerHTML = `<span style="color: #2ecc71;"><i class="fas fa-check"></i> Р РҲРЎРғР С—Р ВөРЎвӮ¬Р Р…Р С•! Р вҖ”Р В°Р С–РЎРӮРЎС“Р В·Р С”Р В° РЎРғР С—Р С‘РЎРғР С”Р В°...</span>`;
            
            let models = [];
            if (isGemini && data.models) {
                models = data.models.map(m => {
                    let id = m.name.replace('models/', '');
                    // Р ВӯР РҶРЎРӮР С‘РЎРғРЎвҖҡР С‘Р С”Р В° РЎвҖҡР С‘Р С—Р С•Р РҶ Р Т‘Р В»РЎРҸ Gemini
                    let type = 'text';
                    if (id.includes('vision') || id.includes('image') || id.includes('nano-banana')) type = 'vision';
                    else if (id.includes('tts') || id.includes('audio')) type = 'audio';
                    else if (id.includes('embed')) type = 'embedding';
                    
                    return {
                        id: id,
                        name: m.displayName || id,
                        desc: m.description || 'Р СӣРЎвҖһР С‘РЎвҖ Р С‘Р В°Р В»РЎРҠР Р…Р В°РЎРҸ Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Google Gemini.',
                        type: type,
                        free: false, // FIX: Р РҲР ВұРЎРӮР В°Р В»Р С‘ Р В»Р С•Р В¶Р Р…РЎвҖ№Р в„– РЎРғРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ "Р вҖҳР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р С•", РЎвҖҡР В°Р С” Р С”Р В°Р С” Р ВөРЎРғРЎвҖҡРЎРҠ Р В¶Р ВөРЎРғРЎвҖҡР С”Р С‘Р Вө Р В»Р С‘Р СҳР С‘РЎвҖҡРЎвҖ№ (Rate Limits)
                        context: m.inputTokenLimit || null,
                        priceText: 'Р вҖәР С‘Р СҳР С‘РЎвҖҡРЎвҖ№ API (Free Tier)' // Р В§Р ВөРЎРғРЎвҖҡР Р…Р С•Р Вө Р С—РЎРӮР ВөР Т‘РЎС“Р С—РЎРӮР ВөР В¶Р Т‘Р ВөР Р…Р С‘Р Вө
                    };
                });
            } else if (provider === 'openrouter' && data.data) {
                models = data.data.map(m => {
                    let type = 'text';
                    if (m.id.includes('vision') || (m.architecture && m.architecture.modality && m.architecture.modality.includes('image'))) type = 'vision';
                    
                    // Р В Р В°РЎРғРЎвҖЎР ВөРЎвҖҡ РЎвҖ Р ВөР Р…РЎвҖ№ Р В·Р В° 1 Р СҳР С‘Р В»Р В»Р С‘Р С•Р Р… РЎвҖҡР С•Р С”Р ВөР Р…Р С•Р РҶ (Р В·Р В°РЎвҖ°Р С‘РЎвҖҡР В° Р С•РЎвҖҡ undefined)
                    let p_prompt = m.pricing && m.pricing.prompt ? parseFloat(m.pricing.prompt) * 1000000 : -1;
                    let p_comp = m.pricing && m.pricing.completion ? parseFloat(m.pricing.completion) * 1000000 : -1;
                    
                    let isFree = (p_prompt === 0 && p_comp === 0) || m.id.endsWith(':free');
                    let priceText = '';
                    
                    if (isFree) {
                        priceText = 'Р вҖҳР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р С•';
                    } else if (p_prompt >= 0 && p_comp >= 0) {
                        // Р ВӨР С•РЎРӮР СҳР В°РЎвҖҡР С‘РЎРӮРЎС“Р ВөР Сҳ РЎвҖ Р ВөР Р…РЎС“: Р ВөРЎРғР В»Р С‘ Р СҳР ВөР Р…РЎРҠРЎвӮ¬Р Вө РЎвҖ Р ВөР Р…РЎвҖҡР В°, Р С—Р С•Р С”Р В°Р В·РЎвҖ№Р РҶР В°Р ВөР Сҳ 4 Р В·Р Р…Р В°Р С”Р В°, Р С‘Р Р…Р В°РЎвҖЎР Вө 2
                        let pr_str = p_prompt < 0.01 ? p_prompt.toFixed(4) : p_prompt.toFixed(2);
                        let cmp_str = p_comp < 0.01 ? p_comp.toFixed(4) : p_comp.toFixed(2);
                        priceText = `$${pr_str} / $${cmp_str} Р В·Р В° 1M`;
                    } else {
                        priceText = 'Р СҹР В»Р В°РЎвҖҡР Р…Р В°РЎРҸ';
                    }
                    
                    return {
                        id: m.id,
                        name: m.name || m.id,
                        desc: m.description || '',
                        type: type,
                        free: isFree,
                        context: m.context_length,
                        priceText: priceText
                    };
                });
            } else if (data.data && Array.isArray(data.data)) {
                models = data.data.map(m => ({ id: m.id, name: m.name || m.id, desc: '', type: 'text', free: false, priceText: 'Р СҹР С• РЎвҖҡР В°РЎРӮР С‘РЎвҖһРЎС“ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°' }));
            } else if (Array.isArray(data)) {
                models = data.map(m => ({ id: m.id || m.name, name: m.name || m.id, desc: '', type: 'text', free: false, priceText: 'Р СҹР С• РЎвҖҡР В°РЎРӮР С‘РЎвҖһРЎС“ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°' }));
            }

            // Р РҲР ВұР С‘РЎРӮР В°Р ВөР Сҳ РЎРҢР СҳР ВұР ВөР Т‘Р Т‘Р С‘Р Р…Р С–Р С‘, Р С•Р Р…Р С‘ Р Р…Р Вө Р Р…РЎС“Р В¶Р Р…РЎвҖ№ Р Т‘Р В»РЎРҸ РЎвҖЎР В°РЎвҖҡР В°
            models = models.filter(m => m.type !== 'embedding');

            if (models.length > 0) {
                showModelSelector(models);
                setTimeout(() => resultDiv.style.display = 'none', 2000);
            } else {
                resultDiv.innerHTML = `<span style="color: #f1c40f;"><i class="fas fa-check"></i> Р РҺР РҶРЎРҸР В·РЎРҠ Р ВөРЎРғРЎвҖҡРЎРҠ, Р Р…Р С• РЎРғР С—Р С‘РЎРғР С•Р С” Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„– Р С—РЎС“РЎРғРЎвҖҡ.</span>`;
            }

        } else {
            const errText = await response.text();
            let shortMsg = t(`apiErrors.${response.status}`, null, `Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° ${response.status}`);
            resultDiv.innerHTML = `<span style="color: #e74c3c;" title="${errText.replace(/"/g, '&quot;')}"><i class="fas fa-times"></i> ${shortMsg} (Р СҷР С•Р Т‘: ${response.status})</span>`;
            console.error("Ping error:", errText);
        }
    } catch (e) {
        let shortMsg = e.message.includes('fetch') ? t('apiErrors.network', null, 'Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° РЎРғР ВөРЎвҖҡР С‘') : e.message;
        resultDiv.innerHTML = `<span style="color: #e74c3c;"><i class="fas fa-times"></i> ${shortMsg}</span>`;
    } finally {
        btn.disabled = false;
    }
}

var currentModelsList = [];
var currentModelFilter = 'all';

function showModelSelector(models) {
    currentModelsList = models;
    const modal = document.getElementById('model-selector-modal');
    const searchInput = document.getElementById('model-search-input');
    const filterBtns = document.querySelectorAll('#model-filters button');
    
    if (!modal || !searchInput) return;

    searchInput.value = '';
    currentModelFilter = 'all';
    
    // Р РҺР ВұРЎРӮР С•РЎРғ Р С”Р Р…Р С•Р С—Р С•Р С” РЎвҖһР С‘Р В»РЎРҠРЎвҖҡРЎРӮР С•Р РҶ
    filterBtns.forEach(btn => {
        btn.classList.remove('active-filter', 'btn-blue');
        btn.classList.add('btn-gray');
        if (btn.dataset.filter === 'all') {
            btn.classList.add('active-filter', 'btn-blue');
            btn.classList.remove('btn-gray');
        }
    });

    applyModelFilters();

    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('visible'), 10);

    // Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡРЎвҖЎР С‘Р С” Р С—Р С•Р С‘РЎРғР С”Р В°
    searchInput.oninput = () => applyModelFilters();

    // Р СӣР ВұРЎРӮР В°Р ВұР С•РЎвҖҡРЎвҖЎР С‘Р С”Р С‘ РЎвҖһР С‘Р В»РЎРҠРЎвҖҡРЎРӮР С•Р РҶ
    filterBtns.forEach(btn => {
        btn.onclick = (e) => {
            filterBtns.forEach(b => {
                b.classList.remove('active-filter', 'btn-blue');
                b.classList.add('btn-gray');
            });
            const target = e.currentTarget;
            target.classList.add('active-filter', 'btn-blue');
            target.classList.remove('btn-gray');
            currentModelFilter = target.dataset.filter;
            applyModelFilters();
        };
    });

    document.getElementById('close-model-selector-btn').onclick = () => {
        modal.classList.remove('visible');
        setTimeout(() => modal.style.display = 'none', 300);
    };
}

function applyModelFilters() {
    const query = document.getElementById('model-search-input').value.toLowerCase();
    
    const filtered = currentModelsList.filter(m => {
        // 1. Р СҹР С•Р С‘РЎРғР С” Р С—Р С• РЎвҖҡР ВөР С”РЎРғРЎвҖҡРЎС“
        const matchesSearch = m.id.toLowerCase().includes(query) || (m.name && m.name.toLowerCase().includes(query));
        if (!matchesSearch) return false;
        
        // 2. Р ВӨР С‘Р В»РЎРҠРЎвҖҡРЎРӮ Р С—Р С• Р С”Р В°РЎвҖҡР ВөР С–Р С•РЎРӮР С‘Р С‘
        if (currentModelFilter === 'all') return true;
        if (currentModelFilter === 'free') return m.free === true;
        return m.type === currentModelFilter;
    });
    
    renderModelList(filtered);
}

function applyModelFilters() {
    const query = document.getElementById('model-search-input').value.toLowerCase();
    
    const filtered = currentModelsList.filter(m => {
        // 1. Р СҹР С•Р С‘РЎРғР С” Р С—Р С• РЎвҖҡР ВөР С”РЎРғРЎвҖҡРЎС“
        const matchesSearch = m.id.toLowerCase().includes(query) || (m.name && m.name.toLowerCase().includes(query));
        if (!matchesSearch) return false;
        
        // 2. Р ВӨР С‘Р В»РЎРҠРЎвҖҡРЎРӮ Р С—Р С• Р С”Р В°РЎвҖҡР ВөР С–Р С•РЎРӮР С‘Р С‘
        if (currentModelFilter === 'all') return true;
        if (currentModelFilter === 'free') return m.free === true;
        return m.type === currentModelFilter;
    });
    
    renderModelList(filtered);
}

function renderModelList(models) {
    const container = document.getElementById('model-list-container');
    const countBadge = document.getElementById('model-count-badge');
    container.innerHTML = '';
    
    if (countBadge) countBadge.textContent = `${models.length} Р СҳР С•Р Т‘Р ВөР В»Р ВөР в„–`;
    
    if (models.length === 0) {
        container.innerHTML = '<div style="padding: 20px; color: #7f8c8d; text-align: center; font-style: italic;">Р СҹР С• Р РҶР В°РЎвӮ¬Р ВөР СҳРЎС“ Р В·Р В°Р С—РЎРӮР С•РЎРғРЎС“ Р Р…Р С‘РЎвҖЎР ВөР С–Р С• Р Р…Р Вө Р Р…Р В°Р в„–Р Т‘Р ВөР Р…Р С•.</div>';
        return;
    }

    models.forEach(m => {
        const item = document.createElement('div');
        item.className = 'model-card';
        
        let badgesHtml = '';
        if (m.free) badgesHtml += `<span class="model-badge badge-free"><i class="fas fa-gift"></i> Р вҖҳР ВөРЎРғР С—Р В»Р В°РЎвҖҡР Р…Р С•</span>`;
        else if (m.priceText) badgesHtml += `<span class="model-badge badge-price"><i class="fas fa-coins"></i> ${m.priceText}</span>`;
        
        if (m.context) {
            let ctxStr = m.context >= 1000 ? Math.round(m.context/1000) + 'k' : m.context;
            badgesHtml += `<span class="model-badge badge-ctx"><i class="fas fa-brain"></i> ${ctxStr} ctx</span>`;
        }
        
        if (m.type === 'vision') badgesHtml += `<span class="model-badge badge-type-vision"><i class="fas fa-eye"></i> Vision</span>`;
        if (m.type === 'audio') badgesHtml += `<span class="model-badge badge-type-audio"><i class="fas fa-volume-up"></i> Audio</span>`;
        
        if (m.caching) badgesHtml += `<span class="model-badge badge-caching" title="Р СҹР С•Р Т‘Р Т‘Р ВөРЎРӮР В¶Р С‘Р РҶР В°Р ВөРЎвҖҡ Prompt Caching (РЎРғР Р…Р С‘Р В¶Р В°Р ВөРЎвҖҡ РЎвҖ Р ВөР Р…РЎС“ Р С‘ РЎС“РЎРғР С”Р С•РЎРӮРЎРҸР ВөРЎвҖҡ Р С•РЎвҖҡР РҶР ВөРЎвҖҡ)"><i class="fas fa-bolt"></i> Caching</span>`;
        if (m.thinking) badgesHtml += `<span class="model-badge badge-thinking" title="Р СҹР С•Р Т‘Р Т‘Р ВөРЎРӮР В¶Р С‘Р РҶР В°Р ВөРЎвҖҡ РЎРӮР ВөР В¶Р С‘Р Сҳ РЎРӮР В°Р В·Р СҳРЎвҖ№РЎвӮ¬Р В»Р ВөР Р…Р С‘РЎРҸ (Reasoning)"><i class="fas fa-brain"></i> Thinking</span>`;

        let descHtml = m.desc ? `<div class="model-card-desc">${m.desc}</div>` : '';

        item.innerHTML = `
            <div class="model-card-header">
                <div class="model-card-title">${m.name}</div>
                <div class="model-card-id">${m.id}</div>
            </div>
            ${descHtml}
            <div class="model-badges">${badgesHtml}</div>
        `;
        
        item.onclick = () => {
            const input = document.getElementById('model-id-input');
            if (input) {
                input.value = m.id;
                input.style.boxShadow = '0 0 15px #2ecc71';
                setTimeout(() => input.style.boxShadow = 'none', 1000);
                
                // Р С’Р РҶРЎвҖҡР С•Р СҳР В°РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘ РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р в„–Р С”Р С‘ Р С—РЎРӮР С‘ Р РҶРЎвҖ№Р ВұР С•РЎРӮР Вө Р СҳР С•Р Т‘Р ВөР В»Р С‘
                if (typeof saveSettings === 'function') saveSettings();
            }
            document.getElementById('model-selector-modal').classList.remove('visible');
            setTimeout(() => document.getElementById('model-selector-modal').style.display = 'none', 300);
        };
        
        container.appendChild(item);
    });
}


function saveSettings() {
    const provider = document.getElementById('api-provider-select')?.value || 'gemini';
    const cachingCheckbox = document.getElementById('prompt-caching-checkbox');
    if (cachingCheckbox) {
        usePromptCaching = cachingCheckbox.checked;
        localStorage.setItem('usePromptCaching', usePromptCaching);
    }

    const thinkingCheckbox = document.getElementById('thinking-mode-checkbox');
    if (thinkingCheckbox) {
        useThinkingMode = thinkingCheckbox.checked;
        localStorage.setItem('useThinkingMode', useThinkingMode);
    }
    const thinkingSlider = document.getElementById('thinking-budget-slider');
    if (thinkingSlider) {
        thinkingBudget = parseInt(thinkingSlider.value);
        localStorage.setItem('thinkingBudget', thinkingBudget);
    }
    const effortSelect = document.getElementById('reasoning-effort-select');
    if (effortSelect) {
        reasoningEffort = effortSelect.value;
        localStorage.setItem('reasoningEffort', reasoningEffort);
    }

    const nsfwCheckbox = document.getElementById('nsfw-mode-checkbox');
    if (nsfwCheckbox) {
        allowNSFW = nsfwCheckbox.checked;
        localStorage.setItem('allowNSFW', allowNSFW);
    }

    // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…Р С‘Р Вө РЎРҢРЎРӮР С•РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р С‘РЎвҖҰ Р Р…Р В°РЎРғРЎвҖҡРЎРӮР С•Р ВөР С”
    const eroticIntensitySlider = document.getElementById('erotic-intensity-slider');
    if (eroticIntensitySlider) {
        eroticIntensityLevel = parseInt(eroticIntensitySlider.value);
        localStorage.setItem('eroticIntensityLevel', eroticIntensityLevel);
    }

    const pregnancyRiskCheckbox = document.getElementById('pregnancy-risk-checkbox');
    const diseaseRiskCheckbox = document.getElementById('disease-risk-checkbox');
    const reputationConsequencesCheckbox = document.getElementById('reputation-consequences-checkbox');
    const pornoModeCheckbox = document.getElementById('porno-mode-checkbox');

    if (pregnancyRiskCheckbox) eroticPreferences.pregnancyRisk = pregnancyRiskCheckbox.checked;
    if (diseaseRiskCheckbox) eroticPreferences.diseaseRisk = diseaseRiskCheckbox.checked;
    if (reputationConsequencesCheckbox) eroticPreferences.reputationConsequences = reputationConsequencesCheckbox.checked;
    if (pornoModeCheckbox) eroticPreferences.pornoMode = pornoModeCheckbox.checked;

    localStorage.setItem('eroticPreferences', JSON.stringify(eroticPreferences));

    const modelId = document.getElementById('model-id-input')?.value.trim() || '';

    // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ ID Р СҳР С•Р Т‘Р ВөР В»Р С‘ Р Т‘Р В»РЎРҸ Р СһР вҖўР СҷР РҲР В©Р вҖўР вҖңР Сӣ Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°
    switch (provider) {
        case 'gemini':
            geminiModelId = modelId;
            localStorage.setItem('geminiModelId', geminiModelId);
            break;
        case 'llmost':
            llmostModelId = modelId;
            localStorage.setItem('llmostModelId', llmostModelId);
            break;
        case 'openrouter':
            openrouterModelId = modelId;
            localStorage.setItem('openrouterModelId', openrouterModelId);
            break;
        case 'deepseek':
            deepseekModelId = modelId;
            localStorage.setItem('deepseekModelId', deepseekModelId);
            break;
        case 'omniroute':
            omnirouteModelId = modelId;
            localStorage.setItem('omnirouteModelId', omnirouteModelId);
            break;
        case 'local':
            localModelId = modelId;
            localStorage.setItem('localModelId', localModelId);
            break;
    }

    // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ Р С”Р В»РЎРӢРЎвҖЎР С‘ Р С‘ URL
    const geminiKeyInput = document.getElementById('gemini-api-key-input')?.value.trim() || '';
    geminiApiKeys = geminiKeyInput.split(/[\n,]+/).map(k => k.trim()).filter(k => k.length > 10);
    geminiApiKey = geminiApiKeys.length > 0 ? geminiApiKeys[0] : '';
    localStorage.setItem('geminiApiKeys', JSON.stringify(geminiApiKeys));
    currentGeminiKeyIndex = 0;

    const llmostKey = document.getElementById('llmost-api-key-input')?.value.trim() || '';
    llmostApiKey = llmostKey;
    localStorage.setItem('llmostApiKey', llmostKey);

    const openrouterKey = document.getElementById('openrouter-api-key-input')?.value.trim() || '';
    openrouterApiKey = openrouterKey;
    localStorage.setItem('openrouterApiKey', openrouterKey);

    const deepseekKey = document.getElementById('deepseek-api-key-input')?.value.trim() || '';
    deepseekApiKey = deepseekKey;
    localStorage.setItem('deepseekApiKey', deepseekKey);

    const omnirouteKey = document.getElementById('omniroute-api-key-input')?.value.trim() || '';
    omnirouteApiKey = omnirouteKey;
    localStorage.setItem('omnirouteApiKey', omnirouteKey);

    const omniUrl = document.getElementById('omniroute-base-url-input')?.value.trim() || '';
    omnirouteBaseUrl = omniUrl;
    localStorage.setItem('omnirouteBaseUrl', omniUrl);

    const localUrl = document.getElementById('local-url-input')?.value.trim() || '';
    localApiUrl = localUrl;
    localStorage.setItem('localApiUrl', localUrl);

    // Save image settings
    const imgGenCheckbox = document.getElementById('enable-img-gen-checkbox');
    const localMapCheckbox = document.getElementById('enable-local-map-checkbox');
    const deepSetupCheckbox = document.getElementById('enable-deep-setup-checkbox');
    
    
    if (imgGenCheckbox) {
        enableImageGeneration = imgGenCheckbox.checked;
        localStorage.setItem('enableImageGeneration', enableImageGeneration);
    }
    if (deepSetupCheckbox) {
        enableDeepSetup = deepSetupCheckbox.checked;
        localStorage.setItem('enableDeepSetup', enableDeepSetup);
    }
    
    imgApiProvider = document.getElementById('img-provider-select')?.value || 'pollinations';
    imgModelId = document.getElementById('img-model-input')?.value.trim() || 'dall-e-3';
    imgApiKey = document.getElementById('img-key-input')?.value.trim() || '';
    localStorage.setItem('imgApiProvider', imgApiProvider);
    localStorage.setItem('imgModelId', imgModelId);
    localStorage.setItem('imgApiKey', imgApiKey);
    
    aiPlayerProvider = document.getElementById('ai-player-provider-select')?.value || 'openrouter';
    aiPlayerModelId = document.getElementById('ai-player-model-input')?.value.trim() || 'google/gemma-2-9b-it:free';
    const aiKeyRaw = document.getElementById('ai-player-key-input')?.value.trim() || '';
    if (aiPlayerProvider === 'local') {
        aiPlayerLocalUrl = aiKeyRaw;
    } else {
        aiPlayerApiKey = aiKeyRaw;
    }
    localStorage.setItem('aiPlayerProvider', aiPlayerProvider);
    localStorage.setItem('aiPlayerModelId', aiPlayerModelId);
    localStorage.setItem('aiPlayerApiKey', aiPlayerApiKey);
    localStorage.setItem('aiPlayerLocalUrl', aiPlayerLocalUrl);
    aiPlayerTurnLimit = parseInt(document.getElementById('ai-player-turn-limit')?.value) || 0;
    localStorage.setItem('aiPlayerTurnLimit', aiPlayerTurnLimit);



    // Р РҺР С•РЎвҖҰРЎРӮР В°Р Р…РЎРҸР ВөР Сҳ Р В·Р РҶРЎС“Р С”
    localStorage.setItem('musicVolume', musicVolume);
    localStorage.setItem('sfxVolume', sfxVolume);


    const autoSaveSelect = document.getElementById('autosave-interval-select');
    if (autoSaveSelect) {
        autoSaveIntervalMs = parseInt(autoSaveSelect.value, 10);
        localStorage.setItem('autoSaveInterval', autoSaveIntervalMs);
        if (typeof startAutoSaveTimer === 'function') startAutoSaveTimer();
    }

    // Р СӣР ВұР Р…Р С•Р РҶР В»РЎРҸР ВөР Сҳ Р С–Р В»Р С•Р ВұР В°Р В»РЎРҠР Р…РЎС“РЎРӢ Р С—Р ВөРЎРӮР ВөР СҳР ВөР Р…Р Р…РЎС“РЎРӢ РЎвҖҡР ВөР С”РЎС“РЎвҖ°Р ВөР С–Р С• Р С—РЎРӮР С•Р РҶР В°Р в„–Р Т‘Р ВөРЎРӮР В°
    currentApiProvider = provider;
    localStorage.setItem('apiProvider', currentApiProvider);



    updateApiKeyStatus();
    showCustomAlert(t('settingsMenu.apiKeySaved', 'Р СңР В°РЎРғРЎвҖҡРЎРӮР С•Р в„–Р С”Р С‘ РЎС“РЎРғР С—Р ВөРЎвӮ¬Р Р…Р С• РЎРғР С•РЎвҖҰРЎРӮР В°Р Р…Р ВөР Р…РЎвҖ№!'));

    if (document.activeElement) document.activeElement.blur();
}

