        // ------------------------------------------

        // --- Р вҖҷР РҺР вҖў Р вҖ”Р С’Р СҹР В Р СӣР РҺР В« Р ВҳР вҖқР РҲР Сһ Р СңР С’Р СҹР В Р РҮР СҡР РҲР В® Р СҹР В Р СӣР вҖҷР С’Р в„ўР вҖқР вҖўР В Р РҲ ---
        // --- Р СҹР СӣР вҖқР вҖңР СӣР СһР СӣР вҖҷР СҷР С’ Р СҹР С’Р В Р С’Р СҡР вҖўР СһР В Р СӣР вҖҷ THINKING ---
        let finalTemperature = 0.7;
