            if (targetUrl.endsWith('/')) targetUrl = targetUrl.slice(0, -1);
            if (!targetUrl.endsWith('/chat/completions')) {
                targetUrl += targetUrl.endsWith('/v1') ? '/chat/completions' : '/v1/chat/completions';
            }
