            targetUrl = 'https://generativelanguage.googleapis.com/v1beta/models/' + providerModel + ':generateContent?key=' + activeKey;

            // Gemini API РЎвҖҡРЎРӮР ВөР ВұРЎС“Р ВөРЎвҖҡ РЎРғР С—Р ВөРЎвҖ Р С‘РЎвҖһР С‘РЎвҖЎР Р…РЎвҖ№Р в„– РЎвҖһР С•РЎРӮР СҳР В°РЎвҖҡ Р Р…Р В°Р С—РЎРӮРЎРҸР СҳРЎС“РЎРӢ
            const contents = [];
