                                    addCalculationMessage(`[Р СӣР РҒР ВҳР вҖҳР СҷР С’ Р РҮР вҖқР В Р С’] Р СҹР С•Р С—РЎвҖ№РЎвҖҡР С”Р В° Р С‘РЎРғРЎвҖ Р ВөР В»Р С‘РЎвҖҡРЎРҠ ${entity.name} РЎвҖЎР ВөРЎРӮР ВөР В· updateEntityStat Р С—РЎРӮР ВөРЎРғР ВөРЎвҖЎР ВөР Р…Р В°.`);
                                    validatedValue = currentHp;
