// --- Р ВӨР РҲР СңР СҷР ВҰР ВҳР Вҳ Р С’Р вҖқР СҡР ВҳР Сң Р СҡР вҖўР СңР В® (DEBUG) ---
// ==========================================

function openAdminMenu() {
    if (!player || !DEBUG_MODE) return;
    populateAdminMenu();
    const modal = document.getElementById('admin-menu-overlay');
    if (!modal) return;
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('visible'), 10);
}

function closeAdminMenu() {
    const modal = document.getElementById('admin-menu-overlay');
    if (!modal) return;
    modal.classList.remove('visible');
    setTimeout(() => modal.style.display = 'none', 300);
}

function populateAdminMenu() {
    const content = document.getElementById('admin-menu-content');
    if (!content) return;

    let html = `
        <div style="margin-bottom: 20px; background: rgba(0,0,0,0.3); padding: 10px; border-radius: 5px; border-left: 3px solid #f1c40f;">
            <h4 style="margin: 0 0 10px 0; color: #f1c40f;">СҖСҹвҖҷВ° Р вҖҳРЎвҖ№РЎРғРЎвҖҡРЎРӮРЎвҖ№Р Вө Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘РЎРҸ</h4>
            <div style="display: flex; gap: 10px; align-items: center; flex-wrap: wrap;">
                <input type="number" id="admin-gold-input" value="1000" style="width: 100px; padding: 5px; color: #fff; background: rgba(0,0,0,0.5); border: 1px solid #f1c40f;">
                <button data-action="admin-add-gold" style="background: #27ae60; margin: 0; padding: 5px 15px; min-width: auto;">+ Р вҖ”Р С•Р В»Р С•РЎвҖҡР С•</button>
                <button data-action="admin-heal" style="background: #e74c3c; margin: 0; padding: 5px 15px; min-width: auto;">Full HP/MP</button>
                <button data-action="admin-force-summary" style="background: #8e44ad; margin: 0; padding: 5px 15px; min-width: auto;">Р РҺР В¶Р В°РЎвҖҡРЎРҠ Р С—Р В°Р СҳРЎРҸРЎвҖҡРЎРҠ (Summarize)</button>
                <button data-action="toggle-autotester" id="admin-autotester-btn" style="background: #e67e22; margin: 0; padding: 5px 15px; min-width: auto;">СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР В«Р СҷР вҖә</button>
                <button data-action="toggle-localization" style="background: #34495e; margin: 0; padding: 5px 15px; min-width: auto;">СҖСҹРҠС’ Р вҖәР С•Р С”Р В°Р В»Р С‘Р В·Р В°РЎвҖ Р С‘РЎРҸ: ${window.DISABLE_LOCALIZATION ? 'Р вҖҷР В«Р СҷР вҖә' : 'Р вҖҷР СҷР вҖә'}</button>
            </div>
        </div>

        <div style="margin-bottom: 20px; background: rgba(0,0,0,0.3); padding: 10px; border-radius: 5px; border-left: 3px solid #9b59b6;">
            <h4 style="margin: 0 0 10px 0; color: #9b59b6;">РІРҸС– Р СҡР В°РЎвӮ¬Р С‘Р Р…Р В° Р вҖҷРЎРӮР ВөР СҳР ВөР Р…Р С‘ Р С‘ Р СҹР В°Р СҳРЎРҸРЎвҖҡРЎРҠ</h4>
            <div style="display: flex; gap: 10px; align-items: center; flex-wrap: wrap;">
                <button onclick="adminSetTurn(28)" style="background: #8e44ad; margin: 0; padding: 5px 15px; min-width: auto;" title="Р РҺР В»Р ВөР Т‘РЎС“РЎРӢРЎвҖ°Р С‘Р в„– РЎвҖҰР С•Р Т‘ Р РҶРЎвҖ№Р В·Р С•Р РҶР ВөРЎвҖҡ РЎРғР В¶Р В°РЎвҖҡР С‘Р Вө Р С—Р В°Р СҳРЎРҸРЎвҖҡР С‘ (29)">Р ТҗР С•Р Т‘ = 28 (Р СһР ВөРЎРғРЎвҖҡ Р РҺР В¶Р В°РЎвҖҡР С‘РЎРҸ)</button>
                <button onclick="adminSetTurn(29)" style="background: #8e44ad; margin: 0; padding: 5px 15px; min-width: auto;" title="Р РҺР В»Р ВөР Т‘РЎС“РЎРӢРЎвҖ°Р С‘Р в„– РЎвҖҰР С•Р Т‘ Р РҶРЎвҖ№Р В·Р С•Р РҶР ВөРЎвҖҡ Р С•РЎвҖЎР С‘РЎРғРЎвҖҡР С”РЎС“ Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘Р С‘ (30)">Р ТҗР С•Р Т‘ = 29 (Р СһР ВөРЎРғРЎвҖҡ Р СӣРЎвҖЎР С‘РЎРғРЎвҖҡР С”Р С‘)</button>
                <button onclick="adminInjectMemory()" style="background: #2980b9; margin: 0; padding: 5px 15px; min-width: auto;">Р вҖҷР С—РЎРӮРЎвҖ№РЎРғР Р…РЎС“РЎвҖҡРЎРҠ РЎвҖһР ВөР в„–Р С”Р С•Р РҶРЎС“РЎРӢ Р С—Р В°Р СҳРЎРҸРЎвҖҡРЎРҠ</button>
                <button onclick="runUnitTests()" style="background: #2c3e50; border: 1px solid #5dade2; margin: 0; padding: 5px 15px; min-width: auto;">СҖСҹВ§Р„ Р вҖ”Р В°Р С—РЎС“РЎРғРЎвҖҡР С‘РЎвҖҡРЎРҠ Unit-РЎвҖҡР ВөРЎРғРЎвҖҡРЎвҖ№</button>
            </div>
            <p style="margin: 5px 0 0 0; font-size: 0.85em; color: #bdc3c7;">Р СһР ВөР С”РЎС“РЎвҖ°Р С‘Р в„– РЎвҖҰР С•Р Т‘: <b style="color:#fff">${player.stats.turnCount}</b></p>
        </div>
    `;

    html += `<div style="display: flex; gap: 20px; flex-wrap: wrap;">`;

    // Р вҖәР ВөР РҶР В°РЎРҸ Р С”Р С•Р В»Р С•Р Р…Р С”Р В°: Р СӣР С”РЎРӮРЎС“Р В¶Р ВөР Р…Р С‘Р Вө
    html += `<div style="flex: 1; min-width: 300px; background: rgba(0,0,0,0.3); padding: 10px; border-radius: 5px; border-left: 3px solid #e74c3c;">
                <h4 style="margin: 0 0 10px 0; color: #e74c3c;">СҖСҹРӢВӯ Р СӣР С”РЎРӮРЎС“Р В¶Р ВөР Р…Р С‘Р Вө (NPC/Р вҖҷРЎРӮР В°Р С–Р С‘)</h4>
                <ul style="list-style: none; padding: 0; margin: 0;">`;

    const entities = Object.values(player.visibleEntities || {});
    if (entities.length === 0) html += `<li style="color: #7f8c8d; font-size: 0.9em;">Р СңР С‘Р С”Р С•Р С–Р С• Р Р…Р ВөРЎвҖҡ РЎРӮРЎРҸР Т‘Р С•Р Сҳ</li>`;
    entities.forEach(ent => {
        html += `<li style="margin-bottom: 8px; font-size: 0.9em; border-bottom: 1px dashed rgba(255,255,255,0.1); padding-bottom: 5px;">
                    <strong style="color: ${ent.isHostile ? '#e74c3c' : '#5dade2'}">${ent.name}</strong> [HP: ${ent.stats.hp}/${ent.stats.maxHp}]
                    <div style="margin-top: 5px; display: flex; gap: 5px;">
                        <button onclick="adminKillEntity('${ent.id}')" style="background: #c0392b; padding: 2px 8px; font-size: 0.8em; margin: 0; min-width: auto;">Р РҲР ВұР С‘РЎвҖҡРЎРҠ (0 HP)</button>
                        <button onclick="adminRemoveEntity('${ent.id}')" style="background: #7f8c8d; padding: 2px 8px; font-size: 0.8em; margin: 0; min-width: auto;">Р РҲР Т‘Р В°Р В»Р С‘РЎвҖҡРЎРҠ</button>
                    </div>
                 </li>`;
    });
    html += `</ul></div>`;

    // Р СҹРЎРӮР В°Р РҶР В°РЎРҸ Р С”Р С•Р В»Р С•Р Р…Р С”Р В°: Nexus
    html += `<div style="flex: 1; min-width: 300px; background: rgba(0,0,0,0.3); padding: 10px; border-radius: 5px; border-left: 3px solid #3498db;">
                <h4 style="margin: 0 0 10px 0; color: #3498db;">СҖСҹвҖқВ® Р СҷР С•Р Р…РЎРғРЎвҖҡР В°Р Р…РЎвҖҡРЎвҖ№ (Nexus)</h4>
                <ul style="list-style: none; padding: 0; margin: 0;">`;

    const nexusItems = Object.values(player.nexusData || {});
    if (nexusItems.length === 0) html += `<li style="color: #7f8c8d; font-size: 0.9em;">Р СңР ВөРЎвҖҡ Р В°Р С”РЎвҖҡР С‘Р РҶР Р…РЎвҖ№РЎвҖҰ Р С”Р С•Р Р…РЎРғРЎвҖҡР В°Р Р…РЎвҖҡ</li>`;
    nexusItems.forEach(item => {
        html += `<li style="margin-bottom: 8px; font-size: 0.9em; border-bottom: 1px dashed rgba(255,255,255,0.1); padding-bottom: 5px;">
                    <strong style="color: #5dade2">${item.name}</strong>: <span style="color: #f1c40f">${item.value}</span>
                    <div style="margin-top: 5px; display: flex; gap: 5px;">
                        <button onclick="adminEditNexus('${item.id}')" style="background: #2980b9; padding: 2px 8px; font-size: 0.8em; margin: 0; min-width: auto;">Р ВҳР В·Р СҳР ВөР Р…Р С‘РЎвҖҡРЎРҠ</button>
                        <button onclick="adminDeleteNexus('${item.id}')" style="background: #c0392b; padding: 2px 8px; font-size: 0.8em; margin: 0; min-width: auto;">Р РҲР Т‘Р В°Р В»Р С‘РЎвҖҡРЎРҠ</button>
                    </div>
                 </li>`;
    });
    html += `</ul></div>`;

    html += `</div>`;

    if (DEBUG_MODE && typeof World !== 'undefined' && World) {
        html += '<div style="margin-top: 20px; border-top: 2px solid #5dade2; padding-top: 10px;"><h3 style="color:#5dade2; margin-top:0;">Р вҖңР вҖәР СӣР вҖҳР С’Р вҖәР В¬Р СңР С’Р РҮ Р РҺР ВҳР СҡР РҲР вҖәР РҮР ВҰР ВҳР РҮ</h3></div>';
        
        // 1. Р ВӨР В Р С’Р СҷР ВҰР ВҳР Вҳ
        html += '<div class="debug-card"><div class="debug-card-title"><span>СҖСҹРҸвҖәРҝС‘РҸ Р ВӨР В Р С’Р СҷР ВҰР ВҳР Вҳ</span></div><div class="debug-grid">';
        for (let fId in World.factions) {
            let f = World.factions[fId];
            let isPlayer = (f.rulerId === 'player');
            let wars = [];
            for (let t in f.diplomacy) { if (f.diplomacy[t] === "war" && World.factions[t]) wars.push(World.factions[t].name); }
            let warText = wars.length > 0 ? `<br><span style="color:#e74c3c; font-size:0.85em;">РІСҷвҖқРҝС‘РҸ Р вҖҷР С•Р в„–Р Р…Р В°: ${wars.join(', ')}</span>` : '';
            
            const formatNum = (num) => {
                if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
                if (num >= 1000) return (num / 1000).toFixed(1) + 'k';
                return num;
            };

            const capitalRegionId = Object.keys(World.regions).find(rid => World.regions[rid].factionId === fId);
            let gold = 0;
            if (capitalRegionId && World.regions[capitalRegionId]?.vault_id) {
                gold = countRealItems(World.regions[capitalRegionId].vault_id, getPrimaryCurrencyPrototypeId('gold'));
            }
            const manpower = availableManpower(f);
            
            let titleColor = isPlayer ? "#2ecc71" : "#3498db";
            let titlePrefix = isPlayer ? "СҖСҹвҖҳвҖҳ [Р вҖҷР С’Р РҒР С’] " : "";
            let bgStyle = isPlayer ? 'style="border-left-color: #2ecc71; background: rgba(46, 204, 113, 0.1);"' : '';
            
            html += `<div class="debug-item" ${bgStyle}>
                     <b style="color:${titleColor}">${titlePrefix}${f.name}</b><br>
                     СҖСҹвҖҷВ°${formatNum(gold)} | СҖСҹвҖәРҺРҝС‘РҸ${formatNum(manpower)}
                     ${warText}
                     </div>`;
        }
        html += '</div></div>';

        // 2. Р С’Р В Р СҡР ВҳР Вҳ Р Вҳ Р СӣР РҺР С’Р вҖқР В«
        html += '<div class="debug-card"><div class="debug-card-title"><span>РІСҷвҖқРҝС‘РҸ Р С’Р СҷР СһР ВҳР вҖҷР СңР СӣР РҺР СһР В¬ Р вҖҷР СӣР в„ўР РҺР Сҷ</span></div>';
        let armiesExist = false;
        for (let fId in World.factions) {
            World.factions[fId].armies.forEach(a => {
                armiesExist = true;
                let dest = World.regions[a.destination] ? World.regions[a.destination].name : a.destination;
                
                let statusText = '';
                if (a.daysToMove > 0) {
                    statusText = `Р вҖҷ Р С—РЎС“РЎвҖҡР С‘ (Р С•РЎРғРЎвҖҡР В°Р В»Р С•РЎРғРЎРҠ ${a.daysToMove} Р Т‘Р Р….)`;
                } else if (a.siegeDays > 0) {
                    statusText = `<b style="color:#e67e22">Р СӣР РҺР С’Р вҖқР С’</b> (Р С•РЎРғРЎвҖҡР В°Р В»Р С•РЎРғРЎРҠ ${a.siegeDays} Р Т‘Р Р….)`;
                } else {
                    let phaseName = a.current_phase;
                    if (phaseName === 'vanguard_clash') phaseName = 'Р РҺРЎвҖҡРЎвҖ№РЎвҖЎР С”Р В° Р В°Р РҶР В°Р Р…Р С–Р В°РЎРӮР Т‘Р С•Р РҶ';
                    else if (phaseName === 'main_battle') phaseName = 'Р СӣРЎРғР Р…Р С•Р РҶР Р…Р С•Р Вө РЎРғРЎРӮР В°Р В¶Р ВөР Р…Р С‘Р Вө';
                    else if (phaseName === 'rout') phaseName = 'Р СӣРЎвҖҡРЎРғРЎвҖҡРЎС“Р С—Р В»Р ВөР Р…Р С‘Р Вө';
                    statusText = `<b style="color:#e74c3c">Р вҖҳР СӣР в„ў: ${phaseName}</b>`;
                }

                let armyName = World.factions[fId].rulerId === 'player' ? "СҖСҹвҖҳвҖҳ Р вҖҷР В°РЎвӮ¬Р В° Р В°РЎРӮР СҳР С‘РЎРҸ" : World.factions[fId].name;

                html += `<div class="debug-army-item">
                            <b>${armyName}</b> (${a.size} Р ВөР Т‘.) РІСӣвҖқ <b>${dest}</b><br>
                            Р РҺРЎвҖҡР В°РЎвҖҡРЎС“РЎРғ: ${statusText}
                         </div>`;
            });
        }
        if (!armiesExist) html += '<div style="color:#7f8c8d; font-style:italic; padding:5px;">Р СңР ВөРЎвҖҡ Р В°Р С”РЎвҖҡР С‘Р РҶР Р…РЎвҖ№РЎвҖҰ Р С—Р ВөРЎРӮР ВөР Т‘Р РҶР С‘Р В¶Р ВөР Р…Р С‘Р в„– Р РҶР С•Р в„–РЎРғР С”</div>';
        html += '</div>';
    
        // 3. Р СҹР В Р С’Р вҖҷР ВҳР СһР вҖўР вҖәР Вҳ Р Вҳ Р ВҳР СңР СһР В Р ВҳР вҖңР Вҳ
        html += '<div class="debug-card"><div class="debug-card-title"><span>СҖСҹвҖҳвҖҳ Р СҹР В Р С’Р вҖҷР ВҳР СһР вҖўР вҖәР Вҳ Р Вҳ Р ВҳР СңР СһР В Р ВҳР вҖңР Вҳ</span></div><div class="debug-grid">';
        if(World.rulers) {
            for(let rId in World.rulers) {
                let r = World.rulers[rId];
                if(!r.alive || r.id.includes("_heir")) continue;
                let goal = r.gmOverride ? `<b style="color:#e74c3c">[GM] ${r.gmOverride}</b>` : (r.currentGoal ? `${r.currentGoal.type} -> ${r.currentGoal.targetFactionId}` : "Р СңР ВөРЎвҖҡ РЎвҖ Р ВөР В»Р С‘");
                html += `<div class="debug-item">
                         <b style="color:#9b59b6">${r.name}</b> (${World.factions[r.factionId]?.name || r.factionId})<br>
                         HP: ${r.health}% | Р С’Р СҳР ВұР С‘РЎвҖ Р С‘Р С‘: ${r.personality.ambition}<br>
                         Р ВҰР ВөР В»РЎРҠ: ${goal}
                         </div>`;
            }
        }
        html += '</div>';
    
        if(World.intrigues && World.intrigues.length > 0) {
            html += '<div style="margin-top:10px; border-top:1px dashed #555; padding-top:5px;"><b>Р С’Р С”РЎвҖҡР С‘Р РҶР Р…РЎвҖ№Р Вө Р В·Р В°Р С–Р С•Р РҶР С•РЎРӮРЎвҖ№:</b><br>';
            World.intrigues.forEach(i => {
                let phaseName = i.phase;
                if (phaseName === 'recruitment') phaseName = 'Р вҖҷР ВөРЎРӮР ВұР С•Р РҶР С”Р В°';
                else if (phaseName === 'espionage') phaseName = 'Р РҒР С—Р С‘Р С•Р Р…Р В°Р В¶';
                else if (phaseName === 'execution') phaseName = 'Р ВҳРЎРғР С—Р С•Р В»Р Р…Р ВөР Р…Р С‘Р Вө';
                else if (phaseName === 'cover_up') phaseName = 'Р вҖ”Р В°Р СҳР ВөРЎвҖҡР В°Р Р…Р С‘Р Вө РЎРғР В»Р ВөР Т‘Р С•Р РҶ';
                html += `<span style="color:${i.isDiscovered ? '#e74c3c' : '#f39c12'}">[${i.type}]</span> ${i.initiatorFactionId} -> ${i.targetFactionId} (Р ВӨР В°Р В·Р В°: ${phaseName}, Р СҹРЎРӮР С•Р С–РЎРӮР ВөРЎРғРЎРғ: ${Math.floor(i.progress)}/${i.requiredProgress})<br>`;
            });
            html += '</div>';
        }
        html += '</div>';
    }

    setTimeout(() => {
        const btn = document.getElementById('admin-autotester-btn');
        if (btn) btn.innerHTML = isAutoTesting ? 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР СҷР вҖә' : 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР В«Р СҷР вҖә';
    }, 50);

    content.innerHTML = html;
}

window.adminAddGold = function () {
    const val = parseInt(document.getElementById('admin-gold-input').value) || 0;
    executeCommand('addItem', { aiIdentifier: 'gold', name: 'Р вҖ”Р С•Р В»Р С•РЎвҖҡР С•', quantity: val });
    populateAdminMenu();
};

;
;
;
;


window.adminHeal = function () {
    executeCommand('updateStat', { stat: 'hp', change: 9999 });
    if (player.class === 'mage') executeCommand('updateStat', { stat: 'mana', change: 9999 });
    populateAdminMenu();
};

window.adminForceSummary = async function () {
    closeAdminMenu();
    if (!player) return;
    addLogMessage("[ADMIN] Р вҖ”Р В°Р С—РЎС“РЎРғР С” Р С–Р В»РЎС“Р ВұР С•Р С”Р С•Р в„– Р В°РЎРӮРЎвҖҰР С‘Р РҶР В°РЎвҖ Р С‘Р С‘ Р С—Р В°Р СҳРЎРҸРЎвҖҡР С‘...", "system-message");
    showLoadingScreen('loadingScreen.generatingWorld', 'Р РҺР В¶Р В°РЎвҖҡР С‘Р Вө Р С—Р В°Р СҳРЎРҸРЎвҖҡР С‘...');

    try {
        const promptTemplate = await loadPromptFromFile('assets/promts/summarize_memory_prompt.txt');
        const historyText = conversationHistory.map(m => `${m.role === 'model' ? 'GM' : 'Player'}: ${m.parts[0].text}`).join('\n\n');
        const notesText = JSON.stringify(player.gmNotes, null, 2);

        const finalPrompt = promptTemplate
            .replace('{gmNotes}', notesText)
            .replace('{conversationHistory}', historyText)
            .replace('{userAction}', 'Р СҹРЎРӮР С‘Р Р…РЎС“Р Т‘Р С‘РЎвҖҡР ВөР В»РЎРҠР Р…Р В°РЎРҸ Р В°РЎРӮРЎвҖҰР С‘Р РҶР В°РЎвҖ Р С‘РЎРҸ');

        let modelId = localModelId;
        if (currentApiProvider === 'gemini') modelId = geminiModelId;
        else if (currentApiProvider === 'llmost') modelId = llmostModelId;
        else if (currentApiProvider === 'openrouter') modelId = openrouterModelId;
        else if (currentApiProvider === 'deepseek') modelId = deepseekModelId;
        else if (currentApiProvider === 'omniroute') modelId = omnirouteModelId;
        
        // Р СҹР С’Р СһР В§: Р СҹР ВөРЎРӮР ВөР Т‘Р В°Р ВөР Сҳ Р С•Р ВұРЎРҸР В·Р В°РЎвҖҡР ВөР В»РЎРҠР Р…РЎвҖ№Р в„– currentInput, РЎвҖЎРЎвҖҡР С•Р ВұРЎвҖ№ Gemini Р Р…Р Вө РЎРӮРЎС“Р С–Р В°Р В»РЎРғРЎРҸ Р Р…Р В° Р С—РЎС“РЎРғРЎвҖҡР С•Р в„– Р СҳР В°РЎРғРЎРғР С‘Р РҶ contents
        const rawResponse = await performAiFetch(finalPrompt, [], modelId, "Р СҹРЎРӮР С•Р В°Р Р…Р В°Р В»Р С‘Р В·Р С‘РЎРӮРЎС“Р в„– Р С‘РЎРғРЎвҖҡР С•РЎРӮР С‘РЎРӢ Р С‘ Р С•Р ВұР Р…Р С•Р РҶР С‘ Р С—Р В°Р СҳРЎРҸРЎвҖҡРЎРҠ (JSON).");
        const result = parseAIResponse(rawResponse);

        if (result.actions && result.actions.length > 0) {
            for (const action of result.actions) {
                await executeCommand(action.command, action.args);
            }
            addLogMessage("Р СҹР В°Р СҳРЎРҸРЎвҖҡРЎРҠ РЎС“РЎРғР С—Р ВөРЎвӮ¬Р Р…Р С• РЎРғР В¶Р В°РЎвҖҡР В° Р С‘ Р В·Р В°Р В°РЎРӮРЎвҖҰР С‘Р РҶР С‘РЎРӮР С•Р РҶР В°Р Р…Р В°.", "command-feedback");
        } else {
            addLogMessage("GM Р Р…Р Вө Р Р…Р В°РЎвӮ¬Р ВөР В» Р Т‘Р В°Р Р…Р Р…РЎвҖ№РЎвҖҰ Р Т‘Р В»РЎРҸ Р В°РЎРӮРЎвҖҰР С‘Р РҶР В°РЎвҖ Р С‘Р С‘.", "command-feedback");
        }
    } catch (e) {
        console.error(e);
        addLogMessage("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р В°РЎРӮРЎвҖҰР С‘Р РҶР В°РЎвҖ Р С‘Р С‘: " + e.message, "system-message");
    } finally {
        hideLoadingScreen();
    }
};

