// --- UNIT Р СһР вҖўР РҺР СһР В« (Р вҖҷР РҺР СһР В Р СӣР вҖўР СңР СңР В«Р в„ў Р ВӨР В Р вҖўР в„ўР СҡР вҖҷР СӣР В Р Сҷ) ---
// ==========================================
window.runUnitTests = function () {
    addLogMessage("[DEV] СҖСҹВ§Р„ Р вҖ”Р В°Р С—РЎС“РЎРғР С” Unit-РЎвҖҡР ВөРЎРғРЎвҖҡР С•Р РҶ...", "system-message");
    console.group("СҖСҹВ§Р„ UNIT TESTS RUN");

    let passed = 0;
    let failed = 0;

    function assertEqual(testName, actual, expected) {
        if (actual === expected) {
            console.log(`РІСҡвҖҰ [PASSED] ${testName}`);
            passed++;
        } else {
            console.error(`РІСңРҠ [FAILED] ${testName} | Р СӣР В¶Р С‘Р Т‘Р В°Р В»Р С•РЎРғРЎРҠ: ${expected}, Р СҹР С•Р В»РЎС“РЎвҖЎР ВөР Р…Р С•: ${actual}`);
            failed++;
        }
    }

    // Р СҡР С•Р С”Р В°Р ВөР Сҳ РЎвҖһРЎС“Р Р…Р С”РЎвҖ Р С‘РЎРӢ РЎРғРЎвҖҡР В°Р Р…Р Т‘Р В°РЎРӮРЎвҖҡР С‘Р В·Р В°РЎвҖ Р С‘Р С‘ Р В°РЎРӮР С–РЎС“Р СҳР ВөР Р…РЎвҖҡР С•Р РҶ Р Т‘Р В»РЎРҸ Р С—РЎРӮР С•Р РҶР ВөРЎРӮР С”Р С‘
    function mockMiddleware(command, args) {
        let testArgs;
        try { testArgs = JSON.parse(JSON.stringify(args)); } catch(e) { console.warn('Test args clone failed:', e); return; }
        if (testArgs && typeof testArgs === 'object') {
            if (testArgs.id !== undefined) {
                if (testArgs.aiIdentifier === undefined) testArgs.aiIdentifier = testArgs.id;
                if (testArgs.key === undefined) testArgs.key = testArgs.id;
                if (testArgs.effectId === undefined) testArgs.effectId = testArgs.id;
            }
            if (testArgs.id === undefined) {
                testArgs.id = testArgs.aiIdentifier || testArgs.key || testArgs.effectId;
            }
            if (command.toLowerCase().includes('quest') && testArgs.id === undefined && testArgs.title !== undefined) {
                testArgs.id = testArgs.title;
                testArgs.aiIdentifier = testArgs.title;
            }
        }
        return testArgs;
    }

    try {
        // Р СһР вҖўР РҺР Сһ 1: aiIdentifier Р С”Р С•Р Р…Р РҶР ВөРЎРӮРЎвҖҡР С‘РЎРӮРЎС“Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶ id
        let res1 = mockMiddleware('addItem', { aiIdentifier: 'sword_1' });
        assertEqual('Middleware: aiIdentifier -> id', res1.id, 'sword_1');

        // Р СһР вҖўР РҺР Сһ 2: key Р С”Р С•Р Р…Р РҶР ВөРЎРӮРЎвҖҡР С‘РЎРӮРЎС“Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶ id
        let res2 = mockMiddleware('setMemory', { key: 'plot_1' });
        assertEqual('Middleware: key -> id', res2.id, 'plot_1');

        // Р СһР вҖўР РҺР Сһ 3: effectId Р С”Р С•Р Р…Р РҶР ВөРЎРӮРЎвҖҡР С‘РЎРӮРЎС“Р ВөРЎвҖҡРЎРғРЎРҸ Р РҶ id
        let res3 = mockMiddleware('applyPredefinedEffect', { effectId: 'burn' });
        assertEqual('Middleware: effectId -> id', res3.id, 'burn');

        // Р СһР вҖўР РҺР Сһ 4: id РЎРӮР В°Р В·Р СҳР Р…Р С•Р В¶Р В°Р ВөРЎвҖҡРЎРғРЎРҸ Р Р…Р В° РЎРғРЎвҖҡР В°РЎРӮРЎвҖ№Р Вө Р С”Р В»РЎРӢРЎвҖЎР С‘
        let res4 = mockMiddleware('addQuest', { id: 'quest_1' });
        assertEqual('Middleware: id -> aiIdentifier', res4.aiIdentifier, 'quest_1');
        assertEqual('Middleware: id -> key', res4.key, 'quest_1');

        // Р СһР вҖўР РҺР Сһ 5: Р ВӯР С”РЎРғРЎвҖҡРЎРӮР ВөР Р…Р Р…РЎвҖ№Р в„– РЎвҖһР С‘Р С”РЎРғ Р С”Р РҶР ВөРЎРғРЎвҖҡР С•Р РҶ (title -> id)
        let res5 = mockMiddleware('updateQuest', { title: 'Р РҲР ВұР С‘РЎвҖҡРЎРҠ Р С”РЎРӮРЎвҖ№РЎРғ', status: 'completed' });
        assertEqual('Middleware: Quest title -> id', res5.id, 'Р РҲР ВұР С‘РЎвҖҡРЎРҠ Р С”РЎРӮРЎвҖ№РЎРғ');
        assertEqual('Middleware: Quest title -> aiIdentifier', res5.aiIdentifier, 'Р РҲР ВұР С‘РЎвҖҡРЎРҠ Р С”РЎРӮРЎвҖ№РЎРғ');

    } catch (e) {
        console.error("Р СҷРЎРӮР С‘РЎвҖҡР С‘РЎвҖЎР ВөРЎРғР С”Р В°РЎРҸ Р С•РЎвӮ¬Р С‘Р ВұР С”Р В° Р РҶР С• Р РҶРЎРӮР ВөР СҳРЎРҸ РЎвҖҡР ВөРЎРғРЎвҖҡР С•Р РҶ:", e);
        failed++;
    }

    console.groupEnd();

    const resultMsg = `[DEV] Р СһР ВөРЎРғРЎвҖҡРЎвҖ№ Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р ВөР Р…РЎвҖ№. Р РҲРЎРғР С—Р ВөРЎвӮ¬Р Р…Р С•: ${passed}, Р СҹРЎРӮР С•Р РҶР В°Р В»Р ВөР Р…Р С•: ${failed}. Р СҹР С•Р Т‘РЎРӮР С•Р ВұР Р…Р С•РЎРғРЎвҖҡР С‘ Р РҶ Р С”Р С•Р Р…РЎРғР С•Р В»Р С‘ (F12).`;
    addLogMessage(resultMsg, failed === 0 ? "level-up" : "system-message");
};


