window.toggleAutoTester = function() {
    isAutoTesting = !isAutoTesting;
    aiPlayerCurrentTurns = 0;
    const btn = document.getElementById('admin-autotester-btn');
    if (btn) btn.innerHTML = isAutoTesting ? 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР СҷР вҖә' : 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР В«Р СҷР вҖә';
    
    if (isAutoTesting) {
        addLogMessage(`[DEV] Р С’Р РҶРЎвҖҡР С•-РЎвҖҡР ВөРЎРғРЎвҖҡР ВөРЎРӮ Р В·Р В°Р С—РЎС“РЎвҖ°Р ВөР Р…. Р вҖәР С‘Р СҳР С‘РЎвҖҡ РЎвҖҰР С•Р Т‘Р С•Р РҶ: ${aiPlayerTurnLimit > 0 ? aiPlayerTurnLimit : 'Р вҖҳР ВөР В·Р В»Р С‘Р СҳР С‘РЎвҖҡ'}.`, "system-message");
        if (!isWaitingForAI) runAIPlayerTurn();
    } else {
        addLogMessage("[DEV] Р С’Р РҶРЎвҖҡР С•-РЎвҖҡР ВөРЎРғРЎвҖҡР ВөРЎРӮ Р С•РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р…. Р РҲР С—РЎРӮР В°Р РҶР В»Р ВөР Р…Р С‘Р Вө Р РҶР С•Р В·Р РҶРЎРӮР В°РЎвҖ°Р ВөР Р…Р С• РЎвҖЎР ВөР В»Р С•Р РҶР ВөР С”РЎС“.", "system-message");
    }
};

async function performAiPlayerFetch(systemInstruction, history, providerModel, currentInput) {
    let targetUrl = "";
    let headers = { 'Content-Type': 'application/json' };
    let requestBody = {};
    let isGeminiFormat = false;

    let messages = [{ role: "system", content: systemInstruction }];
    if (history && history.length > 0) {
        history.forEach(item => {
            messages.push({ role: item.role === 'model' ? 'assistant' : 'user', content: item.parts[0].text });
        });
    }
    if (currentInput) messages.push({ role: "user", content: currentInput });

    if (aiPlayerProvider === 'local') {
        targetUrl = aiPlayerLocalUrl || 'http://localhost:1234/v1/chat/completions';
        if (targetUrl.endsWith('/')) targetUrl = targetUrl.slice(0, -1);
        if (targetUrl.match(/:\d+$/)) targetUrl += '/v1/chat/completions';
        else if (targetUrl.endsWith('/v1')) targetUrl += '/chat/completions';
        
        requestBody = { model: providerModel, messages: messages, temperature: 0.7, max_tokens: 2048 };
    } else if (aiPlayerProvider === 'openrouter') {
        targetUrl = "https://openrouter.ai/api/v1/chat/completions";
        headers['Authorization'] = 'Bearer ' + aiPlayerApiKey;
        headers['HTTP-Referer'] = "https://github.com/MrKins/Chronicles-of-Meterea";
        headers['X-Title'] = "Chronicles of Meterea Auto-Tester";
        requestBody = { model: providerModel, messages: messages, temperature: 0.7, max_tokens: 2048 };
    } else if (aiPlayerProvider === 'llmost') {
        targetUrl = "https://llmost.ru/api/v1/chat/completions";
        headers['Authorization'] = 'Bearer ' + aiPlayerApiKey;
        requestBody = { model: providerModel, messages: messages, temperature: 0.7, max_tokens: 2048 };
    } else if (aiPlayerProvider === 'gemini') {
        targetUrl = 'https://generativelanguage.googleapis.com/v1beta/models/' + providerModel + ':generateContent?key=' + aiPlayerApiKey;
        const contents = [];
        if (history && history.length > 0) {
            history.forEach(item => {
                contents.push({ role: item.role === 'model' ? 'model' : 'user', parts: [{ text: item.parts[0].text }] });
            });
        }
        if (currentInput) contents.push({ role: "user", parts: [{ text: currentInput }] });
        requestBody = { systemInstruction: { parts: [{ text: systemInstruction }] }, contents: contents, generationConfig: { maxOutputTokens: 2048, temperature: 0.7 } };
        isGeminiFormat = true;
    }

    const response = await fetch(targetUrl, { method: 'POST', headers: headers, body: JSON.stringify(requestBody) });
    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`AI Player API Error (${response.status}): ${errText}`);
    }

    const data = await response.json();
    let resultText = "";
    if (isGeminiFormat) {
        if (data.candidates && data.candidates[0] && data.candidates[0].content && data.candidates[0].content.parts && data.candidates[0].content.parts[0]) {
            resultText = data.candidates[0].content.parts[0].text;
        } else {
            throw new Error("Р СңР ВөР РҶР ВөРЎРӮР Р…РЎвҖ№Р в„– РЎвҖһР С•РЎРӮР СҳР В°РЎвҖҡ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° Gemini: " + JSON.stringify(data));
        }
    } else {
        if (data.choices && data.choices[0] && data.choices[0].message) {
            resultText = data.choices[0].message.content;
        } else {
            throw new Error("Р СңР ВөР РҶР ВөРЎРӮР Р…РЎвҖ№Р в„– РЎвҖһР С•РЎРӮР СҳР В°РЎвҖҡ Р С•РЎвҖҡР РҶР ВөРЎвҖҡР В° (Р Р…Р ВөРЎвҖҡ choices[0]): " + JSON.stringify(data));
        }
    }

    // Р СӣРЎвҖЎР С‘РЎРғРЎвҖҡР С”Р В° Р С•РЎвҖҡ РЎвҖҡР ВөР С–Р С•Р РҶ РЎРӮР В°Р В·Р СҳРЎвҖ№РЎвӮ¬Р В»Р ВөР Р…Р С‘РЎРҸ (DeepSeek-R1 Р С‘ Р С—Р С•Р Т‘Р С•Р ВұР Р…РЎвҖ№Р Вө)
    resultText = resultText.replace(/<think>[\s\S]*?<\/think>/gi, '');
    if (resultText.includes('<think>')) {
        resultText = resultText.split('<think>')[0];
    }
    return resultText.trim();
}

async function runAIPlayerTurn() {
    if (!isAutoTesting || isWaitingForAI || !player) return;

    if (aiPlayerTurnLimit > 0 && aiPlayerCurrentTurns >= aiPlayerTurnLimit) {
        isAutoTesting = false;
        const btn = document.getElementById('admin-autotester-btn');
        if (btn) btn.innerHTML = 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР В«Р СҷР вҖә';
        addLogMessage(`[DEV] Р С’Р РҶРЎвҖҡР С•-РЎвҖҡР ВөРЎРғРЎвҖҡР ВөРЎРӮ Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р С‘Р В» РЎРӮР В°Р ВұР С•РЎвҖҡРЎС“ (Р Т‘Р С•РЎРғРЎвҖҡР С‘Р С–Р Р…РЎС“РЎвҖҡ Р В»Р С‘Р СҳР С‘РЎвҖҡ Р РҶ ${aiPlayerTurnLimit} РЎвҖҰР С•Р Т‘Р С•Р РҶ).`, "system-message");
        return;
    }

    aiPlayerCurrentTurns++;
    console.log(`[Auto-Tester] Р ВӨР С•РЎРӮР СҳР С‘РЎРӮР С•Р РҶР В°Р Р…Р С‘Р Вө Р В·Р В°Р С—РЎРӮР С•РЎРғР В°... (Р ТҗР С•Р Т‘ ${aiPlayerCurrentTurns}/${aiPlayerTurnLimit > 0 ? aiPlayerTurnLimit : 'РІвӮ¬Сӣ'})`);
    
    const stateSnapshot = buildLitePlayerSnapshot();
    const recentLogs = player.gameLogHistory ? player.gameLogHistory.slice(-5).map(e => `${e.type === 'user-message' ? 'Р РҮ' : 'GM'}: ${e.message}`).join('\n') : "Р СңР ВөРЎвҖҡ Р Р…Р ВөР Т‘Р В°Р РҶР Р…Р С‘РЎвҖҰ РЎРғР С•Р ВұРЎвҖ№РЎвҖҡР С‘Р в„–.";

    let systemPrompt = autoTesterPromptTemplate;
    if (!systemPrompt || systemPrompt.startsWith("Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°:")) {
        systemPrompt = `Р СһРЎвҖ№ Р С‘Р С–РЎРӮР С•Р С” Р РҶ РЎвҖҡР ВөР С”РЎРғРЎвҖҡР С•Р РҶР С•Р в„– RPG. Р РҺР С•РЎРғРЎвҖҡР С•РЎРҸР Р…Р С‘Р Вө: ${stateSnapshot}\nР вҖәР С•Р С–Р С‘: ${recentLogs}\nР СңР В°Р С—Р С‘РЎвӮ¬Р С‘ РЎРғР РҶР С•Р Вө Р Т‘Р ВөР в„–РЎРғРЎвҖҡР РҶР С‘Р Вө Р С•РЎвҖҡ Р С—Р ВөРЎРӮР РҶР С•Р С–Р С• Р В»Р С‘РЎвҖ Р В° (1-2 Р С—РЎРӮР ВөР Т‘Р В»Р С•Р В¶Р ВөР Р…Р С‘РЎРҸ).`;
    } else {
        systemPrompt = systemPrompt
            .replace('{stateSnapshot}', stateSnapshot)
            .replace('{recentLogs}', recentLogs);
    }

    try {
        const aiAction = await performAiPlayerFetch(systemPrompt, [], aiPlayerModelId, "Р В§РЎвҖҡР С• РЎвҖҡРЎвҖ№ РЎРғР Т‘Р ВөР В»Р В°Р ВөРЎвӮ¬РЎРҠ РЎРғР ВөР в„–РЎвҖЎР В°РЎРғ?");
        
        if (!isAutoTesting) return; // Р СҹРЎРӮР С•Р РҶР ВөРЎРӮР С”Р В°, Р Р…Р Вө Р РҶРЎвҖ№Р С”Р В»РЎРӢРЎвҖЎР С‘Р В»Р С‘ Р В»Р С‘ Р С—Р С•Р С”Р В° Р ВҳР Вҳ Р Т‘РЎС“Р СҳР В°Р В»

        if (!aiAction || aiAction.trim() === "") {
            console.warn("[Auto-Tester] Р СҹР С•Р В»РЎС“РЎвҖЎР ВөР Р… Р С—РЎС“РЎРғРЎвҖҡР С•Р в„– Р С•РЎвҖҡР РҶР ВөРЎвҖҡ. Р вҖҷР С•Р В·Р СҳР С•Р В¶Р Р…Р С•, Р СҳР С•Р Т‘Р ВөР В»РЎРҠ Р Р…Р Вө РЎС“РЎРғР С—Р ВөР В»Р В° Р В·Р В°Р РҶР ВөРЎРӮРЎвӮ¬Р С‘РЎвҖҡРЎРҠ Р СҳРЎвҖ№РЎРғР В»РЎРҠ (hit token limit).");
            addLogMessage(`[DEV] Р С’Р РҶРЎвҖҡР С•-РЎвҖҡР ВөРЎРғРЎвҖҡР ВөРЎРӮ Р РҶР ВөРЎРӮР Р…РЎС“Р В» Р С—РЎС“РЎРғРЎвҖҡР С•Р в„– Р С•РЎвҖҡР РҶР ВөРЎвҖҡ. Р СҹРЎРӮР С•Р С—РЎС“РЎРғР С” РЎвҖҰР С•Р Т‘Р В°.`, "system-message");
            return;
        }

        // Р вҖҷРЎРғРЎвҖҡР В°Р РҶР В»РЎРҸР ВөР Сҳ РЎвҖҡР ВөР С”РЎРғРЎвҖҡ Р РҶ Р С‘Р Р…Р С—РЎС“РЎвҖҡ Р С‘ Р С‘Р СҳР С‘РЎвҖҡР С‘РЎРӮРЎС“Р ВөР Сҳ Р С•РЎвҖҡР С—РЎРӮР В°Р РҶР С”РЎС“
        if (userInput) {
            userInput.value = aiAction.trim();
            console.log("[Auto-Tester] Р вҖқР ВөР в„–РЎРғРЎвҖҡР РҶР С‘Р Вө:", userInput.value);
            handleUserInput();
        }
    } catch (e) {
        console.error("[Auto-Tester] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В°:", e);
        addLogMessage(`[DEV] Р СӣРЎвӮ¬Р С‘Р ВұР С”Р В° Р С’Р РҶРЎвҖҡР С•-РЎвҖҡР ВөРЎРғРЎвҖҡР ВөРЎРӮР В°: ${e.message}. Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ Р С•РЎРғРЎвҖҡР В°Р Р…Р С•Р РҶР В»Р ВөР Р….`, "system-message");
        isAutoTesting = false;
        const btn = document.getElementById('admin-autotester-btn');
        if (btn) btn.innerHTML = 'СҖСҹВӨвҖ“ Р С’Р РҶРЎвҖҡР С•-Р СһР ВөРЎРғРЎвҖҡР ВөРЎРӮ: Р вҖҷР В«Р СҷР вҖә';
    }
}


